INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b57e3c98b0941765961', '不愧是老牌五星，随时随地感受到专业的服务，门口就地铁，出门好吃的太多了，游泳还有饮料送！以后来广州就认花园酒店', '["https://dimg04.c-ctrip.com/images/0233j12000f010s5vE4F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000f010zgm4FA6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000f010ln4675A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-04', '花园双床房', '双床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 10, 2.3978952727983707, 7, '["前台服务", "交通便利性", "公共设施"]'::jsonb, '前台服务', '交通便利性', '公共设施', '未知酒店', '未知地点', '匿名', '不愧是老牌五星，随时随地感受到专业的服务，门口就地铁，出门好吃的太多了，游泳还有', '不愧是老牌五星，随时随地感受到专业的服务，门口就地铁，出门好吃的太多了，游泳还有饮料送！以后来广州就认花园酒店', '2024-08-04', 5, '前台服务');
