INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b62e3c98b094176596a', '酒店大堂很气派，不论是办理入住还是退房都有引导，效率挺高，房间不大，是老酒店了，胜在洗澡水很冲洗的舒服，客服小李还亲自送来小甜品。出行地铁方便吃饭可选择余地比较多，就是周边那几家很红的餐厅都需要等位好久。', '["https://dimg04.c-ctrip.com/images/02302224x8z2z4ytt6503_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g224x8z303wfzF469_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q224x8z2yj3a76E66_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d224x8z2zap72D88B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z224x8z31aplv9284_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-02-02', '花园双床房', '双床房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 12, 2.5649493574615367, 8, '["前台服务", "退房/入住效率", "交通便利性"]'::jsonb, '前台服务', '退房/入住效率', '交通便利性', '未知酒店', '未知地点', '匿名', '酒店大堂很气派，不论是办理入住还是退房都有引导，效率挺高，房间不大，是老酒店了，', '酒店大堂很气派，不论是办理入住还是退房都有引导，效率挺高，房间不大，是老酒店了，胜在洗澡水很冲洗的舒服，客服小李还亲自送来小甜品。出行地铁方便吃饭可选择余地比较多，就是周边那几家很红的餐厅都需要等位好久。', '2025-02-02', 4, '前台服务');
