INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b6de3c98b0941765974', '老牌5星级饭店，房间有点年代感，但还是很干净，服务是真的好，从前厅到客房和餐厅，遇到的每一个服务生都很亲切，很有礼貌，4楼的博物馆记录了广州酒店的发展历程，值得一看', '["https://dimg04.c-ctrip.com/images/0235112000eexnpdrE6B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000eexdy0eCCEF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000eexdwl7FEDA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-10', '花园双床房', '双床房', '家庭亲子', 82, 4.418840607796598, 0, 0.0, 7, 2.079441541679836, 8, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '老牌5星级饭店，房间有点年代感，但还是很干净，服务是真的好，从前厅到客房和餐厅，', '老牌5星级饭店，房间有点年代感，但还是很干净，服务是真的好，从前厅到客房和餐厅，遇到的每一个服务生都很亲切，很有礼貌，4楼的博物馆记录了广州酒店的发展历程，值得一看', '2024-06-10', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b6de3c98b0941765975', '暑假带孩子去长隆，长隆附近的酒店都涨到住不起了，所以选择了住花园酒店，老牌五星级酒店，服务一流，必须五星好评。', '["https://dimg04.c-ctrip.com/images/0232w12000evyma7p3A3B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000evym581B6C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000evynw0z946D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-24', '花园双床房', '双床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 4, 1.6094379124341005, 6, '["整体满意度", "前台服务", "性价比"]'::jsonb, '整体满意度', '前台服务', '性价比', '未知酒店', '未知地点', '匿名', '暑假带孩子去长隆，长隆附近的酒店都涨到住不起了，所以选择了住花园酒店，老牌五星级', '暑假带孩子去长隆，长隆附近的酒店都涨到住不起了，所以选择了住花园酒店，老牌五星级酒店，服务一流，必须五星好评。', '2024-07-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b6de3c98b0941765976', '美丽的花园酒店，广州的国际化大酒店，很美，服务也很好，特意表扬一下酒店的康乐部，游泳池的服务，救生员都有三个，还有酒水部，迎宾，送水送毛巾，救生员小周热情服务，讲解，让客人游泳的很安心，餐饮服务都很好，特别行政酒廊30楼的金牌导游CARRIE，没在服务时间帮我女儿做了咖啡，端午节早餐人有点多，也只等了10分钟，吃完后还有经理来道歉，服务不周，很是感慨酒店服务人员的素质，
但我这里重点说一下前台服务，希望管理层能看到，前台是我这次住店体验不好的，工作人员没有认真看订单，先分配我去9楼房间，我的订单是18楼以上的，吃完饭一看不仅楼层低，还是尾房，后来交涉后给升级了，过程就不说了，其实最终还是住的升级房型，你一早给我不是不用这么麻烦，因为我也是你们金卡会员，在办理入住的时候看到柜台堆满了一支一支的康乃馨，是送给客人的，给我办理的工作人员没有任何触动，就在她手边。
大堂的迎宾小姐姐还会主动帮客人拍照，很美的酒店，希望前台能看到，不要给酒店拖后腿。', '["https://dimg04.c-ctrip.com/images/0233q12000ehd9s634411_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000ehdbnpq07B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000ehd8uj4D165_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-15', '花园双床房', '双床房', '家庭亲子', 425, 6.054439346269371, 0, 0.0, 26, 3.295836866004329, 9, '["前台服务", "公共设施", "整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '美丽的花园酒店，广州的国际化大酒店，很美，服务也很好，特意表扬一下酒店的康乐部，', '美丽的花园酒店，广州的国际化大酒店，很美，服务也很好，特意表扬一下酒店的康乐部，游泳池的服务，救生员都有三个，还有酒水部，迎宾，送水送毛巾，救生员小周热情服务，讲解，让客人游泳的很安心，餐饮服务都很好，特别行政酒廊30楼的金牌导游CARRIE，没在服务时间帮我女儿做了咖啡，端午节早餐人有点多，也只等了10分钟，吃完后还有经理来道歉，服务不周，很是感慨酒店服务人员的素质，
但我这里重点说一下前台服务，希望管理层能看到，前台是我这次住店体验不好的，工作人员没有认真看订单，先分配我去9楼房间，我的订单是18楼以上的，吃完饭一看不仅楼层低，还是尾房，后来交涉后给升级了，过程就不说了，其实最终还是住的升级房型，你一早给我不是不用这么麻烦，因为我也是你们金卡会员，在办理入住的时候看到柜台堆满了一支一支的康乃馨，是送给客人的，给我办理的工作人员没有任何触动，就在她手边。
大堂的迎宾小姐姐还会主动帮客人拍照，很美的酒店，希望前台能看到，不要给酒店拖后腿。', '2024-06-15', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b6de3c98b0941765977', '房间干净卫生，超喜欢后花园，忘了拍照，还参观了4楼的博物馆，服务态度不是一般的好，在酒店吃了早餐和晚餐，菜式丰富，根本没办法一一品尝，非常满意，下次过来还会选择花园酒店', '["https://dimg04.c-ctrip.com/images/0200v12000ecnhcj491A5_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0236q12000ecndo8v7249_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000ecmodmw7803_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234x12000ecn0sciF7A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-06', '花园大床房', '大床房', '家庭亲子', 84, 4.442651256490317, 0, 0.0, 4, 1.6094379124341005, 8, '["整体满意度", "餐饮设施", "卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况', '未知酒店', '未知地点', '匿名', '房间干净卫生，超喜欢后花园，忘了拍照，还参观了4楼的博物馆，服务态度不是一般的好', '房间干净卫生，超喜欢后花园，忘了拍照，还参观了4楼的博物馆，服务态度不是一般的好，在酒店吃了早餐和晚餐，菜式丰富，根本没办法一一品尝，非常满意，下次过来还会选择花园酒店', '2024-06-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b6de3c98b0941765978', '广州的老牌酒店！各方面都还是不错！房间不算大，但布局还算合理。后花园是酒店的亮点，荔湾亭点心出品也是不错的！', '["https://dimg04.c-ctrip.com/images/0230312000ft5qzct8B64_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000ft5pgz0B6DA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000ft5db3lA7C6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-09-28', '花园双床房', '双床房', '家庭亲子', 54, 4.007333185232471, 0, 0.0, 19, 2.995732273553991, 7, '["整体满意度", "周边配套", "餐饮设施"]'::jsonb, '整体满意度', '周边配套', '餐饮设施', '未知酒店', '未知地点', '匿名', '广州的老牌酒店！各方面都还是不错！房间不算大，但布局还算合理。后花园是酒店的亮点', '广州的老牌酒店！各方面都还是不错！房间不算大，但布局还算合理。后花园是酒店的亮点，荔湾亭点心出品也是不错的！', '2024-09-28', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b6de3c98b0941765979', '老牌五星级酒店，还是很能打的，性价比高！离地铁非常近，离利苑近！酒店金碧辉煌的，很多老外，周边很多印度餐厅??', '["https://dimg04.c-ctrip.com/images/0235z12000f3q5d3w490C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000f3q0gksA33C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000f3q63f7228E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000f3py6ozCBD0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-13', '花园大床房', '大床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 12, 2.5649493574615367, 5, '["性价比", "交通便利性", "周边配套"]'::jsonb, '性价比', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '老牌五星级酒店，还是很能打的，性价比高！离地铁非常近，离利苑近！酒店金碧辉煌的，', '老牌五星级酒店，还是很能打的，性价比高！离地铁非常近，离利苑近！酒店金碧辉煌的，很多老外，周边很多印度餐厅??', '2024-08-13', 5, '性价比');
