INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b78e3c98b094176597f', '是什么好运让我在广州暴雨天气入住了花园酒店～
没有亲眼目睹花园酒店的瀑布后花园有点遗憾，
但其他都是很棒的体验～
所选的区域位置比较市中心，
无论去广州塔还是去沙面岛玩耍
居中的位置出行都比较方便。
大堂看着有点奢华，
一楼有瀑布餐厅以及下午茶??
定了两间双床和大床，
虽然是一样的价格，但大床房带浴缸
备好泡泡浴球可以带娃洗个泡泡浴??
早餐就是比较中规中矩的自助餐，
但点心这块很是吸引甜品爱好者～
