INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b83e3c98b0941765986', '定的大床房，给升级了套房，套房的面积比大床房大一倍，没有到酒店之前很忐忑，因为看到评论说因为酒店旧所以有霉味，到了房间之后发现完全是多虑了，房间一点味道也没有，地理位置也很棒，打车去各景点大概都在30元以内，出酒店门就是地铁，周边吃的也很多，很多热门的店周边都有分店。这次住的很满意。', '["https://dimg04.c-ctrip.com/images/0233m12000dxetxw3824B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000dxetq2t63C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-09', '花园大床房', '大床房', '家庭亲子', 142, 4.962844630259907, 2, 1.0986122886681098, 11, 2.4849066497880004, 9, '["整体满意度", "交通便利性", "周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '定的大床房，给升级了套房，套房的面积比大床房大一倍，没有到酒店之前很忐忑，因为看', '定的大床房，给升级了套房，套房的面积比大床房大一倍，没有到酒店之前很忐忑，因为看到评论说因为酒店旧所以有霉味，到了房间之后发现完全是多虑了，房间一点味道也没有，地理位置也很棒，打车去各景点大概都在30元以内，出酒店门就是地铁，周边吃的也很多，很多热门的店周边都有分店。这次住的很满意。', '2024-05-09', 5, '整体满意度');
