INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b83e3c98b094176598b', '跟我前一天的天差地别，前台帮我办理入住的礼宾也非常富有笑容和专业，全程微笑。价位适中，值得再次入住', '["https://dimg04.c-ctrip.com/images/0234712000euodzsiDC77_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000euoeeu1CAC6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000euodu0k0685_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-21', '红棉双床套房', '套房', '家庭亲子', 49, 3.912023005428146, 0, 0.0, 8, 2.19722457733622, 6, '["前台服务", "性价比", "整体满意度"]'::jsonb, '前台服务', '性价比', '整体满意度', '未知酒店', '未知地点', '匿名', '跟我前一天的天差地别，前台帮我办理入住的礼宾也非常富有笑容和专业，全程微笑。价位', '跟我前一天的天差地别，前台帮我办理入住的礼宾也非常富有笑容和专业，全程微笑。价位适中，值得再次入住', '2024-07-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b83e3c98b094176598c', '一路风雨来到广州，毕竟有悠久的历史，从城到人到酒店从美景到美食都丰富而厚重。
房间免费升级行政套房，17岁的少年免费加床，花园饭店真的有温暖到我，房间的细节让，辉煌的大堂，让多年来游历29国的我第一次感觉到宾至如归，结合国外很多博物馆的展品，终于明白了，他们当年为何那样推崇中国元素的装修。
床很舒服，布局合理，枕头可选择，香皂很香，拖鞋很软，自动窗帘方便又遮光，灯光很舒适，忘带房卡也不怕去，电梯口总有热情美丽的服务员。
地铁淘金站的旁边，地处越秀老城区，繁华方便，到各个景点都很方便，外国门童帮忙开门时，心中很骄傲，民族自豪感。
