INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765990', '到酒店时间晚，感谢前台小姐姐安排了满意的房间和延迟退房。每次到广州都住花园酒店，漂亮，卫生、服务好、出行方便。5??赞赞赞', '["https://dimg04.c-ctrip.com/images/0233z12000h9l85leD65B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000h9lcxopD6F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-18', '花园大床房', '大床房', '商务出差', 61, 4.127134385045092, 0, 0.0, 2, 1.0986122886681098, 7, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '到酒店时间晚，感谢前台小姐姐安排了满意的房间和延迟退房。每次到广州都住花园酒店，', '到酒店时间晚，感谢前台小姐姐安排了满意的房间和延迟退房。每次到广州都住花园酒店，漂亮，卫生、服务好、出行方便。5??赞赞赞', '2024-12-18', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765991', '酒店服务太差了，整个过程是，在酒店打印资料费20元，我提出放房费一起结算，工作人员说只能现场支付。现场支付了20，最后结帐酒店又从押金中扣，两次投诉才拿回20元，整个过程匪夷所思，难道只有二次付款才能从押金里扣吗？！现场支付后工作人员不进行标注的吗？！区区20元，费的心力远不及此。更气的是住3天花将近5千，发票只开了1128元，莫名其妙的各种错！作为五星酒店的基本服务能力在哪里？！', '["https://dimg04.c-ctrip.com/images/0232a12000dwiyz6v6EF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-05-07', '花园双床房', '双床房', '朋友出游', 192, 5.262690188904886, 2, 1.0986122886681098, 1, 0.6931471805599453, 9, '["前台服务", "退房/入住效率", "价格合理性"]'::jsonb, '前台服务', '退房/入住效率', '价格合理性', '未知酒店', '未知地点', '匿名', '酒店服务太差了，整个过程是，在酒店打印资料费20元，我提出放房费一起结算，工作人', '酒店服务太差了，整个过程是，在酒店打印资料费20元，我提出放房费一起结算，工作人员说只能现场支付。现场支付了20，最后结帐酒店又从押金中扣，两次投诉才拿回20元，整个过程匪夷所思，难道只有二次付款才能从押金里扣吗？！现场支付后工作人员不进行标注的吗？！区区20元，费的心力远不及此。更气的是住3天花将近5千，发票只开了1128元，莫名其妙的各种错！作为五星酒店的基本服务能力在哪里？！', '2024-05-07', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765992', '广州花园酒店服务体验非常好，可以说是感动式服务，酒店注重服务细节和用户体验，主动为客户提供超值的升级服务，从迎宾、接待、客房到环境和配套都名副其实，再次到广东还想入住花园酒店，感谢酒店管理者和服务人员的辛苦付出和优质服务，你们完全能代表中国五星级酒店品牌和形象！', '["https://dimg04.c-ctrip.com/images/0232q12000dwz2wpd7912_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231x12000dwz4561E5DA_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231312000dwz3m5tD903_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-05-08', '花园双床房', '双床房', '商务出差', 131, 4.882801922586371, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "整体满意度", "客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '广州花园酒店服务体验非常好，可以说是感动式服务，酒店注重服务细节和用户体验，主动', '广州花园酒店服务体验非常好，可以说是感动式服务，酒店注重服务细节和用户体验，主动为客户提供超值的升级服务，从迎宾、接待、客房到环境和配套都名副其实，再次到广东还想入住花园酒店，感谢酒店管理者和服务人员的辛苦付出和优质服务，你们完全能代表中国五星级酒店品牌和形象！', '2024-05-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765993', '老牌酒店的品质保证，第一次入住花园酒店，感觉很贴心，免费升级了套房，送了入住果盘、小孩洗漱套装、冰箱贴、手绘地图，还给小朋友送了一只小羊玩偶，特别可爱。酒店虽然有点年份，但整体还是干净整洁，大堂很华丽，很多广州的装饰，还有一个博物馆可以了解酒店的背景和文化。瀑布餐厅氛围感很好，可以看到花草繁茂的后花园和流水瀑布。整体服务很到位，客房、餐厅都有充足的服务人员，前台的Mancy和James特别nice，有种宾至如归的感觉。', '["https://dimg04.c-ctrip.com/images/0232q12000exblzpj3E7F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000exbmjue74CE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232m12000exblcb42750_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000exblj30B4F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000exbjrjy83AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000exbkgcd61DA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000exblpv9FD21_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-28', '花园双床房', '双床房', '家庭亲子', 211, 5.356586274672012, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '老牌酒店的品质保证，第一次入住花园酒店，感觉很贴心，免费升级了套房，送了入住果盘', '老牌酒店的品质保证，第一次入住花园酒店，感觉很贴心，免费升级了套房，送了入住果盘、小孩洗漱套装、冰箱贴、手绘地图，还给小朋友送了一只小羊玩偶，特别可爱。酒店虽然有点年份，但整体还是干净整洁，大堂很华丽，很多广州的装饰，还有一个博物馆可以了解酒店的背景和文化。瀑布餐厅氛围感很好，可以看到花草繁茂的后花园和流水瀑布。整体服务很到位，客房、餐厅都有充足的服务人员，前台的Mancy和James特别nice，有种宾至如归的感觉。', '2024-07-28', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765994', '酒店环境优美，瀑布餐厅和后院的小花园都很有特色，工作人员服务热情，房间干净卫生，稍小设施也有点老旧。早餐非常丰富，还有很多外国人，总体还是非常不错的。', '["https://dimg04.c-ctrip.com/images/0237012000f56syto175E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000f56wmryD338_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000f56w3ej4F59_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-16', '花园双床房', '双床房', '家庭亲子', 75, 4.330733340286331, 0, 0.0, 14, 2.70805020110221, 7, '["餐饮设施", "整体满意度", "卫生状况"]'::jsonb, '餐饮设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店环境优美，瀑布餐厅和后院的小花园都很有特色，工作人员服务热情，房间干净卫生，', '酒店环境优美，瀑布餐厅和后院的小花园都很有特色，工作人员服务热情，房间干净卫生，稍小设施也有点老旧。早餐非常丰富，还有很多外国人，总体还是非常不错的。', '2024-08-16', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765995', '服务非常好！里面的餐也很正宗，地理位置很好，地铁站出口就是，很方便！适合带孩子！', '["https://dimg04.c-ctrip.com/images/0234l12000f02o4etAB56_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000f02rruzD406_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000f02nhwyBD2E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000f02jv4l391E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000f02iecu70EC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000f02mqu50168_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000f02j4y3D7CE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000f02idxgDA33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-04', '花园大床房', '大床房', '朋友出游', 40, 3.713572066704308, 0, 0.0, 9, 2.302585092994046, 7, '["交通便利性", "餐饮设施", "前台服务"]'::jsonb, '交通便利性', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '服务非常好！里面的餐也很正宗，地理位置很好，地铁站出口就是，很方便！适合带孩子！', '服务非常好！里面的餐也很正宗，地理位置很好，地铁站出口就是，很方便！适合带孩子！', '2024-08-04', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765996', '来过很多次了，这边的人气跟地理位置都让我很喜欢，也是一个非常有老广气息的酒店，这边也有挺出名的餐厅，还有一进门就能见到身穿金色衣服的小姐姐，交谈过后发现他们原来是花园白金大使，让我印象深刻的是一个叫小何的大使，服务真的很不错??', '["https://dimg04.c-ctrip.com/images/0234l12000jf4g5en1CC8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000jf4k8gw8A04_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-03-30', '花园大床房', '大床房', '家庭亲子', 114, 4.74493212836325, 0, 0.0, 5, 1.791759469228055, 7, '["前台服务", "周边配套", "餐饮设施"]'::jsonb, '前台服务', '周边配套', '餐饮设施', '未知酒店', '未知地点', '匿名', '来过很多次了，这边的人气跟地理位置都让我很喜欢，也是一个非常有老广气息的酒店，这', '来过很多次了，这边的人气跟地理位置都让我很喜欢，也是一个非常有老广气息的酒店，这边也有挺出名的餐厅，还有一进门就能见到身穿金色衣服的小姐姐，交谈过后发现他们原来是花园白金大使，让我印象深刻的是一个叫小何的大使，服务真的很不错??', '2025-03-30', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765997', '房间很好，适合小朋友，还有小朋友拖鞋牙刷，打电话给前台，送来的非常快。还有铅笔橡皮尺子卷笔刀。小胶棒，小羊商铺ADA LINA 迎宾LIVEN 都很好。来之前看到很多差评，有点忐忑，但是来了之后，很好。小朋友说非常好，酒店特别大', '["https://dimg04.c-ctrip.com/images/0235i12000duj0gdc88B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000duiom9v04B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000duirimu909A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000duj0qyh83F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000duirea34067_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-01', '花园双床房', '双床房', '家庭亲子', 114, 4.74493212836325, 0, 0.0, 6, 1.9459101490553128, 7, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '房间很好，适合小朋友，还有小朋友拖鞋牙刷，打电话给前台，送来的非常快。还有铅笔橡', '房间很好，适合小朋友，还有小朋友拖鞋牙刷，打电话给前台，送来的非常快。还有铅笔橡皮尺子卷笔刀。小胶棒，小羊商铺ADA LINA 迎宾LIVEN 都很好。来之前看到很多差评，有点忐忑，但是来了之后，很好。小朋友说非常好，酒店特别大', '2024-05-01', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b8fe3c98b0941765998', '91年的时候路过花园酒店，觉得好高端好大气，就非常想去，各种阴差阳错，一拖就拖到了30年后。后花园，锦鲤酒吧感觉都非常好，早餐是在旋转餐厅吃的，风景不错，还非常丰盛，牛腩也很好吃。前台服务很好，很热情，回访的小晴态度也很好，值得表扬，有机会一定再来。', '["https://dimg04.c-ctrip.com/images/0235e12000fil8dnd93CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000fikq31e7D2B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000fil2y3309E9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-12', '红棉大床套房', '套房', '家庭亲子', 125, 4.836281906951478, 1, 0.6931471805599453, 18, 2.9444389791664403, 7, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '91年的时候路过花园酒店，觉得好高端好大气，就非常想去，各种阴差阳错，一拖就拖到', '91年的时候路过花园酒店，觉得好高端好大气，就非常想去，各种阴差阳错，一拖就拖到了30年后。后花园，锦鲤酒吧感觉都非常好，早餐是在旋转餐厅吃的，风景不错，还非常丰盛，牛腩也很好吃。前台服务很好，很热情，回访的小晴态度也很好，值得表扬，有机会一定再来。', '2024-09-12', 5, '餐饮设施');
