INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b99e3c98b094176599b', '房间干净整齐，服务很棒。环境配得上五星级，后花园飞瀑流泉，游鱼欢悦，绿树蓬蓬。酒店建筑设计更是独到有文化韵味。', '["https://dimg04.c-ctrip.com/images/0232r12000ekih86o2849_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000ekigx8e6009_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000ekif2lzCBD3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000ekih2gr3342_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000ekiah8mC0D4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000ekif4z4DFE5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000ekier2g1946_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000ekijjneFDFB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000eki3z02BF81_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-25', '红棉大床套房', '套房', '朋友出游', 55, 4.02535169073515, 1, 0.6931471805599453, 2, 1.0986122886681098, 8, '["整体满意度", "卫生状况", "公共设施"]'::jsonb, '整体满意度', '卫生状况', '公共设施', '未知酒店', '未知地点', '匿名', '房间干净整齐，服务很棒。环境配得上五星级，后花园飞瀑流泉，游鱼欢悦，绿树蓬蓬。酒', '房间干净整齐，服务很棒。环境配得上五星级，后花园飞瀑流泉，游鱼欢悦，绿树蓬蓬。酒店建筑设计更是独到有文化韵味。', '2024-06-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b99e3c98b094176599c', '老牌五星级酒店，虽然有将近四十年了，但内部装修风格和质感比大部分现在新的酒店都好多了，环境不用说，对得起花园酒店的名字，服务不知道是不是广交会的缘故，住的几天都特别好，早餐分别吃了30楼旋转餐厅和一楼瀑布餐厅的，东西差不多，都很丰富，总体对这几天的入住很满意', '["https://dimg04.c-ctrip.com/images/0236w12000dumf8rxCDCF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000dulxq14CC90_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000dumpl127C28_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-02', '花园大床房', '大床房', '家庭亲子', 129, 4.867534450455582, 0, 0.0, 24, 3.218875824868201, 9, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '老牌五星级酒店，虽然有将近四十年了，但内部装修风格和质感比大部分现在新的酒店都好', '老牌五星级酒店，虽然有将近四十年了，但内部装修风格和质感比大部分现在新的酒店都好多了，环境不用说，对得起花园酒店的名字，服务不知道是不是广交会的缘故，住的几天都特别好，早餐分别吃了30楼旋转餐厅和一楼瀑布餐厅的，东西差不多，都很丰富，总体对这几天的入住很满意', '2024-05-02', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b99e3c98b094176599d', '酒店的环境真的没话说，不愧是老牌酒店，大厅富丽堂皇；
