唯一的缺点就是房间有点点小，但整体房间设施都不错，干净、舒服。', '2024-09-22', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b99e3c98b094176599e', '代客户预订，还给升级了房间！客户感觉很满意！今天又续了一天！
作为广州的老五星，服务非常好！连每个楼层都配有服务员指引！厉害厉害！', '["https://dimg04.c-ctrip.com/images/0233212000eicoit5786E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000eicvjwjCE1F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000eicylwf62A4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-18', '花园大床房', '大床房', '代人预订', 65, 4.189654742026425, 1, 0.6931471805599453, 124, 4.8283137373023015, 7, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '代客户预订，还给升级了房间！客户感觉很满意！今天又续了一天！', '代客户预订，还给升级了房间！客户感觉很满意！今天又续了一天！
作为广州的老五星，服务非常好！连每个楼层都配有服务员指引！厉害厉害！', '2024-06-18', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b99e3c98b094176599f', '对海外华人港澳台人来说最知名的内地酒店就是广州花园酒店，非常多外国客入住。位于市中心老城区位置得天独厚，服务也很好，check in等待 会送上可乐饮料。员工积极主动，广交会房间紧张时期酒店还免费给我升级了套房，可能我是携程高级会员的缘故吧，总之非常感谢酒店。', '["https://dimg04.c-ctrip.com/images/0230i12000dtqyyd10B04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000dtqhh9o4954_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000dtrc8lo1E5C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000dtqvg987D7C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000dtqfm2r7FE4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000dtql49eDA5A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000dtqxxgt4D18_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-30', '花园大床房', '大床房', '情侣出游', 130, 4.875197323201151, 1, 0.6931471805599453, 93, 4.543294782270004, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '对海外华人港澳台人来说最知名的内地酒店就是广州花园酒店，非常多外国客入住。位于市', '对海外华人港澳台人来说最知名的内地酒店就是广州花园酒店，非常多外国客入住。位于市中心老城区位置得天独厚，服务也很好，check in等待 会送上可乐饮料。员工积极主动，广交会房间紧张时期酒店还免费给我升级了套房，可能我是携程高级会员的缘故吧，总之非常感谢酒店。', '2024-04-30', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b99e3c98b09417659a0', '第一次入住白金五星级酒店，全国只有三家，这家服务真的好，服务员是很有包容心的那种，知道不说破给客人尊荣！那瀑布是绝绝子，让人很迷恋，前厅经理给我们房间升级了套房双床，送了一份早餐，第二天去用早餐，因为一份早餐的原因在30楼旋转餐厅打包两个人享用了，服务员热情的帮我打了包！后来我又去了30楼和1楼另外两个早餐厅，畅通无阻！管理员知道却默许了，让我们很舒服！去了花园博物馆，真的学到了，那份底蕴无需多言处处渗透！在楼层上电梯打开就有服务员热情的送上红茶指引，第二次上去就记得我住的房间，细节到位，下次有机会还会去花园酒店，尝尝米其林餐厅美食，在早餐厅听瀑布声，去花园酒店博物馆里记记酒店发展史！', '["https://dimg04.c-ctrip.com/images/0235q12000dwpekw00370_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000dwp95l07F67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000dwpe03jEE43_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000dwpdm3i777E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000dwpaut9E75F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000dwp9yng0A46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000dwpda3m7E98_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000dwpas680E38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000dwpd3zl83B7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-07', '花园双床房', '双床房', '商务出差', 296, 5.6937321388027, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '第一次入住白金五星级酒店，全国只有三家，这家服务真的好，服务员是很有包容心的那种', '第一次入住白金五星级酒店，全国只有三家，这家服务真的好，服务员是很有包容心的那种，知道不说破给客人尊荣！那瀑布是绝绝子，让人很迷恋，前厅经理给我们房间升级了套房双床，送了一份早餐，第二天去用早餐，因为一份早餐的原因在30楼旋转餐厅打包两个人享用了，服务员热情的帮我打了包！后来我又去了30楼和1楼另外两个早餐厅，畅通无阻！管理员知道却默许了，让我们很舒服！去了花园博物馆，真的学到了，那份底蕴无需多言处处渗透！在楼层上电梯打开就有服务员热情的送上红茶指引，第二次上去就记得我住的房间，细节到位，下次有机会还会去花园酒店，尝尝米其林餐厅美食，在早餐厅听瀑布声，去花园酒店博物馆里记记酒店发展史！', '2024-05-07', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b99e3c98b09417659a2', '在花园酒店吃住都非常的舒服，花园酒店不愧是花园酒店，酒店的花都非常的漂亮。最让人印象深刻的就是30楼的行政酒廊，这里的风景非常优美，音乐听着也很让人动听。行政酒廊的mignon的笑容很甜美，服务很贴心，ken得服务也非常的周到。让我有一个非常不错的用餐体验，下次旅游还会选择这家酒店。', '["https://dimg04.c-ctrip.com/images/0235112000dtkzjm5DA94_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000dtkkaye8F09_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000dtl2t61AF00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-29', '花园双床房', '双床房', '家庭亲子', 142, 4.962844630259907, 0, 0.0, 4, 1.6094379124341005, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '在花园酒店吃住都非常的舒服，花园酒店不愧是花园酒店，酒店的花都非常的漂亮。最让人', '在花园酒店吃住都非常的舒服，花园酒店不愧是花园酒店，酒店的花都非常的漂亮。最让人印象深刻的就是30楼的行政酒廊，这里的风景非常优美，音乐听着也很让人动听。行政酒廊的mignon的笑容很甜美，服务很贴心，ken得服务也非常的周到。让我有一个非常不错的用餐体验，下次旅游还会选择这家酒店。', '2024-04-29', 5, '餐饮设施');
