INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ba4e3c98b09417659a6', '非常非常满意的一次入住，酒店就在市中心，离地铁站也近，去哪里都特别方便。特别感谢Rebecca小钟，看我们又老又小，拖家带口的，主动提供了很多帮助，真心特别满意。行政酒廊的下午茶和欢乐时光我们也特别喜欢。整个酒店有好多外国人进出，非常国际化，还可以喂锦鲤，孩子喜欢的不得了！', '["https://dimg04.c-ctrip.com/images/0236812000hwsat2s65B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000hwtdgac2A7D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000hwtgdfaCE40_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-19', '红棉双床套房', '套房', '家庭亲子', 137, 4.927253685157205, 0, 0.0, 4, 1.6094379124341005, 9, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '非常非常满意的一次入住，酒店就在市中心，离地铁站也近，去哪里都特别方便。特别感谢', '非常非常满意的一次入住，酒店就在市中心，离地铁站也近，去哪里都特别方便。特别感谢Rebecca小钟，看我们又老又小，拖家带口的，主动提供了很多帮助，真心特别满意。行政酒廊的下午茶和欢乐时光我们也特别喜欢。整个酒店有好多外国人进出，非常国际化，还可以喂锦鲤，孩子喜欢的不得了！', '2025-01-19', 5, '整体满意度');
