INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bc1e3c98b09417659bb', '上午十点半的飞机从上海飞广州一点落地，到酒
店差不多两点，就不想再去景点人挤人了，所以
特意选了这家自己就可以当作景点的花园酒店好适合带小朋友的家庭言因为过年期间客人太多，所以一直晚等到四点半多才打扫完房间，但是呢一点也没有影响旅行的心情。寄存完行李以后，拿着酒店地图去把酒店的景点都打一遍卡再去酒店四楼的博物馆听了三点的讲解，了解中西方酒店发展史，逛完博物馆正好去二楼荔湾亭吃个下午茶，一系列操作完毕以后刚刚好回房间休息，完美。不得不说广州真的太有过年和搞钱的氛围感了，整个儿金碧辉煌富丽堂皇。', '["https://dimg04.c-ctrip.com/images/0231s12000dece1z76639_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000dechoh0FFFB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000decgwa7CA3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000decgwhq7D78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000decgwafE53C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000decgwhsA780_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000decgwhu266C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000decgwahC4CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000decgwhwCD21_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-12', '花园双床房', '双床房', '家庭亲子', 248, 5.517452896464707, 0, 0.0, 4, 1.6094379124341005, 9, '["公共设施", "整体满意度", "退房/入住效率"]'::jsonb, '公共设施', '整体满意度', '退房/入住效率', '未知酒店', '未知地点', '匿名', '上午十点半的飞机从上海飞广州一点落地，到酒', '上午十点半的飞机从上海飞广州一点落地，到酒
店差不多两点，就不想再去景点人挤人了，所以
特意选了这家自己就可以当作景点的花园酒店好适合带小朋友的家庭言因为过年期间客人太多，所以一直晚等到四点半多才打扫完房间，但是呢一点也没有影响旅行的心情。寄存完行李以后，拿着酒店地图去把酒店的景点都打一遍卡再去酒店四楼的博物馆听了三点的讲解，了解中西方酒店发展史，逛完博物馆正好去二楼荔湾亭吃个下午茶，一系列操作完毕以后刚刚好回房间休息，完美。不得不说广州真的太有过年和搞钱的氛围感了，整个儿金碧辉煌富丽堂皇。', '2024-03-12', 5, '公共设施');
