INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bc1e3c98b09417659bd', '广州之行的最后一天订在了有“白金五星”之称的“花园酒店”，酒店位于中心城区，极具岭南文化特色并与现代科技相结合；这次行程匆忙，酒店里许多地方没有打卡，早餐选择一楼的瀑布餐厅；酒店的后花园着实惊喜，虽是雨天，景致依然很美！前台服务尚觉欠缺，相比之下，三十楼的行政酒廊堪称完美，工作人员热情好客，详细的介绍、周全的服务，让初来广州的我们真切体会到了宾至如归，在这里也表达对你们的谢意????', '["https://dimg04.c-ctrip.com/images/0233q12000dphepiqE9A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000dphf2ic0D20_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000dphi8rxD3C0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000dpgzqbl3D8D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000dphbllw82A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000dph14g70D25_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000dph5kktDD05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000dphxy6iD45F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-17', '花园大床房', '大床房', '家庭亲子', 193, 5.267858159063328, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '广州之行的最后一天订在了有“白金五星”之称的“花园酒店”，酒店位于中心城区，极具', '广州之行的最后一天订在了有“白金五星”之称的“花园酒店”，酒店位于中心城区，极具岭南文化特色并与现代科技相结合；这次行程匆忙，酒店里许多地方没有打卡，早餐选择一楼的瀑布餐厅；酒店的后花园着实惊喜，虽是雨天，景致依然很美！前台服务尚觉欠缺，相比之下，三十楼的行政酒廊堪称完美，工作人员热情好客，详细的介绍、周全的服务，让初来广州的我们真切体会到了宾至如归，在这里也表达对你们的谢意????', '2024-04-17', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bc1e3c98b09417659be', '服务很到位的老牌五星 早餐厅都有三个 每一个都很有特色', '["https://dimg04.c-ctrip.com/images/0233j12000f4glyulE77E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000f4h0rgm856C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000f4gws4l6446_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000f4gwbuuA04B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-14', '红棉大床套房', '套房', '商务出差', 27, 3.332204510175204, 0, 0.0, 23, 3.1780538303479458, 6, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '服务很到位的老牌五星 早餐厅都有三个 每一个都很有特色', '服务很到位的老牌五星 早餐厅都有三个 每一个都很有特色', '2024-08-14', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bc1e3c98b09417659bf', '非常满意的一次度假体验，超出预期。特别要表扬前台的cecilia小姐姐，悉心安排好我们的住宿，不厌其烦，入住后我们有一间房需要更换为双床，又要加床，她都帮我们一一解决，我们也按照酒店规矩付了需要增加的费用，但整个过程令我们感到非常满意。我们和朋友两家人就在广州市附近的城市居住，我们安排入住当天上午到南越王墓参观，然后入住花园酒店，下午闲逛酒店，还参观了花园酒店博物馆，晚上就在酒店内吃饭+蒲吧，开心快乐地在酒店欢度美好时光！！第二天我们还去了楼顶的旋转餐厅吃早餐，心满意足地离开这里！！我们决定以后再来一次花园酒店，要多住一两天！！', '["https://dimg04.c-ctrip.com/images/0236c12000ii864chF316_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000ii8791rBC2C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237212000ii8cvh60905_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000ii7prdm4632_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000ii7xqk2288B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000ii88pfiC3F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000ii84heo9409_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000ii8f9u44319_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000ii8b6x2FE30_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-13', '红棉大床套房', '套房', '家庭亲子', 267, 5.5909869805108565, 0, 0.0, 20, 3.044522437723423, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '非常满意的一次度假体验，超出预期。特别要表扬前台的cecilia小姐姐，悉心安排', '非常满意的一次度假体验，超出预期。特别要表扬前台的cecilia小姐姐，悉心安排好我们的住宿，不厌其烦，入住后我们有一间房需要更换为双床，又要加床，她都帮我们一一解决，我们也按照酒店规矩付了需要增加的费用，但整个过程令我们感到非常满意。我们和朋友两家人就在广州市附近的城市居住，我们安排入住当天上午到南越王墓参观，然后入住花园酒店，下午闲逛酒店，还参观了花园酒店博物馆，晚上就在酒店内吃饭+蒲吧，开心快乐地在酒店欢度美好时光！！第二天我们还去了楼顶的旋转餐厅吃早餐，心满意足地离开这里！！我们决定以后再来一次花园酒店，要多住一两天！！', '2025-02-13', 5, '前台服务');
