INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bcce3c98b09417659c7', '这次广州行，爸爸极力推荐住花园酒店，真的超级满意。办理入住是一个外国小哥，特别的热情，还送了鲜花，中文也说的非常好！儿子最近热衷看老王的视频，一个劲的说小哥好像老王。酒店荣誉满满，有自己的博物馆可以预约参观。下次到广州来还会选择！', '["https://dimg04.c-ctrip.com/images/0235a12000dlert38C862_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000dlerrp0A264_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j12000dles3g6B491_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000dleqvsuB61A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000dlergu0B1AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000dles39v5755_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000dlerzfi490F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000dletad7DC66_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-05', '花园双床房', '双床房', '家庭亲子', 115, 4.7535901911063645, 0, 0.0, 1, 0.6931471805599453, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '这次广州行，爸爸极力推荐住花园酒店，真的超级满意。办理入住是一个外国小哥，特别的', '这次广州行，爸爸极力推荐住花园酒店，真的超级满意。办理入住是一个外国小哥，特别的热情，还送了鲜花，中文也说的非常好！儿子最近热衷看老王的视频，一个劲的说小哥好像老王。酒店荣誉满满，有自己的博物馆可以预约参观。下次到广州来还会选择！', '2024-04-05', 5, '前台服务');
