INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bcce3c98b09417659ca', '经常来广州花园酒店接待合作伙伴，每次来都感觉很舒心，一进门有礼宾帮忙开门，并且主动和我打招呼，入住认识了 前厅部副经理 Lavinia吴灵伶，很热情地给我办入住，让我感受到温暖和体贴的服务，非常满意，五星好评', '["https://dimg04.c-ctrip.com/images/0232s12000f1uw0a8A2DB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000f1v0u601BE3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000f1uxsy0DB2F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000f1v0fky4712_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000f1v2hoa0F5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000f1utn7114DB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000f1v0u624386_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-08', '花园大床房', '大床房', '商务出差', 104, 4.653960350157523, 0, 0.0, 10, 2.3978952727983707, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '经常来广州花园酒店接待合作伙伴，每次来都感觉很舒心，一进门有礼宾帮忙开门，并且主', '经常来广州花园酒店接待合作伙伴，每次来都感觉很舒心，一进门有礼宾帮忙开门，并且主动和我打招呼，入住认识了 前厅部副经理 Lavinia吴灵伶，很热情地给我办入住，让我感受到温暖和体贴的服务，非常满意，五星好评', '2024-08-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bcce3c98b09417659cb', '非常满意的一次住宿体验，酒店设施好，服务热情周到，免费升级客房并升级至30楼旋转餐厅享用早餐，非常感谢！酒店就在地铁淘金站旁边，出行非常方便，距机场也只有二三十分钟车程。总之，本次广州之行让我爱上了广州。', '["https://dimg04.c-ctrip.com/images/0236w12000dlg1b9kEF0E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000dlg0iizB09E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000dlg0a8o359D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000dlg1b9m0EDB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000dlg004t2A0A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000dlg0a8q495E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-05', '花园双床房', '双床房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 7, 2.079441541679836, 8, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '非常满意的一次住宿体验，酒店设施好，服务热情周到，免费升级客房并升级至30楼旋转', '非常满意的一次住宿体验，酒店设施好，服务热情周到，免费升级客房并升级至30楼旋转餐厅享用早餐，非常感谢！酒店就在地铁淘金站旁边，出行非常方便，距机场也只有二三十分钟车程。总之，本次广州之行让我爱上了广州。', '2024-04-05', 5, '整体满意度');
