INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659cd', '花园酒店是我住过的最好的酒店之一，酒店内部环境非常养眼，服务也非常棒，非常满意！', '["https://dimg04.c-ctrip.com/images/0231r12000eub4wkq7E7F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000eub8q7j1DA6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000euav5yt39CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237212000euay0i50DFE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000euav5yv169B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000euav5241261_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000eub8uudE6E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000eub0yljC261_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-20', '花园双床房', '双床房', '情侣出游', 40, 3.713572066704308, 0, 0.0, 49, 3.912023005428146, 5, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '花园酒店是我住过的最好的酒店之一，酒店内部环境非常养眼，服务也非常棒，非常满意！', '花园酒店是我住过的最好的酒店之一，酒店内部环境非常养眼，服务也非常棒，非常满意！', '2024-07-20', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659ce', '服务很好，每个人都很热情，免费升级了一个套房，很安静很舒服，欢迎甜品很可爱，其实本来冲着美食酒店入住的，对餐食有点小小的失望，不过下次来广州还会选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0234t12000dt5l3zjC8F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000dt5tntmAD54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-28', '城央绿意大床房', '大床房', '朋友出游', 79, 4.382026634673881, 0, 0.0, 3, 1.3862943611198906, 7, '["前台服务", "整体满意度", "安静程度"]'::jsonb, '前台服务', '整体满意度', '安静程度', '未知酒店', '未知地点', '匿名', '服务很好，每个人都很热情，免费升级了一个套房，很安静很舒服，欢迎甜品很可爱，其实', '服务很好，每个人都很热情，免费升级了一个套房，很安静很舒服，欢迎甜品很可爱，其实本来冲着美食酒店入住的，对餐食有点小小的失望，不过下次来广州还会选择花园酒店。', '2024-04-28', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659cf', '很不错，老牌五星级酒店标杆', '["https://dimg04.c-ctrip.com/images/0234a12000fadl54sDC63_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-28', '花园双床房', '双床房', '家庭亲子', 13, 2.6390573296152584, 0, 0.0, 2, 1.0986122886681098, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '很不错，老牌五星级酒店标杆', '很不错，老牌五星级酒店标杆', '2024-08-28', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659d0', '卫生干净   服务到位  还有博物馆参观。了解中外酒店史??', '["https://dimg04.c-ctrip.com/images/0236612000evwes92537C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-24', '花园大床房', '大床房', '其他', 30, 3.4339872044851463, 0, 0.0, 5, 1.791759469228055, 4, '["卫生状况", "前台服务", "客房服务"]'::jsonb, '卫生状况', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '卫生干净   服务到位  还有博物馆参观。了解中外酒店史??', '卫生干净   服务到位  还有博物馆参观。了解中外酒店史??', '2024-07-24', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659d1', '谢谢花园酒店的接待，从一下车开始就收到了无微不至的关怀。前台的邓先生给我们安排了一间套房，还附赠了行政酒廊入场券和早餐券；房间宽敞明亮整洁，硬件设施也无可挑剔；在暴雨天气下，酒店的娱乐设施（后花园博物馆什么的应有尽有）和餐饮也足够满足需求。凌璇阁的餐饮环境服务也让人印象深刻，特别是有一位印度裔的服务员Carrie很贴心，中文也特别好。Thank you Carrie！岭南集团的酒店水准一直都让人很满意！', '["https://dimg04.c-ctrip.com/images/0234h12000dt9ldrn2326_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235912000dt8yqxq951B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000dt97mdzC449_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000dt9l6cx51F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000dt94xkhE35F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-28', '花园大床房', '大床房', '情侣出游', 203, 5.318119993844216, 0, 0.0, 18, 2.9444389791664403, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '谢谢花园酒店的接待，从一下车开始就收到了无微不至的关怀。前台的邓先生给我们安排了', '谢谢花园酒店的接待，从一下车开始就收到了无微不至的关怀。前台的邓先生给我们安排了一间套房，还附赠了行政酒廊入场券和早餐券；房间宽敞明亮整洁，硬件设施也无可挑剔；在暴雨天气下，酒店的娱乐设施（后花园博物馆什么的应有尽有）和餐饮也足够满足需求。凌璇阁的餐饮环境服务也让人印象深刻，特别是有一位印度裔的服务员Carrie很贴心，中文也特别好。Thank you Carrie！岭南集团的酒店水准一直都让人很满意！', '2024-04-28', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659d2', '酒店环境一流，很多景观值得亲子打卡，参加活动也有小礼物赠送；前台服务到位，ann和cassie直接帮忙升级为红棉房并加赠早餐以及酒廊待遇一人份；餐饮方面有多个餐厅可供选择，美食多样、服务勤快。总之，在携程活动加持下酒店体验超预期，大赞！', '["https://dimg04.c-ctrip.com/images/0230c12000f9b4sgf72E5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000f9b1tsb81A5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000f9b5wswDA83_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000f9b4mfb3A13_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-26', '花园双床房', '双床房', '家庭亲子', 118, 4.77912349311153, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店环境一流，很多景观值得亲子打卡，参加活动也有小礼物赠送；前台服务到位，ann', '酒店环境一流，很多景观值得亲子打卡，参加活动也有小礼物赠送；前台服务到位，ann和cassie直接帮忙升级为红棉房并加赠早餐以及酒廊待遇一人份；餐饮方面有多个餐厅可供选择，美食多样、服务勤快。总之，在携程活动加持下酒店体验超预期，大赞！', '2024-08-26', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659d3', '广州花园酒店，让我们非常惊艳！大堂依然大气、豪华，中西餐都让人极其享受。虽然是老牌五星酒店，各类设施维护保养极好，服务更是保持了五星水准！强烈推荐！', '["https://dimg04.c-ctrip.com/images/0236o12000do2nfbuC63F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237212000do2nwcwD440_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000do2of9v19D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000do2o1ymD7F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000do2on2b81A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000do2o0lr27C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000do2oc5aD319_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230u12000do2p2c16A4E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000do2nfc311C4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-13', '城央绿意大床房', '大床房', '商务出差', 74, 4.31748811353631, 1, 0.6931471805599453, 7, 2.079441541679836, 8, '["整体满意度", "餐饮设施", "公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '广州花园酒店，让我们非常惊艳！大堂依然大气、豪华，中西餐都让人极其享受。虽然是老', '广州花园酒店，让我们非常惊艳！大堂依然大气、豪华，中西餐都让人极其享受。虽然是老牌五星酒店，各类设施维护保养极好，服务更是保持了五星水准！强烈推荐！', '2024-04-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659d4', '到广州一如既往选择花园酒店入住，地铁和打车出行都很方便。前台帮忙升级了套房～宽敞很多住起来很舒服，设施一点点旧但齐全整洁。客务中心小杨也有主动了解体验反馈。
花园酒店真的经典，比起普通酒店好玩，岭南文化满满，这次有时间参观了四楼博物馆。瀑布餐厅早餐时间开到11点，不用早起赶时间??餐厅view很好！24h的健身房也很贴心！下次来有机会再试试桃园馆餐厅！', '["https://dimg04.c-ctrip.com/images/0236012000jlptwfgE650_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000jlpsm9x9B8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000jlpeed1E1C4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000jlq5jyaA7C7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000jlpzmu6CAC5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-06', '城央绿意大床房', '大床房', '朋友出游', 177, 5.181783550292085, 0, 0.0, 18, 2.9444389791664403, 9, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '到广州一如既往选择花园酒店入住，地铁和打车出行都很方便。前台帮忙升级了套房～宽敞', '到广州一如既往选择花园酒店入住，地铁和打车出行都很方便。前台帮忙升级了套房～宽敞很多住起来很舒服，设施一点点旧但齐全整洁。客务中心小杨也有主动了解体验反馈。
花园酒店真的经典，比起普通酒店好玩，岭南文化满满，这次有时间参观了四楼博物馆。瀑布餐厅早餐时间开到11点，不用早起赶时间??餐厅view很好！24h的健身房也很贴心！下次来有机会再试试桃园馆餐厅！', '2025-04-06', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bd8e3c98b09417659d5', '老牌酒店，情怀满满，还有多家超棒的餐厅，很值得一住。', '["https://dimg04.c-ctrip.com/images/0236v12000ey0mq9q18B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000ey0nqbmFFC7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000ey0idiyE835_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000ey0isywF9A9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000ey0grbgCCEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-30', '红棉大床套房', '套房', '家庭亲子', 26, 3.295836866004329, 0, 0.0, 7, 2.079441541679836, 5, '["餐饮设施", "整体满意度", "性价比"]'::jsonb, '餐饮设施', '整体满意度', '性价比', '未知酒店', '未知地点', '匿名', '老牌酒店，情怀满满，还有多家超棒的餐厅，很值得一住。', '老牌酒店，情怀满满，还有多家超棒的餐厅，很值得一住。', '2024-07-30', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027be3e3c98b09417659d6', '一走进大堂被震撼到了，金碧辉煌。酒店各环节的服务都很好，特别是我们的车刚停，门童立马过来开门、提箱，引导到前台办理入住。客房干净整洁，就是隔音不是很好，酒店位置交通便利，出行方便。', '["https://dimg04.c-ctrip.com/images/0201a12000doc614u8416_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0231z12000dobt8na5FEE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000doboa3gE46B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-14', '花园双床房', '双床房', '朋友出游', 90, 4.51085950651685, 0, 0.0, 27, 3.332204510175204, 8, '["前台服务", "交通便利性", "安静程度"]'::jsonb, '前台服务', '交通便利性', '安静程度', '未知酒店', '未知地点', '匿名', '一走进大堂被震撼到了，金碧辉煌。酒店各环节的服务都很好，特别是我们的车刚停，门童', '一走进大堂被震撼到了，金碧辉煌。酒店各环节的服务都很好，特别是我们的车刚停，门童立马过来开门、提箱，引导到前台办理入住。客房干净整洁，就是隔音不是很好，酒店位置交通便利，出行方便。', '2024-04-14', 5, '前台服务');
