INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027be3e3c98b09417659db', '终于有机会体验了一把心心念念的酒店，推门瞬间就有了度假的感觉。各方面服务都很贴心，酒店套餐还可以再多一点～', '["https://dimg04.c-ctrip.com/images/0233k12000eva7ypv736B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000evabe9x211F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000eva6j3kE326_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000evaebm9B2CE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-23', '羊羊得意主题大床房', '主题房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 47, 3.871201010907891, 6, '["整体满意度", "餐饮设施"]'::jsonb, '整体满意度', '餐饮设施', NULL, '未知酒店', '未知地点', '匿名', '终于有机会体验了一把心心念念的酒店，推门瞬间就有了度假的感觉。各方面服务都很贴心', '终于有机会体验了一把心心念念的酒店，推门瞬间就有了度假的感觉。各方面服务都很贴心，酒店套餐还可以再多一点～', '2024-07-23', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027be3e3c98b09417659dc', '酒店花园很美，服务也很赞，真是一次美好的旅行', '["https://dimg04.c-ctrip.com/images/0234g12000eynxv3n1D08_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000eynzfbc7D5C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000eyo92am510E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-01', '花园双床房', '双床房', '家庭亲子', 22, 3.1354942159291497, 0, 0.0, 6, 1.9459101490553128, 4, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '酒店花园很美，服务也很赞，真是一次美好的旅行', '酒店花园很美，服务也很赞，真是一次美好的旅行', '2024-08-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027be3e3c98b09417659dd', '广州花园酒店的花园酒廊堪称城市中的一方静谧绿洲，无论是环境、服务还是餐品都令人印象深刻。步入酒廊的瞬间，便被其优雅的设计所吸引——挑高的玻璃穹顶将自然光线温柔洒落，绿植环绕的空间与典雅的欧式家具相映成趣，仿佛置身都市花园。落地窗外是郁郁葱葱的庭院景观，尤其在午后阳光斜照时，光影交错间更显诗意，随手一拍皆是质感大片。
服务细节堪称典范，花园酒廊的Kitty小姐姐笑容亲切且专业高效，从入座时的贴心指引到点单时的细致推荐，无不体现白金五星级酒店的待客之道。席间Kitty会主动询问需求，甚至为我们拍照调整灯光角度，细微之处尽显用心。
餐品方面，花园酒廊的欢乐时光堪称招牌。三层银质托盘上，咸甜搭配的精致点心既满足味蕾又充满艺术感——烟熏三文鱼挞的咸香、芒果慕斯的清甜、司康饼的松软温热，每一口都令人回味。特调饮品也别具巧思，推荐尝试以岭南水果为灵感的季节限定鸡尾酒，果香与酒香融合得恰到好处。若赶上晚上，现场还会有乐队演奏，无论家庭小聚、商务洽谈或独自放空都极为适宜。
总体而言，花园酒廊以高品质的环境与服务，将都市奢华与自然惬意完美结合，是值得反复打卡的城中秘境。离店时还会送酒店特色小羊，这份温暖的小惊喜，为我的出行体验画上了圆满句号。', '["https://dimg04.c-ctrip.com/images/0235m12000j1u17lk326B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000j1u2gqd6C6C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000j1u2epf5041_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000j1u1b6e7717_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000j1ujdzn4281_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-13', '花园双床房', '双床房', '家庭亲子', 519, 6.253828811575473, 0, 0.0, 1, 0.6931471805599453, 10, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '广州花园酒店的花园酒廊堪称城市中的一方静谧绿洲，无论是环境、服务还是餐品都令人印', '广州花园酒店的花园酒廊堪称城市中的一方静谧绿洲，无论是环境、服务还是餐品都令人印象深刻。步入酒廊的瞬间，便被其优雅的设计所吸引——挑高的玻璃穹顶将自然光线温柔洒落，绿植环绕的空间与典雅的欧式家具相映成趣，仿佛置身都市花园。落地窗外是郁郁葱葱的庭院景观，尤其在午后阳光斜照时，光影交错间更显诗意，随手一拍皆是质感大片。
