餐品方面，花园酒廊的欢乐时光堪称招牌。三层银质托盘上，咸甜搭配的精致点心既满足味蕾又充满艺术感——烟熏三文鱼挞的咸香、芒果慕斯的清甜、司康饼的松软温热，每一口都令人回味。特调饮品也别具巧思，推荐尝试以岭南水果为灵感的季节限定鸡尾酒，果香与酒香融合得恰到好处。若赶上晚上，现场还会有乐队演奏，无论家庭小聚、商务洽谈或独自放空都极为适宜。
总体而言，花园酒廊以高品质的环境与服务，将都市奢华与自然惬意完美结合，是值得反复打卡的城中秘境。离店时还会送酒店特色小羊，这份温暖的小惊喜，为我的出行体验画上了圆满句号。', '2025-03-13', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027be3e3c98b09417659de', '广州老牌五星，名不虚传。管理到位，服务员认真客气，业务能力强，酒店整个环境非常好，有自己的后花园，餐饮档次高，早餐很认真。周边出行也方便，对面友谊商店六楼的广州酒店品质很高。这次酒店很客气，还给我们升级了套房，很棒。以往升级最多是亲子房湖景房或者海景房，第一次碰到五星级能升级套房的。感谢酒店的精心服务！', '["https://dimg04.c-ctrip.com/images/0233t12000dhh5oia214B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000dhh5jgj908E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000dhh5gbgE843_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000dhh5dpl9591_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000dhh568u8C42_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000dhh5y1l3C86_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-23', '花园双床房', '双床房', '家庭亲子', 152, 5.030437921392435, 0, 0.0, 56, 4.04305126783455, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '广州老牌五星，名不虚传。管理到位，服务员认真客气，业务能力强，酒店整个环境非常好', '广州老牌五星，名不虚传。管理到位，服务员认真客气，业务能力强，酒店整个环境非常好，有自己的后花园，餐饮档次高，早餐很认真。周边出行也方便，对面友谊商店六楼的广州酒店品质很高。这次酒店很客气，还给我们升级了套房，很棒。以往升级最多是亲子房湖景房或者海景房，第一次碰到五星级能升级套房的。感谢酒店的精心服务！', '2024-03-23', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027be3e3c98b09417659df', '感觉依旧很不错', '["https://dimg04.c-ctrip.com/images/0233p12000fe4q24t7F29_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-09-04', '花园双床房', '双床房', '商务出差', 7, 2.079441541679836, 0, 0.0, 1, 0.6931471805599453, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '感觉依旧很不错', '感觉依旧很不错', '2024-09-04', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bede3c98b09417659e0', '非常棒的老牌酒店，服务也很好', '["https://dimg04.c-ctrip.com/images/0234q12000fhpfa7h8DCB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-10', '花园大床房', '大床房', '商务出差', 14, 2.70805020110221, 0, 0.0, 3, 1.3862943611198906, 4, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '非常棒的老牌酒店，服务也很好', '非常棒的老牌酒店，服务也很好', '2024-09-10', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bede3c98b09417659e1', '设施：作为中国白金级别酒店所有设施一应俱全，甚至还有一个花园酒店博物馆??
卫生：非常干净卫生，房间内的浴缸是我见过最干净的
环境：位于老城区黄金位置，出行交通都十分便利，是出游广州一个非常好的选择
服务：大大的好，从入住开始就感受到了服务的热情，因为我们提前有说过今天是家人生日，前台的VIRIA非常热情告知我生日的安排，不止升级了房型，还准备了蛋糕。客务部的小华还非常热心帮我们把蛋糕准备到了晚上才给我们，让我们享受到了最美味的蛋糕。临走的时候也和大堂的阿金表达了这次入住的感受，只能说非常满意！下次还要再来????', '["https://dimg04.c-ctrip.com/images/0230v12000jg1lqbaE7D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000jg0wveb5ED6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000jg1bqfqAF99_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000jg0g7nz9727_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000jg0wjpzA8E9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-31', '花园大床房', '大床房', '情侣出游', 263, 5.575949103146316, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '设施：作为中国白金级别酒店所有设施一应俱全，甚至还有一个花园酒店博物馆??', '设施：作为中国白金级别酒店所有设施一应俱全，甚至还有一个花园酒店博物馆??
卫生：非常干净卫生，房间内的浴缸是我见过最干净的
环境：位于老城区黄金位置，出行交通都十分便利，是出游广州一个非常好的选择
服务：大大的好，从入住开始就感受到了服务的热情，因为我们提前有说过今天是家人生日，前台的VIRIA非常热情告知我生日的安排，不止升级了房型，还准备了蛋糕。客务部的小华还非常热心帮我们把蛋糕准备到了晚上才给我们，让我们享受到了最美味的蛋糕。临走的时候也和大堂的阿金表达了这次入住的感受，只能说非常满意！下次还要再来????', '2025-03-31', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bede3c98b09417659e2', '每次去广州都会选择入住花园，房间舒适干净，服务态度也很棒～这次朋友过来也推荐了她～位置优越出行方便！', '["https://dimg04.c-ctrip.com/images/0235c12000echw4esBFF1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000ecicgnb20FC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000eci7mkoBB7B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-06', '花园双床房', '双床房', '朋友出游', 50, 3.9318256327243257, 0, 0.0, 11, 2.4849066497880004, 7, '["整体满意度", "交通便利性", "卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况', '未知酒店', '未知地点', '匿名', '每次去广州都会选择入住花园，房间舒适干净，服务态度也很棒～这次朋友过来也推荐了她', '每次去广州都会选择入住花园，房间舒适干净，服务态度也很棒～这次朋友过来也推荐了她～位置优越出行方便！', '2024-06-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bede3c98b09417659e3', '不错的酒店，地段很好，入住方便快捷，大堂漂亮，后面小花园风景也很美，因为有事只入住一天，下次来广州继续选择该酒店。', '["https://dimg04.c-ctrip.com/images/0234u12000e3iitlo1AEC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000e3ijb2017BC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-21', '花园双床房', '双床房', '朋友出游', 57, 4.060443010546419, 0, 0.0, 6, 1.9459101490553128, 7, '["交通便利性", "整体满意度", "退房/入住效率"]'::jsonb, '交通便利性', '整体满意度', '退房/入住效率', '未知酒店', '未知地点', '匿名', '不错的酒店，地段很好，入住方便快捷，大堂漂亮，后面小花园风景也很美，因为有事只入', '不错的酒店，地段很好，入住方便快捷，大堂漂亮，后面小花园风景也很美，因为有事只入住一天，下次来广州继续选择该酒店。', '2024-05-21', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bede3c98b09417659e4', '房间卫生不错，酒店环境好，出入方便，这次前台服务感觉不怎地，有点感觉被套路了，我们到酒店的时候差不多中午十一点多了，说我订的房间还没有打扫卫生，大概还需要一个多小时，接下来前台服务员说只有升级版的房间还有，另外还需加钱，大中午的我们只有升级了，心里有种说不出的感觉。', '["https://dimg04.c-ctrip.com/images/0236y12000dg7gf6hE5A4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-19', '红棉大床套房', '套房', '商务出差', 133, 4.897839799950911, 2, 1.0986122886681098, 22, 3.1354942159291497, 8, '["前台服务", "退房/入住效率", "卫生状况"]'::jsonb, '前台服务', '退房/入住效率', '卫生状况', '未知酒店', '未知地点', '匿名', '房间卫生不错，酒店环境好，出入方便，这次前台服务感觉不怎地，有点感觉被套路了，我', '房间卫生不错，酒店环境好，出入方便，这次前台服务感觉不怎地，有点感觉被套路了，我们到酒店的时候差不多中午十一点多了，说我订的房间还没有打扫卫生，大概还需要一个多小时，接下来前台服务员说只有升级版的房间还有，另外还需加钱，大中午的我们只有升级了，心里有种说不出的感觉。', '2024-03-19', 5, '前台服务');
