INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bede3c98b09417659e7', '酒店服务很好，很多外宾客人，出门就是地铁站，去哪里都很方面，非常推荐！', '["https://dimg04.c-ctrip.com/images/0236912000eoaq1kp6082_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-04', '花园大床房', '大床房', '家庭亲子', 35, 3.58351893845611, 0, 0.0, 8, 2.19722457733622, 6, '["交通便利性", "整体满意度", "前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '酒店服务很好，很多外宾客人，出门就是地铁站，去哪里都很方面，非常推荐！', '酒店服务很好，很多外宾客人，出门就是地铁站，去哪里都很方面，非常推荐！', '2024-07-04', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bede3c98b09417659e8', '满意干净舒适', '["https://dimg04.c-ctrip.com/images/0232g12000fccqokb765A_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-09-01', '花园大床房', '大床房', '家庭亲子', 6, 1.9459101490553128, 0, 0.0, 4, 1.6094379124341005, 3, '["整体满意度", "卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '满意干净舒适', '满意干净舒适', '2024-09-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bede3c98b09417659e9', '这家广州地标酒店，依旧被惊艳得说不出话！踏入挑高10米的鎏金大堂瞬间，金龙藻井与巨型壁画交相辉映，随手一拍都是大片既视感。这次入住的虽有些瑕疵，但细节和卫生做到极致：浴巾蓬松度堪比云朵，迷你吧饮品排列如仪仗队般整齐，其他地方都一尘不染！
真正让体验升华的是充满温度的服务——前台的高效，礼宾部拉门小哥的欢迎；最令人印象深刻的是大堂经理小郑，热情与敏捷应对，必须大大的点赞！ 虽然酒店确实有历史，但如果说硬件是酒店的骨骼，服务便是流淌的血液。广州花园酒店用实力证明：真正的顶奢，永远以人为尺。  这次还遇到了超棒的前台VIRIA 。', '["https://dimg04.c-ctrip.com/images/0234j12000jbekvhmD79A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000jbex529FAA1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000jbek8apDB12_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-03-25', '城央绿意双床房', '双床房', '家庭亲子', 265, 5.583496308781699, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '这家广州地标酒店，依旧被惊艳得说不出话！踏入挑高10米的鎏金大堂瞬间，金龙藻井与', '这家广州地标酒店，依旧被惊艳得说不出话！踏入挑高10米的鎏金大堂瞬间，金龙藻井与巨型壁画交相辉映，随手一拍都是大片既视感。这次入住的虽有些瑕疵，但细节和卫生做到极致：浴巾蓬松度堪比云朵，迷你吧饮品排列如仪仗队般整齐，其他地方都一尘不染！
真正让体验升华的是充满温度的服务——前台的高效，礼宾部拉门小哥的欢迎；最令人印象深刻的是大堂经理小郑，热情与敏捷应对，必须大大的点赞！ 虽然酒店确实有历史，但如果说硬件是酒店的骨骼，服务便是流淌的血液。广州花园酒店用实力证明：真正的顶奢，永远以人为尺。  这次还遇到了超棒的前台VIRIA 。', '2025-03-25', 4, '前台服务');
