INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bf9e3c98b09417659eb', '花园酒店，一如既往如此优秀的酒店！超赞！', '["https://dimg04.c-ctrip.com/images/0234i12000ewnwxf8BFCE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000ewnyudtA75B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000ewnww8hD3D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000ewnywf16E53_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-26', '花园大床房', '大床房', '商务出差', 20, 3.044522437723423, 0, 0.0, 4, 1.6094379124341005, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '花园酒店，一如既往如此优秀的酒店！超赞！', '花园酒店，一如既往如此优秀的酒店！超赞！', '2024-07-26', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bf9e3c98b09417659ec', '带娃来广州玩选择了花园酒店，环境很棒，餐食都很好吃，服务特别好，尤其对小朋友真是太友好了，让妈妈们感受到满满的温暖', '["https://dimg04.c-ctrip.com/images/0236v12000drlwr0eF3B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000drlu9g2AFCC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000drlu9g4537F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000drlu9wfF921_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000drlu9g63324_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000drlulnr3A2B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000drlu9wk3AE0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000drlu9wmF906_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000drlu9ga77C5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-24', '花园双床房', '双床房', '家庭亲子', 57, 4.060443010546419, 0, 0.0, 3, 1.3862943611198906, 6, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '带娃来广州玩选择了花园酒店，环境很棒，餐食都很好吃，服务特别好，尤其对小朋友真是', '带娃来广州玩选择了花园酒店，环境很棒，餐食都很好吃，服务特别好，尤其对小朋友真是太友好了，让妈妈们感受到满满的温暖', '2024-04-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bf9e3c98b09417659ed', '春节前带着父母孩子逛羊城入住了白金五星级的花园酒店，酒店1985年开业至今，除了客房等正常损耗翻新外，基本上各种格局和摆设均保持了40年；在瀑布餐厅吃了早餐，荔湾厅吃了晚餐，味道也很好；入住的红棉房型，孩子高兴的手舞足蹈；在今日当值Golden Key John导览下参观了各个点，40年的酒店历史积淀深厚，父母平时比较少拍照的，没想到这次却是各种拍，直接停不下来，一改平时住酒店的风格；最后让我大感意外的是内设的博物馆，不仅可以对公众开放，还非常系统梳理了国内外酒店发展史，脉络非常清晰易懂，印象深刻，还有828间房体量的酒店，服务人员各种到位，无论餐厅，前台，接线员，真的是好的服务才让人更愿意再来。酒店位置也无敌，出门地铁站，西有越秀公园，东有动物园，无论带老人还是开孩子，可以说是游刃有余，无愧酒店标杆称号！下次来广州，还会住这里！', '["https://dimg04.c-ctrip.com/images/0235012000d3bu9iq51F5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000d3bfu23D32A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000d3bjm5g0A66_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000d3bm036F98C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000d3bw7xvD80B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000d3by8aiA6D6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000d3by4fbAA8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000d3bg27fA45A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000d3bw17bDCC0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-31', '红棉双床套房', '套房', '家庭亲子', 370, 5.916202062607435, 1, 0.6931471805599453, 7, 2.079441541679836, 10, '["整体满意度", "前台服务", "交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '春节前带着父母孩子逛羊城入住了白金五星级的花园酒店，酒店1985年开业至今，除了', '春节前带着父母孩子逛羊城入住了白金五星级的花园酒店，酒店1985年开业至今，除了客房等正常损耗翻新外，基本上各种格局和摆设均保持了40年；在瀑布餐厅吃了早餐，荔湾厅吃了晚餐，味道也很好；入住的红棉房型，孩子高兴的手舞足蹈；在今日当值Golden Key John导览下参观了各个点，40年的酒店历史积淀深厚，父母平时比较少拍照的，没想到这次却是各种拍，直接停不下来，一改平时住酒店的风格；最后让我大感意外的是内设的博物馆，不仅可以对公众开放，还非常系统梳理了国内外酒店发展史，脉络非常清晰易懂，印象深刻，还有828间房体量的酒店，服务人员各种到位，无论餐厅，前台，接线员，真的是好的服务才让人更愿意再来。酒店位置也无敌，出门地铁站，西有越秀公园，东有动物园，无论带老人还是开孩子，可以说是游刃有余，无愧酒店标杆称号！下次来广州，还会住这里！', '2024-01-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bf9e3c98b09417659ee', '环境人文都很不错，就是住的楼层高的话窗户是封闭的，其他都很好', '["https://dimg04.c-ctrip.com/images/0230s12000ep9jm3dE4B0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000ep9gosg1B4B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000ep9ajb81B28_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-06', '花园双床房', '双床房', '家庭亲子', 30, 3.4339872044851463, 0, 0.0, 7, 2.079441541679836, 5, '["景观/朝向", "整体满意度"]'::jsonb, '景观/朝向', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '环境人文都很不错，就是住的楼层高的话窗户是封闭的，其他都很好', '环境人文都很不错，就是住的楼层高的话窗户是封闭的，其他都很好', '2024-07-06', 5, '景观/朝向');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bf9e3c98b09417659ef', '本来以为老牌酒店一切设施都比较老，实际上一进去就被金碧辉煌的大厅吸引了，然后酒店也很有复古风格，装饰的一些小细节都很棒。
然后大堂服务人员都很不错，有礼貌而且会有专门的服务员摁电梯。感谢大堂rebecca，给了我们一个不错的房间，而且相关情况讲解的都很清楚。
酒店位置也很不错，在老城区，旁边广州酒家、利苑和点都德这些走走就到，所以我们没有定早餐，早上直接去喝早茶非常方便。然后酒店自带的荔湾亭也很好吃啊，走的那天下雨，就没有出去觅食，去荔湾亭吃了一顿，云吞面和牛肉丸超赞。
总之是一个很不错的酒店，下次来广州还会入住，推荐给大家。', '["https://dimg04.c-ctrip.com/images/0234n12000devx9vfFFC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000devwxzl0F66_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000dew70af16D6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-14', '花园双床房', '双床房', '朋友出游', 269, 5.598421958998375, 0, 0.0, 14, 2.70805020110221, 9, '["整体满意度", "周边配套", "前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '本来以为老牌酒店一切设施都比较老，实际上一进去就被金碧辉煌的大厅吸引了，然后酒店', '本来以为老牌酒店一切设施都比较老，实际上一进去就被金碧辉煌的大厅吸引了，然后酒店也很有复古风格，装饰的一些小细节都很棒。
然后大堂服务人员都很不错，有礼貌而且会有专门的服务员摁电梯。感谢大堂rebecca，给了我们一个不错的房间，而且相关情况讲解的都很清楚。
酒店位置也很不错，在老城区，旁边广州酒家、利苑和点都德这些走走就到，所以我们没有定早餐，早上直接去喝早茶非常方便。然后酒店自带的荔湾亭也很好吃啊，走的那天下雨，就没有出去觅食，去荔湾亭吃了一顿，云吞面和牛肉丸超赞。
总之是一个很不错的酒店，下次来广州还会入住，推荐给大家。', '2024-03-14', 5, '整体满意度');
