INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027bf9e3c98b09417659f3', '环境一流，鲜花环绕，名副其实的鲜花酒店。前台帮我们安排了朝向很好的户型，透过窗户看园景，三月的羊城木棉花开，草坪上的喷泉潺潺，春意盎然的景象尽收眼底……
房间布局合理，洗浴分开很fashion，每日提供纯净水、胶囊咖啡和高档茶包，处处彰显五星级的周到、细致。
客服阿姨的服务一流，每天外出回来后房间里收拾得整整齐齐，干净清爽，衣服都帮我们折好。酒店打车非常方便，服务生会积极主动帮助拿行李，很贴心。
