INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c04e3c98b09417659fa', '周末带小朋友到广州玩，无意中订到的花园酒店原来是一家宝藏酒店，比我的年龄还大，但各方面一点都不落后，设施绝对一流，服务十分到位，不愧为白金五星。
酒店周边配套很成熟，出行也很方便，出门就是地铁口，到市内多个景区也就半小时车程，周末过来citywalk感觉挺好的。退房后前台可以寄存行李，下午可以继续逛吃。
总之是一次满意的入住体验。', '["https://dimg04.c-ctrip.com/images/0232c12000dc4u4ua3FC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000dc4rcz222D2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000dc4p6885F4A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000dc4s5hu24BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000dc4uz5vAEA6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000dc4ljegC633_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-03', '花园双床房', '双床房', '家庭亲子', 166, 5.117993812416755, 0, 0.0, 5, 1.791759469228055, 8, '["整体满意度", "周边配套", "交通便利性"]'::jsonb, '整体满意度', '周边配套', '交通便利性', '未知酒店', '未知地点', '匿名', '周末带小朋友到广州玩，无意中订到的花园酒店原来是一家宝藏酒店，比我的年龄还大，但', '周末带小朋友到广州玩，无意中订到的花园酒店原来是一家宝藏酒店，比我的年龄还大，但各方面一点都不落后，设施绝对一流，服务十分到位，不愧为白金五星。
酒店周边配套很成熟，出行也很方便，出门就是地铁口，到市内多个景区也就半小时车程，周末过来citywalk感觉挺好的。退房后前台可以寄存行李，下午可以继续逛吃。
总之是一次满意的入住体验。', '2024-03-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c04e3c98b09417659fb', '真是宝藏酒店啊，本身就是个度假地，很气派精致优雅老钱风，有历史有文化有品位，瀑布餐厅，岭南花园，各种餐厅，小黄鸭是超大套房，还有一座宝藏的博物馆。服务水平高，总之就是让客人觉得舒适又体面。', '["https://dimg04.c-ctrip.com/images/0236412000d8pjfnqC231_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000d8pb3pn32B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000d8pdopmC1D5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000d8pkbvpE206_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000d8p96peA1A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000d8pa0tt1DAB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000d8p93et78AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236t12000d8pky90D9D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000d8pczq70AF2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-19', '盼酷小黄鸭亲子主题大床房', '主题房', '家庭亲子', 94, 4.553876891600541, 0, 0.0, 10, 2.3978952727983707, 8, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '真是宝藏酒店啊，本身就是个度假地，很气派精致优雅老钱风，有历史有文化有品位，瀑布', '真是宝藏酒店啊，本身就是个度假地，很气派精致优雅老钱风，有历史有文化有品位，瀑布餐厅，岭南花园，各种餐厅，小黄鸭是超大套房，还有一座宝藏的博物馆。服务水平高，总之就是让客人觉得舒适又体面。', '2024-02-19', 5, '整体满意度');
