INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c0ee3c98b09417659fe', '房间装修很好，整洁，空气清新。
酒店大堂豪华大气，很多旅客在大堂拍照留念，我们也不例外。
酒店门口有循环车道，方便接送客户。还设有临时停车场，充电桩，规划得很周到。
花园酒店的五星级实至名归，快来体验吧！', '["https://dimg04.c-ctrip.com/images/0230j12000dbytjd47062_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000dbyutin3A83_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-03', '花园大床房', '大床房', '商务出差', 102, 4.634728988229636, 0, 0.0, 15, 2.772588722239781, 8, '["房间设施", "公共设施", "整体满意度"]'::jsonb, '房间设施', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间装修很好，整洁，空气清新。', '房间装修很好，整洁，空气清新。
酒店大堂豪华大气，很多旅客在大堂拍照留念，我们也不例外。
酒店门口有循环车道，方便接送客户。还设有临时停车场，充电桩，规划得很周到。
花园酒店的五星级实至名归，快来体验吧！', '2024-03-03', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c0ee3c98b09417659ff', '环境优美，服务热情，卫生干净，房间设施还行。', '["https://dimg04.c-ctrip.com/images/0236e12000eqb02d07362_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000eqbbfz19DC9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000eqb4sws0DA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-09', '花园双床房', '双床房', '家庭亲子', 22, 3.1354942159291497, 0, 0.0, 14, 2.70805020110221, 5, '["整体满意度", "卫生状况", "房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施', '未知酒店', '未知地点', '匿名', '环境优美，服务热情，卫生干净，房间设施还行。', '环境优美，服务热情，卫生干净，房间设施还行。', '2024-07-09', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c0ee3c98b0941765a00', '后花园完美诠释花园酒店这个名称，还有酒店处处都有艺术插花和兰花盆栽装饰，很吸我这个鲜花控。
健身室器材很多，保养得也不错，不逊正规健身房了。桑拿房干湿都有，唯一的缺点是没有冰毛巾。露天游泳池挺大，遗憾的是冬天没有开放。
行政走廊服务不错，但是空间比较小，餐食比较少，跟文华比差得不是一星半点。下午茶时间有红酒，可以小酌红酒一杯。欢乐时间的餐点都是冷盘，建议可以增加一两款热汤食，例如云吞面或者牛腩粉这种有广州特色的粉面，即能让外宾尝试广州美食也能满足中国胃。
入住的是基本房间，空间比较小也能理解，没有浴缸。
生日有小布置，还送了好吃的山楂蛋糕，加分。
有个酒店博物馆可以参观，可以了解一下酒店发展史，不错。
老牌五星酒店，外宾比较多。', '["https://dimg04.c-ctrip.com/images/0233c12000d2btjcb34A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000d2bstwa2A82_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000d2bowki3948_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000d2bi3brED90_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000d2bu7gmD383_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000d2bnzrbA60E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000d2bh4qw3F78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000d2bhkbjB8DA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000d2bjfeg338F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-28', '花园双床房', '双床房', '家庭亲子', 318, 5.765191102784844, 0, 0.0, 5, 1.791759469228055, 9, '["公共设施", "餐饮设施", "整体满意度"]'::jsonb, '公共设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '后花园完美诠释花园酒店这个名称，还有酒店处处都有艺术插花和兰花盆栽装饰，很吸我这', '后花园完美诠释花园酒店这个名称，还有酒店处处都有艺术插花和兰花盆栽装饰，很吸我这个鲜花控。
健身室器材很多，保养得也不错，不逊正规健身房了。桑拿房干湿都有，唯一的缺点是没有冰毛巾。露天游泳池挺大，遗憾的是冬天没有开放。
行政走廊服务不错，但是空间比较小，餐食比较少，跟文华比差得不是一星半点。下午茶时间有红酒，可以小酌红酒一杯。欢乐时间的餐点都是冷盘，建议可以增加一两款热汤食，例如云吞面或者牛腩粉这种有广州特色的粉面，即能让外宾尝试广州美食也能满足中国胃。
入住的是基本房间，空间比较小也能理解，没有浴缸。
生日有小布置，还送了好吃的山楂蛋糕，加分。
有个酒店博物馆可以参观，可以了解一下酒店发展史，不错。
老牌五星酒店，外宾比较多。', '2024-01-28', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c0ee3c98b0941765a01', '不错，酒店干净，服务也挺好，停车免费。下次出玩还选这家。', '["https://dimg04.c-ctrip.com/images/0234p12000elmw6sh899A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000elmxxg760C2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-28', '花园双床房', '双床房', '家庭亲子', 28, 3.367295829986474, 0, 0.0, 7, 2.079441541679836, 5, '["卫生状况", "前台服务", "公共设施"]'::jsonb, '卫生状况', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '不错，酒店干净，服务也挺好，停车免费。下次出玩还选这家。', '不错，酒店干净，服务也挺好，停车免费。下次出玩还选这家。', '2024-06-28', 5, '卫生状况');
