INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c0ee3c98b0941765a03', '我们一家人选择在2024年的除夕之际，共赴广州花园酒店，开启了一段难忘的四天三夜之旅。酒店的环境、服务以及餐饮都让我们深感满意，让我们在南方的春节中，尽享了浓厚的年味。
广州花园酒店为我们提供了舒适的住宿环境，无论是房间的清洁度还是设施的完备性，都让我们倍感满意。在餐饮方面，酒店的年夜饭更是让人回味无穷，每一道菜品都充满了南方独特的年味，让我们一家人在除夕夜品尝到了家的味道。同时，酒店的卫生和服务也是无可挑剔的，让人感受到了一份温馨和关怀。
此次广州之旅，让我们充分领略了南方春节的独特魅力。酒店为我们呈现了一场别开生面的年味盛宴，让我们一家人在欢乐和温馨中度过了一个难忘的除夕之夜。
广州花园酒店无疑是一家高品质的酒店，无论是从硬件设施还是从服务细节上，都展现了其专业和贴心的水准。我们在此次旅行中收获了满满的愉快体验，我们愿意向更多的朋友推荐广州花园酒店，也期待未来再次来到这里。', '["https://dimg04.c-ctrip.com/images/0200x12000d6rynjnC3CE_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0232f12000d6rpim0170D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000d6rtu207DEA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000d6rvhf20080_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000d6rmz7n79B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000d6rm1fg6F2D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000d6rwcwm1BC8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000d6rhk91B994_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000d6rwsud7F52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000d6rbda38B5E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-12', '粤韵双床套房', '套房', '家庭亲子', 394, 5.978885764901122, 0, 0.0, 5, 1.791759469228055, 8, '["整体满意度", "餐饮设施", "房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '我们一家人选择在2024年的除夕之际，共赴广州花园酒店，开启了一段难忘的四天三夜', '我们一家人选择在2024年的除夕之际，共赴广州花园酒店，开启了一段难忘的四天三夜之旅。酒店的环境、服务以及餐饮都让我们深感满意，让我们在南方的春节中，尽享了浓厚的年味。
