INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c0ee3c98b0941765a07', '五星级酒店，满意服务', '["https://dimg04.c-ctrip.com/images/0233312000f4vsojv4827_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000f4vs3elBD3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000f4vtygn0142_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-15', '红棉双床套房', '套房', '商务出差', 10, 2.3978952727983707, 0, 0.0, 14, 2.70805020110221, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '五星级酒店，满意服务', '五星级酒店，满意服务', '2024-08-15', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c1ae3c98b0941765a08', '酒店位置很便利，离华桥村很近，出门就是地铁口。周边很多当地有名的餐厅，基本你能想到的都有。大厅前台工作人员很多，主动帮拿行李，主动帮叫电梯，还有很多外籍服务人员，很国际化的老牌五星酒店。我这间房早餐是在30层旋转餐厅用餐，360度无死角边赏美景边用餐。ps：早餐炒菜类调整一俩道中式热炒会更好！', '["https://dimg04.c-ctrip.com/images/0234o12000dacfajoF531_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000dacf5pyE05B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000dacghh445A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-25', '粤韵双床套房', '套房', '家庭亲子', 147, 4.997212273764115, 0, 0.0, 39, 3.688879454113936, 9, '["交通便利性", "周边配套", "餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店位置很便利，离华桥村很近，出门就是地铁口。周边很多当地有名的餐厅，基本你能想', '酒店位置很便利，离华桥村很近，出门就是地铁口。周边很多当地有名的餐厅，基本你能想到的都有。大厅前台工作人员很多，主动帮拿行李，主动帮叫电梯，还有很多外籍服务人员，很国际化的老牌五星酒店。我这间房早餐是在30层旋转餐厅用餐，360度无死角边赏美景边用餐。ps：早餐炒菜类调整一俩道中式热炒会更好！', '2024-02-25', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c1ae3c98b0941765a09', '冲着花园酒店去的，酒店花园名副其实，夜景也很漂亮，但酒店内有些陈旧，我们住的这间咖啡机也是坏的，有些失望。走的时候原本想参观酒店博物馆，谁知星期一闭馆，又是遗憾。', '["https://dimg04.c-ctrip.com/images/0236g12000dmzdkvlBAFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000dmzvduh4CE5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000dmzvjc0A43F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000dmzl9euDBFD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000dmzcxz17FBF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000dmzq8sw7CD9_R_150_150_R5_Q70_D.webp", "https://dimg04.c-ctrip.com/images/0231u12000dmzu9s1F119_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000dmzpf7e3D58_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000dmzq556EFC7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2024-04-10', '城央绿意大床房', '大床房', '情侣出游', 81, 4.406719247264253, 1, 0.6931471805599453, 15, 2.772588722239781, 7, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '冲着花园酒店去的，酒店花园名副其实，夜景也很漂亮，但酒店内有些陈旧，我们住的这间', '冲着花园酒店去的，酒店花园名副其实，夜景也很漂亮，但酒店内有些陈旧，我们住的这间咖啡机也是坏的，有些失望。走的时候原本想参观酒店博物馆，谁知星期一闭馆，又是遗憾。', '2024-04-10', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c1ae3c98b0941765a0a', '位置交通：位于环市东路淘金站上盖的花园酒店.公交地铁非常便利，酒店里也设有停车场，但私人车位居多。房间景观：有多种客房、套房可供选择：粤韵客房、花园客房、岭南套房等，丰俭由人。餐厅：有9间餐厅可供就餐，中西法日各式菜系，还有酒吧咖啡厅等不同休闲应酬场所，适合各种人士的需求。服务：酒店大堂服务非常认真细致，主动打招呼、帮推门拿行李，外语交流流利。餐厅服务员热气好客，随传随到，斟茶收盘及时。其他：户外有个几层楼高的景观瀑布，在瀑布餐厅就餐可以一览无余：后门出口有网球场：写字楼区1-3楼有日本驻广州总领馆。室内除了餐厅外，还有多家时装服饰和艺术品商铺，3楼有9间多功能会议室和1个国际会议中心，经常举办大型国际性商务会议；4楼还有花园酒店博物馆，扫码实名登记可以进馆参观，馆内收藏有酒店故事和发展变迁的珍贵照片藏品，丰富了花园酒店的内涵。
行政走廊的Kanchan,Cathy,Beryle,前台服务人员kasas,betty温和有礼，热情招待', '["https://dimg04.c-ctrip.com/images/0232r12000f6qbug5F26C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000f6qbt3pAD4D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000f6qa31gA328_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000f6qbyk09726_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231o12000f6qggbs8A71_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000f6q8q23505F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000f6pmp18330A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000f6qdlv47601_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000f6qc6zn96BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-20', '花园大床房', '大床房', '情侣出游', 422, 6.0473721790462776, 0, 0.0, 1, 0.6931471805599453, 10, '["交通便利性", "周边配套", "前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '位置交通：位于环市东路淘金站上盖的花园酒店.公交地铁非常便利，酒店里也设有停车场', '位置交通：位于环市东路淘金站上盖的花园酒店.公交地铁非常便利，酒店里也设有停车场，但私人车位居多。房间景观：有多种客房、套房可供选择：粤韵客房、花园客房、岭南套房等，丰俭由人。餐厅：有9间餐厅可供就餐，中西法日各式菜系，还有酒吧咖啡厅等不同休闲应酬场所，适合各种人士的需求。服务：酒店大堂服务非常认真细致，主动打招呼、帮推门拿行李，外语交流流利。餐厅服务员热气好客，随传随到，斟茶收盘及时。其他：户外有个几层楼高的景观瀑布，在瀑布餐厅就餐可以一览无余：后门出口有网球场：写字楼区1-3楼有日本驻广州总领馆。室内除了餐厅外，还有多家时装服饰和艺术品商铺，3楼有9间多功能会议室和1个国际会议中心，经常举办大型国际性商务会议；4楼还有花园酒店博物馆，扫码实名登记可以进馆参观，馆内收藏有酒店故事和发展变迁的珍贵照片藏品，丰富了花园酒店的内涵。
行政走廊的Kanchan,Cathy,Beryle,前台服务人员kasas,betty温和有礼，热情招待', '2024-08-20', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c1ae3c98b0941765a0b', '房间干净，安静，妈妈说枕头特别好睡，出行方便，周围好吃的店很多，宝宝每日的必备项目就是去小花园喂鱼，推荐入住', '["https://dimg04.c-ctrip.com/images/0232p12000du2be8iC0F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000du27zylE9FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000du2xvbz59E5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000du2iny55522_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-30', '花园大床房', '大床房', '家庭亲子', 54, 4.007333185232471, 0, 0.0, 7, 2.079441541679836, 7, '["卫生状况", "安静程度", "周边配套"]'::jsonb, '卫生状况', '安静程度', '周边配套', '未知酒店', '未知地点', '匿名', '房间干净，安静，妈妈说枕头特别好睡，出行方便，周围好吃的店很多，宝宝每日的必备项', '房间干净，安静，妈妈说枕头特别好睡，出行方便，周围好吃的店很多，宝宝每日的必备项目就是去小花园喂鱼，推荐入住', '2024-04-30', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c1ae3c98b0941765a0c', '槽点略多的酒店。
1. 携程上显示金卡可以升级房型，办理入住时表示要视当日房量而定，能理解，但我查看平台发现更高级的房型全都没有售空，希望前台再争取一下。前台女生走到旁边和另一个男生沟通，还没把我的诉求说完那个男生就立马说不行。当拒则拒，非常喜欢这种干脆果断的男生。
2. 房间明显有做翻修，但是翻修后的保养依然不太好。沙发套、办公椅等属于深度保洁的部分应该是没有常做的。浴缸有灰有毛发，日常保洁也欠佳。同时玻璃通透度太好了，不拉窗帘晚上恐有艳照门风险。
3. 外卖柜的位置令人感到匪夷所思。大堂设计本来就欠妥当，各种意义不明的隔断让人眼花缭乱，外卖柜更是设置在大堂深处角落。两个外卖柜不在一起不说，其中一个还设置在店铺里，标示牌也不明确。外卖员从正门进入酒店后要穿过整个大堂越过住客电梯厅才能到达外卖柜，所以大堂里乱哄哄的。这也是我第一次外卖送达取餐柜后被其他住客误取（这一点不完全是酒店责任，但也不能说完全和酒店无关。）
4. 外籍工作人员在入住期间打我手机求好评。相当不能理解，因为是外国人所以中文说得很艰难，考虑到他工作的辛苦我还是努力和他沟通希望听懂他的意思，但最后还是艰难地失败了，因为我听不懂他的名字。希望酒店可以让中外籍工作人员各管各的吧，是不愿意招中国人吗？
5. 花园瀑布挺漂亮的，但是晚上也开得太晚了，窗户隔音不好，明媚晴朗的夜晚听上去外面像在下暴雨。
整体看下来，酒店整体运营应该是遇到了一些问题，品控相当一般。
除去缺点以外，其他各方面表现（床品、个护用品、房间大小、地理位置等）也仅仅是尚可，和做得较好的连锁酒店是差不多的。表现最优秀的是餐饮，但是广州五星级酒店餐饮大多不差，甚至还有很出色的，故而也没有什么竞争力。', '["https://dimg04.c-ctrip.com/images/0230f12000d9ilv7fF4F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000d9itm2v2A42_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000d9j29511515_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000d9j1muh8B27_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2024-02-21', '花园大床房', '大床房', '独自旅行', 722, 6.583409222158765, 16, 2.833213344056216, 13, 2.6390573296152584, 9, '["客房服务", "安静程度", "整体满意度"]'::jsonb, '客房服务', '安静程度', '整体满意度', '未知酒店', '未知地点', '匿名', '槽点略多的酒店。', '槽点略多的酒店。
