INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c1ae3c98b0941765a11', '不愧为广州老牌高星级酒店，大气依旧，虽然智能化不一定跟得上现在的一些现代化未来酒店，但处处体现的人文让宾客感受暖心。尤其是酒店自带博物馆、私家花园，地理位置相当方便，门口就是地铁站，周边环东商区，游购娱吃喝玩乐都很近。隔壁就是一家点都德，对面还有一家广州酒家。总之住花园酒店令本次旅程增色加分不少。', '["https://dimg04.c-ctrip.com/images/0202j12000d8i2lodAF8A_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0230u12000d8hpaqfC1E3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000d8hln3l7442_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000d8i1k4895BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000d8i2k925ADE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000d8i1zkx271D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000d8ht1aj55CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000d8hw1n2A6A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000d8hs1nsBA6E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000d8hx57d565A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-18', '城央绿意大床房', '大床房', '家庭亲子', 149, 5.010635294096256, 0, 0.0, 6, 1.9459101490553128, 9, '["周边配套", "交通便利性", "整体满意度"]'::jsonb, '周边配套', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '不愧为广州老牌高星级酒店，大气依旧，虽然智能化不一定跟得上现在的一些现代化未来酒', '不愧为广州老牌高星级酒店，大气依旧，虽然智能化不一定跟得上现在的一些现代化未来酒店，但处处体现的人文让宾客感受暖心。尤其是酒店自带博物馆、私家花园，地理位置相当方便，门口就是地铁站，周边环东商区，游购娱吃喝玩乐都很近。隔壁就是一家点都德，对面还有一家广州酒家。总之住花园酒店令本次旅程增色加分不少。', '2024-02-18', 5, '周边配套');
