INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c25e3c98b0941765a14', '久负盛名的花园酒店，盛名之下其实难副。一流的环境，二流的设施，三流的餐品。酒店占据广州核心区位，后花园是最大亮点。作为中国为数不多的白金五星，办理入住居然要15分钟，完全缺少宾至如归的感觉，减分；客房比较干净，布局和配置也相对合理、精细，但是设施太老旧，白金五星居然不配智能马桶，减分；早餐种类乏善可陈，口味一般，由于场地局促，高峰时间吃饭等位严重，11点的早餐截止时间，10点30就撤摊，岂是待客之道，减分。
建议亲子度假游客，可选不含早的套餐，避免踩坑。', '["https://dimg04.c-ctrip.com/images/0233r12000d6rnal35FA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000d6ro08z6D13_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000d6rrualA8A5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000d6rqncm62F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000d6rp5km2EC8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000d6rq2ol861A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000d6rp0x780C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000d6rp7ngEE3B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000d6rouuvB151_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-02-12', '花园大床房', '大床房', '家庭亲子', 229, 5.438079308923196, 1, 0.6931471805599453, 9, 2.302585092994046, 9, '["房间设施", "餐饮设施", "退房/入住效率"]'::jsonb, '房间设施', '餐饮设施', '退房/入住效率', '未知酒店', '未知地点', '匿名', '久负盛名的花园酒店，盛名之下其实难副。一流的环境，二流的设施，三流的餐品。酒店占', '久负盛名的花园酒店，盛名之下其实难副。一流的环境，二流的设施，三流的餐品。酒店占据广州核心区位，后花园是最大亮点。作为中国为数不多的白金五星，办理入住居然要15分钟，完全缺少宾至如归的感觉，减分；客房比较干净，布局和配置也相对合理、精细，但是设施太老旧，白金五星居然不配智能马桶，减分；早餐种类乏善可陈，口味一般，由于场地局促，高峰时间吃饭等位严重，11点的早餐截止时间，10点30就撤摊，岂是待客之道，减分。
建议亲子度假游客，可选不含早的套餐，避免踩坑。', '2024-02-12', 3, '房间设施');
