服务：服务一般，金卡会员不能升级房型。并且可能是因为人多，让我们先去逛再来办理入住，说到时候收拾出来会给我们发短信，等了一个半小时也没有收到短信，最后去了前台说有房可以入住了，属实有点耽误时间
早餐：早餐我们在旋转餐厅吃的，环境很好，吃的也中规中矩', '2024-02-16', 4, '退房/入住效率');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c25e3c98b0941765a17', '之前几年每次来广州出差都住花园，开会睡觉两点一线倒也没留下什么印象，这一次携老小来广州过年；顺手订了熟悉的花园，没想到意外惊喜，成为此行最满意的一个决定：花园酒店竟然有个大！花！园！来了这么多次都没注意过，瀑布小桥流水锦鲤，草坪鲜花，妥妥一个精致的城市园林，还不用人挤人，两娃每天都去花园里玩耍放电；来的当天是初五，大堂摆着年味集市，工作人员发金币巧克力和糖果，高跷财神合影，充满了浓浓的年味；服务也是120分，每层的电梯间都站了一位员工，迎来送往问好祝贺，亲切有礼举止专业；最最过意不去是小朋友突发肠胃炎，弄脏了床单，凌晨四点一个电话立刻来换被子和床褥，全程安慰也没有收清洁费；第二天半夜又弄脏了…依旧火速赶到换床品，住了两晚基本都在照顾小朋友生病中度过，是花园员工的温暖让我们的熬夜照料变得不那么痛苦，真的非常感动～以后来广州一定认准花园！', '["https://dimg04.c-ctrip.com/images/0232312000d8bivk1D947_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000d8bh4a01407_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000d8bgpu9F9C2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-17', '花园大床房', '大床房', '家庭亲子', 372, 5.921578419643816, 1, 0.6931471805599453, 10, 2.3978952727983707, 10, '["客房服务", "整体满意度", "公共设施"]'::jsonb, '客房服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '之前几年每次来广州出差都住花园，开会睡觉两点一线倒也没留下什么印象，这一次携老小', '之前几年每次来广州出差都住花园，开会睡觉两点一线倒也没留下什么印象，这一次携老小来广州过年；顺手订了熟悉的花园，没想到意外惊喜，成为此行最满意的一个决定：花园酒店竟然有个大！花！园！来了这么多次都没注意过，瀑布小桥流水锦鲤，草坪鲜花，妥妥一个精致的城市园林，还不用人挤人，两娃每天都去花园里玩耍放电；来的当天是初五，大堂摆着年味集市，工作人员发金币巧克力和糖果，高跷财神合影，充满了浓浓的年味；服务也是120分，每层的电梯间都站了一位员工，迎来送往问好祝贺，亲切有礼举止专业；最最过意不去是小朋友突发肠胃炎，弄脏了床单，凌晨四点一个电话立刻来换被子和床褥，全程安慰也没有收清洁费；第二天半夜又弄脏了…依旧火速赶到换床品，住了两晚基本都在照顾小朋友生病中度过，是花园员工的温暖让我们的熬夜照料变得不那么痛苦，真的非常感动～以后来广州一定认准花园！', '2024-02-17', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c25e3c98b0941765a18', '非常nice 的酒店，还会再光临。', '["https://dimg04.c-ctrip.com/images/0232g12000eosx9lw8C5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-05', '红棉双床套房', '套房', '其他', 17, 2.8903717578961645, 0, 0.0, 4, 1.6094379124341005, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '非常nice 的酒店，还会再光临。', '非常nice 的酒店，还会再光临。', '2024-07-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c25e3c98b0941765a19', '按照约定2点check in时说没有空房要等待，没有任何主动的补偿措施。和前台说不要尾房，结果还是给开了一间尾房，重新排队一个小时等待换房间。房间隔音很差，旁边房间的小孩吵闹都能听到，投诉多次无果，下次不会再考虑花园酒店。', '["https://dimg04.c-ctrip.com/images/0230y12000dacj0eyFF07_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000dacj56z0B4A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000dacik2t2226_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.5, 1, '2024-02-25', '城央绿意大床房', '大床房', '其他', 111, 4.718498871295094, 5, 1.791759469228055, 7, 2.079441541679836, 8, '["退房/入住效率", "前台服务", "安静程度"]'::jsonb, '退房/入住效率', '前台服务', '安静程度', '未知酒店', '未知地点', '匿名', '按照约定2点check in时说没有空房要等待，没有任何主动的补偿措施。和前台说', '按照约定2点check in时说没有空房要等待，没有任何主动的补偿措施。和前台说不要尾房，结果还是给开了一间尾房，重新排队一个小时等待换房间。房间隔音很差，旁边房间的小孩吵闹都能听到，投诉多次无果，下次不会再考虑花园酒店。', '2024-02-25', 1, '退房/入住效率');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c25e3c98b0941765a1a', '热闹非凡的大堂，春节活动很多，人也很多，但丝毫没感觉到乱，反而很有氛围，电梯门厅和客房楼层电梯口都有迎宾接待服务，还热情地帮我们订楼下米其林餐厅的位子，从大门口开车门的服务员开始就一路给人如沐春风的感觉。
酒店地理位置很好，本身有一个小花园，有瀑布景观，对面是友谊商店，里面有广州酒家，酒店边上是点都德，去景区打车也都20分钟左右就可以。
尤其赞的是酒店里面就有三家米其林，不出酒店就可以吃到地道地美食。', '["https://dimg04.c-ctrip.com/images/0234b12000d7oly1mC307_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000d7oliahB59F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000d7okpud4004_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000d7oly1sBE87_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-15', '红棉大床套房', '套房', '其他', 202, 5.313205979041787, 0, 0.0, 12, 2.5649493574615367, 9, '["前台服务", "周边配套", "餐饮设施"]'::jsonb, '前台服务', '周边配套', '餐饮设施', '未知酒店', '未知地点', '匿名', '热闹非凡的大堂，春节活动很多，人也很多，但丝毫没感觉到乱，反而很有氛围，电梯门厅', '热闹非凡的大堂，春节活动很多，人也很多，但丝毫没感觉到乱，反而很有氛围，电梯门厅和客房楼层电梯口都有迎宾接待服务，还热情地帮我们订楼下米其林餐厅的位子，从大门口开车门的服务员开始就一路给人如沐春风的感觉。
酒店地理位置很好，本身有一个小花园，有瀑布景观，对面是友谊商店，里面有广州酒家，酒店边上是点都德，去景区打车也都20分钟左右就可以。
尤其赞的是酒店里面就有三家米其林，不出酒店就可以吃到地道地美食。', '2024-02-15', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c25e3c98b0941765a1b', '说真心话没想到过年期间酒店这么火爆，但还是要为酒店点赞??，一流的服务，房间虽小，但设施齐全，床垫不错??酒店的服务态度都很好??。酒店的经典设计风格很独特，最关键的是出行方便，地铁就在旁边。来广州玩了两天，便捷的交通，舒适的入住体验还是不错滴', '["https://dimg04.c-ctrip.com/images/0230b12000d89z21oB67E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000d89yyujD0CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000d89yw406D2A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-17', '花园双床房', '双床房', '朋友出游', 122, 4.812184355372417, 0, 0.0, 17, 2.8903717578961645, 7, '["交通便利性", "整体满意度", "房间设施"]'::jsonb, '交通便利性', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '说真心话没想到过年期间酒店这么火爆，但还是要为酒店点赞??，一流的服务，房间虽小', '说真心话没想到过年期间酒店这么火爆，但还是要为酒店点赞??，一流的服务，房间虽小，但设施齐全，床垫不错??酒店的服务态度都很好??。酒店的经典设计风格很独特，最关键的是出行方便，地铁就在旁边。来广州玩了两天，便捷的交通，舒适的入住体验还是不错滴', '2024-02-17', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a1c', '宾至如归，花园漂亮！老牌服务，大气！整个酒店虽然有一些年头了，但都做了整体的装饰新老结合中西合璧，颇有岭南地区的艺术美感。瀑布餐厅也是一大特色，孩子们还可以去花园喂鱼。如果有机会还会再次入住。', '["https://dimg04.c-ctrip.com/images/0232m12000d94x8y2716E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000d94znguE6E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000d95ae71A1F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000d952pmm98E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000d95cr3vF30F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000d952eq655EC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 96, 4.574710978503383, 0, 0.0, 29, 3.4011973816621555, 8, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '宾至如归，花园漂亮！老牌服务，大气！整个酒店虽然有一些年头了，但都做了整体的装饰', '宾至如归，花园漂亮！老牌服务，大气！整个酒店虽然有一些年头了，但都做了整体的装饰新老结合中西合璧，颇有岭南地区的艺术美感。瀑布餐厅也是一大特色，孩子们还可以去花园喂鱼。如果有机会还会再次入住。', '2024-02-20', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a1d', '酒店位于老城区，老牌酒店，服务不错！过年气氛好，酒店里面饭店也多，各种价位都有！选了桃园高端粤菜！菜品没话说，就是价格真的好贵！唯一不足，酒店卫生间设施老旧了点，淋浴房是浴缸，爬进爬出的，而且卫生间是敞开式！不太方便！隐私不够！', '["https://dimg04.c-ctrip.com/images/0234q12000d7x7ry44B47_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000d7x9yty8FAB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000d7xcbhxFA16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000d7xjq39EED6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-16', '花园双床房', '双床房', '家庭亲子', 114, 4.74493212836325, 0, 0.0, 8, 2.19722457733622, 8, '["房间设施", "餐饮设施", "价格合理性"]'::jsonb, '房间设施', '餐饮设施', '价格合理性', '未知酒店', '未知地点', '匿名', '酒店位于老城区，老牌酒店，服务不错！过年气氛好，酒店里面饭店也多，各种价位都有！', '酒店位于老城区，老牌酒店，服务不错！过年气氛好，酒店里面饭店也多，各种价位都有！选了桃园高端粤菜！菜品没话说，就是价格真的好贵！唯一不足，酒店卫生间设施老旧了点，淋浴房是浴缸，爬进爬出的，而且卫生间是敞开式！不太方便！隐私不够！', '2024-02-16', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a1e', '好不容易出差这次可以住上了。之前来因为到别的区去一直没住上。酒店大堂香味怡人，服务人员主动帮忙，热心。环境优雅，设施高级，卫生一直都很好。非常推荐', '["https://dimg04.c-ctrip.com/images/0235x12000dibtxtg9F31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000dibv7k9112D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000dibvcmv9B84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000dibbainA15F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000dibghl97048_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-26', '花园大床房', '大床房', '商务出差', 73, 4.30406509320417, 0, 0.0, 41, 3.737669618283368, 7, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '好不容易出差这次可以住上了。之前来因为到别的区去一直没住上。酒店大堂香味怡人，服', '好不容易出差这次可以住上了。之前来因为到别的区去一直没住上。酒店大堂香味怡人，服务人员主动帮忙，热心。环境优雅，设施高级，卫生一直都很好。非常推荐', '2024-03-26', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a1f', '这个酒店超棒！首先 ，出了地铁口就到，对老人家来说很友好。酒店大堂的所有工作人员都态度非常非常亲切面带微笑。办理入住很顺利，看我们小孩是初中生，主动提出免费升了套房加了单人床，让我们在广州的3晚睡了舒服级了，并赠送了三套宝格丽的洗护用品套装！度过了美好的假期??', '["https://dimg04.c-ctrip.com/images/0235z12000d72nam31696_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000d72pvdy6B67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000d72n2n82114_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000d72dec44DFD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000d72g5qmA1E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000d722szfB70F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000d726abp72D5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000d72o31s902B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000d72q82qBB82_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-13', '城央绿意双床房', '双床房', '家庭亲子', 131, 4.882801922586371, 0, 0.0, 9, 2.302585092994046, 9, '["前台服务", "交通便利性", "整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '这个酒店超棒！首先 ，出了地铁口就到，对老人家来说很友好。酒店大堂的所有工作人员', '这个酒店超棒！首先 ，出了地铁口就到，对老人家来说很友好。酒店大堂的所有工作人员都态度非常非常亲切面带微笑。办理入住很顺利，看我们小孩是初中生，主动提出免费升了套房加了单人床，让我们在广州的3晚睡了舒服级了，并赠送了三套宝格丽的洗护用品套装！度过了美好的假期??', '2024-02-13', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a20', '非常喜欢！酒店有后花园，池子里有很多鱼，小朋友专门买了面包来喂鱼（鱼好肥），有漂亮的瀑布，还有一个博物馆。我们一家四口，原本订的是双床房，前台小哥哥给免费升级成了粤韵大床房，然后加了一个床，房间很大，浴缸泡澡也很舒服，服务非常好也很贴心，总之就是超赞的一次入住体验！', '["https://dimg04.c-ctrip.com/images/0231912000d8sm2odB556_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000d8shgdm4EEE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000d8skrhhEBD0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000d8saneiC3A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000d8slpor60A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000d8si5au4BD9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-19', '花园双床房', '双床房', '家庭亲子', 133, 4.897839799950911, 0, 0.0, 6, 1.9459101490553128, 9, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '非常喜欢！酒店有后花园，池子里有很多鱼，小朋友专门买了面包来喂鱼（鱼好肥），有漂', '非常喜欢！酒店有后花园，池子里有很多鱼，小朋友专门买了面包来喂鱼（鱼好肥），有漂亮的瀑布，还有一个博物馆。我们一家四口，原本订的是双床房，前台小哥哥给免费升级成了粤韵大床房，然后加了一个床，房间很大，浴缸泡澡也很舒服，服务非常好也很贴心，总之就是超赞的一次入住体验！', '2024-02-19', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a21', '订的红棉房套餐，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵吧，给的几间都是粤韵；房间很大，设施新，卫生、服务、环境都很好，早餐在瀑布餐厅也不错，4楼还有个博物馆，入住外国人多。餐饮券能在酒吧用。套餐超值。', '["https://dimg04.c-ctrip.com/images/0235m12000d2ds5r3A046_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000d2drvo74719_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000d2dv38n3F6D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000d2dsnn941A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000d2dtl3qE8F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000d2e12tdA3C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000d2e1t867CBC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000d2dqc7sA4F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000d2e12tj4D69_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-28', '红棉大床套房', '套房', '家庭亲子', 111, 4.718498871295094, 1, 0.6931471805599453, 36, 3.610917912644224, 8, '["性价比", "房间设施", "餐饮设施"]'::jsonb, '性价比', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '订的红棉房套餐，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵吧，', '订的红棉房套餐，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵吧，给的几间都是粤韵；房间很大，设施新，卫生、服务、环境都很好，早餐在瀑布餐厅也不错，4楼还有个博物馆，入住外国人多。餐饮券能在酒吧用。套餐超值。', '2024-01-28', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a22', '闹市中的公园酒店，虽然有些老旧，但是维护的很好，服务也好，过年期间酒店大堂布置的霸气奢华，活动也丰富，但是第一次来广州，光忙着在外面玩了，只最后一天吃完早餐才在酒店转了转，玩的太少，下次还会选择', '["https://dimg04.c-ctrip.com/images/0236u12000dzc9zfo2BA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000dzcbu57B071_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000dzcacx1FB70_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-13', '红棉大床套房', '套房', '家庭亲子', 97, 4.584967478670572, 0, 0.0, 9, 2.302585092994046, 7, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '闹市中的公园酒店，虽然有些老旧，但是维护的很好，服务也好，过年期间酒店大堂布置的', '闹市中的公园酒店，虽然有些老旧，但是维护的很好，服务也好，过年期间酒店大堂布置的霸气奢华，活动也丰富，但是第一次来广州，光忙着在外面玩了，只最后一天吃完早餐才在酒店转了转，玩的太少，下次还会选择', '2024-05-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a23', '酒店自带花园相当不错，瀑布流水锦鲤，非常适合小孩和老人。地理位置也很好。虽然是春节但服务人员很充足并且态度都很好走到哪里都主动打招呼。房间电视有很多海外频道。缺点是房间硬件落后了。插座少特别是床头充电很不方便。空调温度打不上去有点冷，关了反而好点。另外床太软腰不好慎选。', '["https://dimg04.c-ctrip.com/images/0233m12000d6t4otrDBB1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000d6t6gkd0492_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000d6sapu41DBB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000d6t2kl59E0F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-02-12', '红棉大床套房', '套房', '家庭亲子', 135, 4.912654885736052, 0, 0.0, 3, 1.3862943611198906, 9, '["房间设施", "整体满意度", "前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '酒店自带花园相当不错，瀑布流水锦鲤，非常适合小孩和老人。地理位置也很好。虽然是春', '酒店自带花园相当不错，瀑布流水锦鲤，非常适合小孩和老人。地理位置也很好。虽然是春节但服务人员很充足并且态度都很好走到哪里都主动打招呼。房间电视有很多海外频道。缺点是房间硬件落后了。插座少特别是床头充电很不方便。空调温度打不上去有点冷，关了反而好点。另外床太软腰不好慎选。', '2024-02-12', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a24', '新年气氛杠杠的，一进门被大堂喜庆的装饰惊艳到了。房间整洁舒适，好评！酒店考虑到春节入住人较多，开了两个自助早餐的餐厅分流客人，很是贴心。每个工作人员都是微笑的跟你说新年好，很是温馨！来广州住花园，没选错！', '["https://dimg04.c-ctrip.com/images/0230512000d6pyj4374E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000d6pyexh80C5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-12', '城央绿意双床房', '双床房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '新年气氛杠杠的，一进门被大堂喜庆的装饰惊艳到了。房间整洁舒适，好评！酒店考虑到春', '新年气氛杠杠的，一进门被大堂喜庆的装饰惊艳到了。房间整洁舒适，好评！酒店考虑到春节入住人较多，开了两个自助早餐的餐厅分流客人，很是贴心。每个工作人员都是微笑的跟你说新年好，很是温馨！来广州住花园，没选错！', '2024-02-12', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c34e3c98b0941765a25', '酒店非常漂亮，布置充满了年味，年三十入住给人的第一感觉非常好。年初一上午酒店有舞狮活动，第一次近距离接触，非常棒。酒店每个工作人员热情，礼貌，主动打招呼，不愧是老牌五星级酒店。在酒店内有不少可以打卡的地方，有着浓厚的文化氛围！', '["https://dimg04.c-ctrip.com/images/0202512000d73hi5oC08B_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0234v12000d73gu4wD24A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000d72r82vBF9C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-13', '红棉大床套房', '套房', '情侣出游', 113, 4.736198448394496, 0, 0.0, 31, 3.4657359027997265, 8, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '酒店非常漂亮，布置充满了年味，年三十入住给人的第一感觉非常好。年初一上午酒店有舞', '酒店非常漂亮，布置充满了年味，年三十入住给人的第一感觉非常好。年初一上午酒店有舞狮活动，第一次近距离接触，非常棒。酒店每个工作人员热情，礼貌，主动打招呼，不愧是老牌五星级酒店。在酒店内有不少可以打卡的地方，有着浓厚的文化氛围！', '2024-02-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c40e3c98b0941765a26', '过年期间酒店住客多，入住排了长队，是我去过的所有酒店里办理入住时间最长的一家。我定的红棉大床房，下午3点办理入住时前台小哥说需要等一个多小时，可以帮我调剂到旁边楼的公寓房，有两个房间，当时我答应了。结果进去一感受，房间非常的旧，90年代装修那种感觉，旁边是长租的那种住客，环境像住居民楼，我受不了要求换到我原订的房间，告诉我还得等打扫完，于是除夕夜等到晚上快10点，终于入住了自己原先定的房间，房间装修比较新，空间也挺大的，就是没房调剂这点操作太让人迷惑了，人家总是往高了调吧，哪有他们这种往差了给我调的，幸亏坚持换回来了，不然真的得难受过年了。酒店服务员态度都挺好的，后花园的环境也很好，早餐种类也还可以，过年的氛围布置都挺用心的。', '["https://dimg04.c-ctrip.com/images/0232b12000d6wrlhr003E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000d6wrx7d7D05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000d6ws5uq8CF8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-13', '红棉大床套房', '套房', '家庭亲子', 317, 5.762051382780177, 0, 0.0, 2, 1.0986122886681098, 9, '["退房/入住效率", "前台服务", "整体满意度"]'::jsonb, '退房/入住效率', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '过年期间酒店住客多，入住排了长队，是我去过的所有酒店里办理入住时间最长的一家。我', '过年期间酒店住客多，入住排了长队，是我去过的所有酒店里办理入住时间最长的一家。我定的红棉大床房，下午3点办理入住时前台小哥说需要等一个多小时，可以帮我调剂到旁边楼的公寓房，有两个房间，当时我答应了。结果进去一感受，房间非常的旧，90年代装修那种感觉，旁边是长租的那种住客，环境像住居民楼，我受不了要求换到我原订的房间，告诉我还得等打扫完，于是除夕夜等到晚上快10点，终于入住了自己原先定的房间，房间装修比较新，空间也挺大的，就是没房调剂这点操作太让人迷惑了，人家总是往高了调吧，哪有他们这种往差了给我调的，幸亏坚持换回来了，不然真的得难受过年了。酒店服务员态度都挺好的，后花园的环境也很好，早餐种类也还可以，过年的氛围布置都挺用心的。', '2024-02-13', 5, '退房/入住效率');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c40e3c98b0941765a27', '带家人过年，谢谢办理入住的工作人员帮我免费升级了套房，不愧是花园酒店，套房体验好，工作人员热情负责，年味浓。晚上订了团年宴，因为坐在喇叭附近音响太大，跟服务员说了后，很快音量调小了，谢谢那位小姐姐负责有效率。团年宴菜量有些多，后面还有几道菜没上我们就饱了，提前走了。早餐丰盛环境好。', '["https://dimg04.c-ctrip.com/images/0231r12000d66eckq46E3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000d66nloo54B7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000d66nc5l55B4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000d66hp7cC4BB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000d669vagC2C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000d65xdfp9B46_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-10', '红棉双床套房', '套房', '其他', 141, 4.955827057601261, 0, 0.0, 29, 3.4011973816621555, 8, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '带家人过年，谢谢办理入住的工作人员帮我免费升级了套房，不愧是花园酒店，套房体验好', '带家人过年，谢谢办理入住的工作人员帮我免费升级了套房，不愧是花园酒店，套房体验好，工作人员热情负责，年味浓。晚上订了团年宴，因为坐在喇叭附近音响太大，跟服务员说了后，很快音量调小了，谢谢那位小姐姐负责有效率。团年宴菜量有些多，后面还有几道菜没上我们就饱了，提前走了。早餐丰盛环境好。', '2024-02-10', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c40e3c98b0941765a28', '总体品质服务不错，房间设施比较老但是保养还可以，公区旋转餐厅、后花园能看出上世纪最高端5星级酒店的风格，也是个独特的体验。大年三十酒店有很多特色活动非常有氛围，还赠送了几只康乃馨。这个酒店感觉外国客人挺多，还有外籍工作人员。建议：房间增加空气清新或香氛。', '["https://dimg04.c-ctrip.com/images/0236c12000d7q64wk20CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000d7q8fijDE33_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000d7pv9gb5BA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-02-15', '花园大床房', '大床房', '情侣出游', 127, 4.852030263919617, 0, 0.0, 9, 2.302585092994046, 8, '["房间设施", "整体满意度", "餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '总体品质服务不错，房间设施比较老但是保养还可以，公区旋转餐厅、后花园能看出上世纪', '总体品质服务不错，房间设施比较老但是保养还可以，公区旋转餐厅、后花园能看出上世纪最高端5星级酒店的风格，也是个独特的体验。大年三十酒店有很多特色活动非常有氛围，还赠送了几只康乃馨。这个酒店感觉外国客人挺多，还有外籍工作人员。建议：房间增加空气清新或香氛。', '2024-02-15', 4, '房间设施');
