INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c40e3c98b0941765a2a', '服务很周到，门童会主动打招呼并帮忙拿行李，去客房电梯口也有工作人员指引，checkin柜台小姐姐Viria很热情且耐心。酒店环境不错，后面有个小花园，唯一欠缺是房间设施有些旧了，卫生间通风换气不佳。', '["https://dimg04.c-ctrip.com/images/0232z12000d9gf3sb94C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000d9gej8762E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000d9gebu48428_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-21', '红棉大床套房', '套房', '家庭亲子', 99, 4.605170185988092, 0, 0.0, 5, 1.791759469228055, 8, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '服务很周到，门童会主动打招呼并帮忙拿行李，去客房电梯口也有工作人员指引，chec', '服务很周到，门童会主动打招呼并帮忙拿行李，去客房电梯口也有工作人员指引，checkin柜台小姐姐Viria很热情且耐心。酒店环境不错，后面有个小花园，唯一欠缺是房间设施有些旧了，卫生间通风换气不佳。', '2024-02-21', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c40e3c98b0941765a2b', '有史以来入住等待时间最久的一家酒店，大堂人员嘈杂，乱哄哄的，体验极差，前台服务人员一点不急，在那里慢吞吞的。客房装修老旧，堪比快捷酒店。水龙头设计不合理，一打开水溅的台面上一塌糊涂。淋浴和马桶共用一扇门，关上淋浴，用马桶的就没有门了，敞开着上厕所。奇葩省钱装修。淋浴间瓷砖破损，茶几磨损严重，还在坚持给客人使用。完全与五星不搭。这个酒店真是金玉其外……。', '["https://dimg04.c-ctrip.com/images/0230s12000d6pfgw9F0B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000d6pgw4fD345_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2024-02-12', '花园双床房', '双床房', '其他', 177, 5.181783550292085, 2, 1.0986122886681098, 7, 2.079441541679836, 9, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '有史以来入住等待时间最久的一家酒店，大堂人员嘈杂，乱哄哄的，体验极差，前台服务人', '有史以来入住等待时间最久的一家酒店，大堂人员嘈杂，乱哄哄的，体验极差，前台服务人员一点不急，在那里慢吞吞的。客房装修老旧，堪比快捷酒店。水龙头设计不合理，一打开水溅的台面上一塌糊涂。淋浴和马桶共用一扇门，关上淋浴，用马桶的就没有门了，敞开着上厕所。奇葩省钱装修。淋浴间瓷砖破损，茶几磨损严重，还在坚持给客人使用。完全与五星不搭。这个酒店真是金玉其外……。', '2024-02-12', 2, '前台服务');
