INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c40e3c98b0941765a2d', '花园酒店除了地理位置优越，服务几十年来没有任何降低，酒店的房间干净大气，充分体现国际酒店的水平。酒店的各类服务人员，态度和素质非常高，超越很多新的酒店。广州酒店，首选花园酒店是绝对不会错的', '["https://dimg04.c-ctrip.com/images/0232a12000d8adntt392A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-17', '城央绿意大床房', '大床房', '家庭亲子', 94, 4.553876891600541, 0, 0.0, 28, 3.367295829986474, 8, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '花园酒店除了地理位置优越，服务几十年来没有任何降低，酒店的房间干净大气，充分体现', '花园酒店除了地理位置优越，服务几十年来没有任何降低，酒店的房间干净大气，充分体现国际酒店的水平。酒店的各类服务人员，态度和素质非常高，超越很多新的酒店。广州酒店，首选花园酒店是绝对不会错的', '2024-02-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c40e3c98b0941765a2e', '入住环境真的是很好，酒店自带一个那么大花园很惊叹了。而且春节期间，过年气氛搞得特别浓，特别喜庆热闹，感觉随时有节目随时有惊喜，孩子遇到好几次财神高兴的不得了，几块金币巧克力带来的欢乐??愉快了整个旅程。服务也很好，热情又主动，前台接待、大堂经理、餐厅工作人员都很积极。整体入住体验很满意。', '["https://dimg04.c-ctrip.com/images/0235w12000d98wbus72E3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000d98w5ozAA02_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000d98vz9m4163_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000d98wbv0E917_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-20', '红棉大床套房', '套房', '家庭亲子', 144, 4.976733742420574, 0, 0.0, 9, 2.302585092994046, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '入住环境真的是很好，酒店自带一个那么大花园很惊叹了。而且春节期间，过年气氛搞得特', '入住环境真的是很好，酒店自带一个那么大花园很惊叹了。而且春节期间，过年气氛搞得特别浓，特别喜庆热闹，感觉随时有节目随时有惊喜，孩子遇到好几次财神高兴的不得了，几块金币巧克力带来的欢乐??愉快了整个旅程。服务也很好，热情又主动，前台接待、大堂经理、餐厅工作人员都很积极。整体入住体验很满意。', '2024-02-20', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c40e3c98b0941765a2f', '第2次入住花园，地理位置好，离北京路很近，办理入住可以再便捷快一点，房间干净，床垫偏软，早餐在一楼，地方不大，有安排座位，餐品一般，种类不多，参观了花园博物馆，里面陈列的是以花园酒店为主的广州酒店发展史。总体感觉一般。', '["https://dimg04.c-ctrip.com/images/0233012000d7ma3gqA78B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235v12000d7ma54l8432_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-02-15', '花园双床房', '双床房', '朋友出游', 109, 4.700480365792417, 0, 0.0, 4, 1.6094379124341005, 7, '["周边配套", "退房/入住效率", "卫生状况"]'::jsonb, '周边配套', '退房/入住效率', '卫生状况', '未知酒店', '未知地点', '匿名', '第2次入住花园，地理位置好，离北京路很近，办理入住可以再便捷快一点，房间干净，床', '第2次入住花园，地理位置好，离北京路很近，办理入住可以再便捷快一点，房间干净，床垫偏软，早餐在一楼，地方不大，有安排座位，餐品一般，种类不多，参观了花园博物馆，里面陈列的是以花园酒店为主的广州酒店发展史。总体感觉一般。', '2024-02-15', 4, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c4be3c98b0941765a30', '房间总体保养不错，就是淋浴下水有些不畅，可能是时代有些久远。酒店内瀑布花园，顶层 360旋宫餐厅是酒店亮点，住酒店有空值得一去。旋宫可以俯视全城美景，瀑布花园小而精致，很有岭南风味，点赞！', '["https://dimg04.c-ctrip.com/images/0230h12000d7o92ef14C0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000d7o9dyw1A84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000d7o0qglD729_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000d7nzoe80DD7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-15', '城央绿意双床房', '双床房', '家庭亲子', 94, 4.553876891600541, 0, 0.0, 4, 1.6094379124341005, 8, '["房间设施", "公共设施", "景观/朝向"]'::jsonb, '房间设施', '公共设施', '景观/朝向', '未知酒店', '未知地点', '匿名', '房间总体保养不错，就是淋浴下水有些不畅，可能是时代有些久远。酒店内瀑布花园，顶层', '房间总体保养不错，就是淋浴下水有些不畅，可能是时代有些久远。酒店内瀑布花园，顶层 360旋宫餐厅是酒店亮点，住酒店有空值得一去。旋宫可以俯视全城美景，瀑布花园小而精致，很有岭南风味，点赞！', '2024-02-15', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c4be3c98b0941765a31', '每次来广州都喜欢住花园酒店，酒店服务始终保持着传统的管家式的贴心，行李房，楼层管理，房间整理，都一如既往地规范有礼，路上员工也会主动跟客人打招呼，而且酒店大堂的布置总是那么富有岭南特色。', '["https://dimg04.c-ctrip.com/images/0232e12000d9bhs19EBCF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000d9bhe0cB10A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-21', '花园大床房', '大床房', '独自旅行', 93, 4.543294782270004, 0, 0.0, 14, 2.70805020110221, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '每次来广州都喜欢住花园酒店，酒店服务始终保持着传统的管家式的贴心，行李房，楼层管', '每次来广州都喜欢住花园酒店，酒店服务始终保持着传统的管家式的贴心，行李房，楼层管理，房间整理，都一如既往地规范有礼，路上员工也会主动跟客人打招呼，而且酒店大堂的布置总是那么富有岭南特色。', '2024-02-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c4be3c98b0941765a32', '酒店环境很好，瀑布餐厅很美，服务很好，办理入住送了鲜花，房间整体不错，有迎宾水果，过生日还送了蛋糕，服务员Amy写的小卡片很贴心，很不错的入住体验，下次来广州还会考虑住花园酒店！', '["https://dimg04.c-ctrip.com/images/0234i12000h4pbgag2A1A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000h4p4yb18FD3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-10', '花园双床房', '双床房', '朋友出游', 89, 4.499809670330265, 0, 0.0, 1, 0.6931471805599453, 8, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '酒店环境很好，瀑布餐厅很美，服务很好，办理入住送了鲜花，房间整体不错，有迎宾水果', '酒店环境很好，瀑布餐厅很美，服务很好，办理入住送了鲜花，房间整体不错，有迎宾水果，过生日还送了蛋糕，服务员Amy写的小卡片很贴心，很不错的入住体验，下次来广州还会考虑住花园酒店！', '2024-12-10', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c4be3c98b0941765a33', '作为老广，花园酒店一直都是属于高档酒店的存在，没想到入住大失所望，房间设施陈旧就不说了，浴室卫生简直以灾难级形容，大理石裂的，洗脸盆和淋浴间的霉菌简直吓人，很难想象跟星级扯上关系', '["https://dimg04.c-ctrip.com/images/0236x224x8u1bbeva867C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l224x8u1cd07b2F68_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02359224x8u1cdw3j362D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02337224x8u1bnuz2593F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q224x8u1bbevcE5F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d224x8u1b2ynyDBCD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02303224x8u1cd07dB629_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m224x8u1cfbfgFDDB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z224x8u1bz417FE33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2024-02-15', '红棉大床套房', '套房', '情侣出游', 89, 4.499809670330265, 18, 2.9444389791664403, 8, 2.19722457733622, 9, '["房间设施", "卫生状况"]'::jsonb, '房间设施', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '作为老广，花园酒店一直都是属于高档酒店的存在，没想到入住大失所望，房间设施陈旧就', '作为老广，花园酒店一直都是属于高档酒店的存在，没想到入住大失所望，房间设施陈旧就不说了，浴室卫生简直以灾难级形容，大理石裂的，洗脸盆和淋浴间的霉菌简直吓人，很难想象跟星级扯上关系', '2024-02-15', 2, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c4be3c98b0941765a34', '选择住花园酒店时还有点纠结，虽然也是五星，但年代久远，硬件设施确实还有改进的空间，但也因为是老牌五星，对于我们这种没体验过的外地游客而言，还是很新奇，瀑布、花园、博物馆这些无论对于大人还是孩子而言，都还是不错的体验。应该说特色突出，值得一试。但是入住和退房都要排队，有点尴尬，携程的铂金会员也要押金，好在办了个岭南酒店金卡，送了小朋友早餐还是不错的，而且瀑布餐厅和楼上的旋转餐厅，孩子都很喜欢，总体来说还是很满意的！对了，在地铁口也非常重要，超级方便！', '["https://dimg04.c-ctrip.com/images/0236x12000dgi8s56305C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000dgi8svqC8C7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000dgi8ue63237_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000dgi95cfDEF4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-03-20', '花园大床房', '大床房', '家庭亲子', 226, 5.424950017481403, 0, 0.0, 9, 2.302585092994046, 9, '["整体满意度", "交通便利性", "退房/入住效率"]'::jsonb, '整体满意度', '交通便利性', '退房/入住效率', '未知酒店', '未知地点', '匿名', '选择住花园酒店时还有点纠结，虽然也是五星，但年代久远，硬件设施确实还有改进的空间', '选择住花园酒店时还有点纠结，虽然也是五星，但年代久远，硬件设施确实还有改进的空间，但也因为是老牌五星，对于我们这种没体验过的外地游客而言，还是很新奇，瀑布、花园、博物馆这些无论对于大人还是孩子而言，都还是不错的体验。应该说特色突出，值得一试。但是入住和退房都要排队，有点尴尬，携程的铂金会员也要押金，好在办了个岭南酒店金卡，送了小朋友早餐还是不错的，而且瀑布餐厅和楼上的旋转餐厅，孩子都很喜欢，总体来说还是很满意的！对了，在地铁口也非常重要，超级方便！', '2024-03-20', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c4be3c98b0941765a35', '家庭出游定了双床房，整个交通，酒店环境都还不错。但只有三分的原因就是这个洗手间和浴缸（没有淋浴间）是正对房间两个床，也就是家里有异性的话，无可避免的要有几分钟暴露时间，因为你不能在浴缸里穿衣服，而且也没地方放干净的衣服，如果家里有老人，跨进跨出洗澡还非常有难度！这个设计是我不能理解的。就算是好朋友一起出游，我想也不太好意思洗完澡出来就被看光吧？？？
另外，我在六楼，需要补给我去找走廊打扫的小妹，外籍小姑娘说“听不懂”，只能用英语交流，我想说，你在中国的土地上打工，你听不懂？？？这个需要客房部培训一下了。我可以讲英语，但是你不能不会中文哦！', '["https://dimg04.c-ctrip.com/images/0233112000d6d6stbD701_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z12000d6de616286D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000d6d53jg7C8D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2024-02-11', '城央绿意双床房', '双床房', '家庭亲子', 272, 5.60947179518496, 1, 0.6931471805599453, 16, 2.833213344056216, 9, '["房间设施", "客房服务"]'::jsonb, '房间设施', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '家庭出游定了双床房，整个交通，酒店环境都还不错。但只有三分的原因就是这个洗手间和', '家庭出游定了双床房，整个交通，酒店环境都还不错。但只有三分的原因就是这个洗手间和浴缸（没有淋浴间）是正对房间两个床，也就是家里有异性的话，无可避免的要有几分钟暴露时间，因为你不能在浴缸里穿衣服，而且也没地方放干净的衣服，如果家里有老人，跨进跨出洗澡还非常有难度！这个设计是我不能理解的。就算是好朋友一起出游，我想也不太好意思洗完澡出来就被看光吧？？？
另外，我在六楼，需要补给我去找走廊打扫的小妹，外籍小姑娘说“听不懂”，只能用英语交流，我想说，你在中国的土地上打工，你听不懂？？？这个需要客房部培训一下了。我可以讲英语，但是你不能不会中文哦！', '2024-02-11', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c4be3c98b0941765a36', '孩子们非常喜欢花园酒店，装修精致，服务贴心，后花园景色优美，欣赏瀑布尝心悦目，酒店的文创商品也非常有特色，荔湾亭的食物让人流连忘返，酒店交通便捷，距离地铁站很近，酒店各方面都让人很满意，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0233p12000d8a1ojt7045_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000d8a0p6yAF5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000d89um1d1DAF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235912000d89y9n73564_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000d8a2lm9A923_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-17', '花园大床房', '大床房', '家庭亲子', 100, 4.61512051684126, 0, 0.0, 5, 1.791759469228055, 8, '["整体满意度", "周边配套", "交通便利性"]'::jsonb, '整体满意度', '周边配套', '交通便利性', '未知酒店', '未知地点', '匿名', '孩子们非常喜欢花园酒店，装修精致，服务贴心，后花园景色优美，欣赏瀑布尝心悦目，酒', '孩子们非常喜欢花园酒店，装修精致，服务贴心，后花园景色优美，欣赏瀑布尝心悦目，酒店的文创商品也非常有特色，荔湾亭的食物让人流连忘返，酒店交通便捷，距离地铁站很近，酒店各方面都让人很满意，下次还会入住。', '2024-02-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c4be3c98b0941765a37', '酒店非常气派，大开眼界！ 长辈都夸好。
