INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c56e3c98b0941765a3c', '都很满意，出地库就有漂亮小姐姐帮忙拿行李引路。还有欢迎糖果，和离店小礼物。酒店后花园是隐藏在闹市里的世外桃源，美美的！很出片！下次去还住花园酒店！周边很方便，饭后遛食，一杯小酒惬意的很！', '["https://dimg04.c-ctrip.com/images/0234m12000d7b2ym55209_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000d7b2eqh5649_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000d7b2whd5DD9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000d7b2xik9C05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000d7b3b3z80C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000d7b3mm699AE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000d7b3hs2F3D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000d7b2iiiE39C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-14', '城央绿意双床房', '双床房', '朋友出游', 93, 4.543294782270004, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "前台服务", "周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套', '未知酒店', '未知地点', '匿名', '都很满意，出地库就有漂亮小姐姐帮忙拿行李引路。还有欢迎糖果，和离店小礼物。酒店后', '都很满意，出地库就有漂亮小姐姐帮忙拿行李引路。还有欢迎糖果，和离店小礼物。酒店后花园是隐藏在闹市里的世外桃源，美美的！很出片！下次去还住花园酒店！周边很方便，饭后遛食，一杯小酒惬意的很！', '2024-02-14', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c56e3c98b0941765a3d', '花园酒店真的是目前住过最有底蕴的酒店，一进入大厅就能感受到。前台办理入住非常快，虽然排队的人多但是窗口非常多很快就到了。前台Gillian非常专业迅速，得知我们是金卡会员并且过生日迅速安排房型升级超级认真负责，还送了鲜花超好评。行政酒廊待遇也非常全面，包含了早餐，下午茶和晚上的欢乐时光。
早餐种类非常多，在30楼旋转餐厅，每次都会带领我们入座。在我们记错时间错过下午茶时间后，Carrie女士立刻为我们安排第二天补上。即使不在服务时间，另外几位女士也为我们制作了两杯咖啡。二天我们入座后Carrie立刻前来询问我们的需求。
此外，我们住宿的16层电梯口也也服务的女生，我们安排电梯。
花园酒店的服务团队非常非常专业，非常庆幸这次能够选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0232x12000euns61q4F60_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000eunvsyw002A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000eunsaaoFADC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000eunr5cgC79B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000eunlun62212_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-21', '花园双床房', '双床房', '家庭亲子', 324, 5.783825182329737, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店真的是目前住过最有底蕴的酒店，一进入大厅就能感受到。前台办理入住非常快，', '花园酒店真的是目前住过最有底蕴的酒店，一进入大厅就能感受到。前台办理入住非常快，虽然排队的人多但是窗口非常多很快就到了。前台Gillian非常专业迅速，得知我们是金卡会员并且过生日迅速安排房型升级超级认真负责，还送了鲜花超好评。行政酒廊待遇也非常全面，包含了早餐，下午茶和晚上的欢乐时光。
早餐种类非常多，在30楼旋转餐厅，每次都会带领我们入座。在我们记错时间错过下午茶时间后，Carrie女士立刻为我们安排第二天补上。即使不在服务时间，另外几位女士也为我们制作了两杯咖啡。二天我们入座后Carrie立刻前来询问我们的需求。
此外，我们住宿的16层电梯口也也服务的女生，我们安排电梯。
花园酒店的服务团队非常非常专业，非常庆幸这次能够选择花园酒店。', '2024-07-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c56e3c98b0941765a3e', '非常巨大的酒店，所以入住要排队很久……大厅很国际化，设施还不错。第一次安排的房间一进门就是浓浓的蒜蓉生蚝味道，虽说闻起来不错，可实在不适合入住吧。之前就听闻早餐是米其林级别的，所以都订购了含早的房型，第一天体验还可以，虽说选择不多，餐厅比较小，有点局促，但餐厅后的瀑布还比较特别。第二天的早餐因为人太多，被忽悠到了旁边的酒吧，进去前一直被告知菜品是一样的，结果酒吧里不仅很冷，还没什么吃的，本来没什么胃口，只想喝完热粥，哪知道连这么卑微的要求都不能满足。敞开的粥锅里只剩一个底儿，还得排队抢，好不容易盛好了粥，还居然是冰粥。酒吧的服务人员一直在保障外国友人，国人在她们眼中，大概就是被施舍的吧，体验非常非常差，这样的品质也好意思说自己米其林？也好意思收200+的价格？现在是2024年了，拜托酒店醒醒吧，不是只有服务好外国友人就可以万事大吉的时候了。很糟糕的体验。再也不会来这样一家徒有虚名的虚伪酒店了。', '["https://dimg04.c-ctrip.com/images/0235812000d914evn8F54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2024-02-20', '花园大床房', '大床房', '家庭亲子', 402, 5.998936561946683, 7, 2.079441541679836, 13, 2.6390573296152584, 9, '["餐饮设施", "整体满意度", "性价比"]'::jsonb, '餐饮设施', '整体满意度', '性价比', '未知酒店', '未知地点', '匿名', '非常巨大的酒店，所以入住要排队很久……大厅很国际化，设施还不错。第一次安排的房间', '非常巨大的酒店，所以入住要排队很久……大厅很国际化，设施还不错。第一次安排的房间一进门就是浓浓的蒜蓉生蚝味道，虽说闻起来不错，可实在不适合入住吧。之前就听闻早餐是米其林级别的，所以都订购了含早的房型，第一天体验还可以，虽说选择不多，餐厅比较小，有点局促，但餐厅后的瀑布还比较特别。第二天的早餐因为人太多，被忽悠到了旁边的酒吧，进去前一直被告知菜品是一样的，结果酒吧里不仅很冷，还没什么吃的，本来没什么胃口，只想喝完热粥，哪知道连这么卑微的要求都不能满足。敞开的粥锅里只剩一个底儿，还得排队抢，好不容易盛好了粥，还居然是冰粥。酒吧的服务人员一直在保障外国友人，国人在她们眼中，大概就是被施舍的吧，体验非常非常差，这样的品质也好意思说自己米其林？也好意思收200+的价格？现在是2024年了，拜托酒店醒醒吧，不是只有服务好外国友人就可以万事大吉的时候了。很糟糕的体验。再也不会来这样一家徒有虚名的虚伪酒店了。', '2024-02-20', 2, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c56e3c98b0941765a3f', '著名的花园酒店，非常喜欢那种文化气息和岁月的底蕴，同时自然也会有设施维护的问题，比如用水时下水管道会发出响声，沙发上会有污渍，但服务也非常周到，除了入住时前台不清楚套餐包含的桃园馆餐次数，说要核实后告知，不过一直没有回音，后来主动问过一次，也没有回话，除此而外，服务特别好，比如无论去餐厅还是乘电梯都有人引导，退房体验特别好特别方便以及人性化。下午茶和欢乐时光体验也很美好。总之，满意，再去广州会再选花园。', '["https://dimg04.c-ctrip.com/images/0235f12000d59v0c7125D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000d5aijkzEAF2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000d5aiin2059E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-06', '粤韵双床套房', '套房', '家庭亲子', 203, 5.318119993844216, 0, 0.0, 6, 1.9459101490553128, 8, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '著名的花园酒店，非常喜欢那种文化气息和岁月的底蕴，同时自然也会有设施维护的问题，', '著名的花园酒店，非常喜欢那种文化气息和岁月的底蕴，同时自然也会有设施维护的问题，比如用水时下水管道会发出响声，沙发上会有污渍，但服务也非常周到，除了入住时前台不清楚套餐包含的桃园馆餐次数，说要核实后告知，不过一直没有回音，后来主动问过一次，也没有回话，除此而外，服务特别好，比如无论去餐厅还是乘电梯都有人引导，退房体验特别好特别方便以及人性化。下午茶和欢乐时光体验也很美好。总之，满意，再去广州会再选花园。', '2024-02-06', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c56e3c98b0941765a40', '购买了携程3晚连住花园双床房含早3600套餐，提前一周预约了房间。出发前一天跟客房部打电话确认房型，要求高楼层安静无烟，对方回答会给备注。当天20点到达办理入住，说是帮我帮忙升级了9楼的城央绿意房，上去查看900是位于电梯间后面，浴缸和淋浴同处一处，考虑带孩子使用不便，便座机酒店客房部要求原房型入住。结果被告知已无类似房型。那么问题来了，我之前的全款预约、电话确认是为了什么？！座机沟通后被告知还有一间花园双床房在打扫，但无浴缸。我提出可否参观一下，被拒绝，并且打扫需要1.5小时左右，就是22点半以后！！毫无选择的我只能致电携程客服帮忙解决～就这么等了50分钟酒店和携程都没有任何回复。第三次致电携程后仍没有确切回复，自行前往大堂前台直接理论。诉求和理由同上。在前台交涉了50分钟，最终给了间23楼的红棉大床房加床处理，入住时接近22:30。我们不是无理取闹的人，只是争取合理的权益。好在后续酒店和携程在催促下有积极处理，结果还是满意的。说说酒店本身，地处老城区，餐饮交通真的方便。顶楼旋转餐厅风景好，餐食和服务都不错。所在楼层会有电梯间引导服务员，每次见面问好并确认房间号，挺安全的。图1-3是9楼的城央绿意房，除了浴缸淋浴不合理，其余中规中矩。图4是新装修的红棉房，推荐入住。携程平台还是很注意客户感受的，继续支持！', '["https://dimg04.c-ctrip.com/images/0234x12000d5um70s1B80_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000d5u8fjzE728_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000d5ujepx30C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000d5uchav48C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-08', '花园双床房', '双床房', '家庭亲子', 562, 6.333279628139691, 0, 0.0, 26, 3.295836866004329, 9, '["前台服务", "退房/入住效率", "房间设施"]'::jsonb, '前台服务', '退房/入住效率', '房间设施', '未知酒店', '未知地点', '匿名', '购买了携程3晚连住花园双床房含早3600套餐，提前一周预约了房间。出发前一天跟客', '购买了携程3晚连住花园双床房含早3600套餐，提前一周预约了房间。出发前一天跟客房部打电话确认房型，要求高楼层安静无烟，对方回答会给备注。当天20点到达办理入住，说是帮我帮忙升级了9楼的城央绿意房，上去查看900是位于电梯间后面，浴缸和淋浴同处一处，考虑带孩子使用不便，便座机酒店客房部要求原房型入住。结果被告知已无类似房型。那么问题来了，我之前的全款预约、电话确认是为了什么？！座机沟通后被告知还有一间花园双床房在打扫，但无浴缸。我提出可否参观一下，被拒绝，并且打扫需要1.5小时左右，就是22点半以后！！毫无选择的我只能致电携程客服帮忙解决～就这么等了50分钟酒店和携程都没有任何回复。第三次致电携程后仍没有确切回复，自行前往大堂前台直接理论。诉求和理由同上。在前台交涉了50分钟，最终给了间23楼的红棉大床房加床处理，入住时接近22:30。我们不是无理取闹的人，只是争取合理的权益。好在后续酒店和携程在催促下有积极处理，结果还是满意的。说说酒店本身，地处老城区，餐饮交通真的方便。顶楼旋转餐厅风景好，餐食和服务都不错。所在楼层会有电梯间引导服务员，每次见面问好并确认房间号，挺安全的。图1-3是9楼的城央绿意房，除了浴缸淋浴不合理，其余中规中矩。图4是新装修的红棉房，推荐入住。携程平台还是很注意客户感受的，继续支持！', '2024-02-08', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c56e3c98b0941765a41', '房间干净，环境很好', '["https://dimg04.c-ctrip.com/images/0233112000eroqusg1AE9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000erojtjw6044_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000eroquky5D33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-13', '红棉大床套房', '套房', '情侣出游', 9, 2.302585092994046, 0, 0.0, 12, 2.5649493574615367, 4, '["卫生状况", "整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '房间干净，环境很好', '房间干净，环境很好', '2024-07-13', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c56e3c98b0941765a42', '不知道为什么会有许多差评，对于一个比较挑剔的住客来讲首先我认为不错的。选了家庭大床房，服务很好，酒店下车时工作人员主动帮忙搬行李，每层都有导引人员，其次房间虽然不是非常大，但是干净温馨而舒适。巴基斯坦的小伙子很热情。作为白金五星酒店四楼的博物馆一定要去看看，那是时代的缩影，还有后花园，繁华喧嚣中的宁静与美好。唯一的遗憾是瀑布餐厅的早餐因为周六客满被换到了旋转餐厅，希望这一项能够改善，至少要保证住店客人用餐。', '["https://dimg04.c-ctrip.com/images/0230u12000d49hbp170F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000d49tivrDCE2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000d49w5zd725C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-03', '花园大床房', '大床房', '家庭亲子', 205, 5.327876168789581, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '不知道为什么会有许多差评，对于一个比较挑剔的住客来讲首先我认为不错的。选了家庭大', '不知道为什么会有许多差评，对于一个比较挑剔的住客来讲首先我认为不错的。选了家庭大床房，服务很好，酒店下车时工作人员主动帮忙搬行李，每层都有导引人员，其次房间虽然不是非常大，但是干净温馨而舒适。巴基斯坦的小伙子很热情。作为白金五星酒店四楼的博物馆一定要去看看，那是时代的缩影，还有后花园，繁华喧嚣中的宁静与美好。唯一的遗憾是瀑布餐厅的早餐因为周六客满被换到了旋转餐厅，希望这一项能够改善，至少要保证住店客人用餐。', '2024-02-03', 5, '整体满意度');
