下次还会再来住！', '2024-02-09', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a44', '第一次入住，很成熟高雅的酒店。花园酒店的Rebecca还给升级了房间，必须点个赞！', '["https://dimg04.c-ctrip.com/images/0233112000e3h02acC28E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000e3gycdi0688_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000e3gzph884F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-21', '花园大床房', '大床房', '其他', 41, 3.737669618283368, 0, 0.0, 1, 0.6931471805599453, 6, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '第一次入住，很成熟高雅的酒店。花园酒店的Rebecca还给升级了房间，必须点个赞', '第一次入住，很成熟高雅的酒店。花园酒店的Rebecca还给升级了房间，必须点个赞！', '2024-05-21', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a45', '满意，舒服！安娜和李文服务热情周到，保洁员对客户提出要求及时记录（服务满意）餐厅早餐美味，旁边有瀑布环境舒适', '["https://dimg04.c-ctrip.com/images/0230l12000jh0mcb0F34C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000jh05eu2E3FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000jgzufl75FF4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-01', '红棉大床套房', '套房', '情侣出游', 54, 4.007333185232471, 0, 0.0, 3, 1.3862943611198906, 7, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '满意，舒服！安娜和李文服务热情周到，保洁员对客户提出要求及时记录（服务满意）餐厅', '满意，舒服！安娜和李文服务热情周到，保洁员对客户提出要求及时记录（服务满意）餐厅早餐美味，旁边有瀑布环境舒适', '2025-04-01', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a46', '房间的设施有点老旧了，酒店大堂和后花园还可以。这酒店住的老外挺多的，重点来了。因为老外多，我发现大厅餐厅的服务员就比较**，我们去吃早饭的时候遇到同样一起排队的老外就分在能看见瀑布的位置视野开阔，光线明亮，我们一家三口分的位置就是最最角落的不要说看看瀑布了连光线都很暗的，家人们谁懂啊，花600多就是去打卡瀑布的好吗。我看见我们前面的三个老外就坐的位置很好，我当时就emo了，问服务员有没有位置好点的嘛？大厅不是有很多空位置吗？我想坐到那边去，她说啊那是有人坐的，他们都在取餐，一边说的时候一边微笑，我听了就不开心了，吃饭的心情也没有，过一会不知怎么的大概看我不开心就给我们换位置到大厅了，重点来了，我去取咖啡的时候杯子着急拿走服务员就跟我说no finished 谁懂啊，我一中国人在广州玩又没有出国说啥英语啊，真的醉了，咱不是说排斥英语啊，就你环顾四周的时候就发现坐大厅好位置的都是老外，我严重怀疑这酒店服务员是**。最后酒店早餐真的很一般就同是五星级酒店的早餐来比不能说最差的，实在是一般。不建议去吃。', '["https://dimg04.c-ctrip.com/images/0236112000d43ak44002F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000d439zl62586_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000d43arke538E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-02-03', '花园双床房', '双床房', '家庭亲子', 454, 6.12029741895095, 1, 0.6931471805599453, 1, 0.6931471805599453, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '房间的设施有点老旧了，酒店大堂和后花园还可以。这酒店住的老外挺多的，重点来了。因', '房间的设施有点老旧了，酒店大堂和后花园还可以。这酒店住的老外挺多的，重点来了。因为老外多，我发现大厅餐厅的服务员就比较**，我们去吃早饭的时候遇到同样一起排队的老外就分在能看见瀑布的位置视野开阔，光线明亮，我们一家三口分的位置就是最最角落的不要说看看瀑布了连光线都很暗的，家人们谁懂啊，花600多就是去打卡瀑布的好吗。我看见我们前面的三个老外就坐的位置很好，我当时就emo了，问服务员有没有位置好点的嘛？大厅不是有很多空位置吗？我想坐到那边去，她说啊那是有人坐的，他们都在取餐，一边说的时候一边微笑，我听了就不开心了，吃饭的心情也没有，过一会不知怎么的大概看我不开心就给我们换位置到大厅了，重点来了，我去取咖啡的时候杯子着急拿走服务员就跟我说no finished 谁懂啊，我一中国人在广州玩又没有出国说啥英语啊，真的醉了，咱不是说排斥英语啊，就你环顾四周的时候就发现坐大厅好位置的都是老外，我严重怀疑这酒店服务员是**。最后酒店早餐真的很一般就同是五星级酒店的早餐来比不能说最差的，实在是一般。不建议去吃。', '2024-02-03', 3, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a47', '超级漂亮的酒店，地理位置非常好，整个酒店进门就是香香的，给我们升级了套房，三大一小住起来很宽敞，很舒服的一次旅行，客房还送了小书包跟水果给宝宝，特别用心呢', '["https://dimg04.c-ctrip.com/images/0232j12000dctkqbr9A37_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000dct83q77958_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000dcth2f6EC16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000dctjphy62BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000dctl6baA3A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000dct7vjhBFC7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000dctoc29A7E8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-06', '红棉大床套房', '套房', '家庭亲子', 77, 4.356708826689592, 1, 0.6931471805599453, 7, 2.079441541679836, 8, '["整体满意度", "客房服务", "周边配套"]'::jsonb, '整体满意度', '客房服务', '周边配套', '未知酒店', '未知地点', '匿名', '超级漂亮的酒店，地理位置非常好，整个酒店进门就是香香的，给我们升级了套房，三大一', '超级漂亮的酒店，地理位置非常好，整个酒店进门就是香香的，给我们升级了套房，三大一小住起来很宽敞，很舒服的一次旅行，客房还送了小书包跟水果给宝宝，特别用心呢', '2024-03-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a48', '酒店位置很好，环境优美，服务到位，床品舒服，早餐纯西式，周边有广东酒家、点都德早茶非常不错！卫生需要注意，咖啡机和水壶感觉都不太干净！过年气氛很浓，大堂有自己的集市和乐队，热热闹闹，开开心心！', '["https://dimg04.c-ctrip.com/images/0234712000d5rdzk6E556_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000d5remy15829_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000d5rf5k569E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000d5rfevsB913_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000d5rdddt189B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000d5rf5k995A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-08', '花园大床房', '大床房', '家庭亲子', 96, 4.574710978503383, 0, 0.0, 18, 2.9444389791664403, 8, '["周边配套", "整体满意度", "卫生状况"]'::jsonb, '周边配套', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店位置很好，环境优美，服务到位，床品舒服，早餐纯西式，周边有广东酒家、点都德早', '酒店位置很好，环境优美，服务到位，床品舒服，早餐纯西式，周边有广东酒家、点都德早茶非常不错！卫生需要注意，咖啡机和水壶感觉都不太干净！过年气氛很浓，大堂有自己的集市和乐队，热热闹闹，开开心心！', '2024-02-08', 4, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a49', '这是我住过最差的酒店（更别说是五星级酒店了），比招待所都不如，还五星。房间和卫生间冲凉房直通，冲凉换衣服都不方便，而且设施非常残旧，真的是招待所的硬件。
    冲凉房居然就是一个浴缸，排水又慢，冲个凉简直就是水漫金山，水泡到脚腕，无法排水，而且在浴缸跨来跨去影响人身安全，出来就是房间，无任何遮挡，招待所都不是如此吧？岂有此理！！
    卫生间又窄又残旧，进去又不方便，就是个招待所不如的地方。
    房间又小可能 10 平方左右，而且床又残旧，地板更残旧，反正没一样东西是好的。就是乡下的招待所都比花园酒店客房好。反正谁住谁遭殃。看看图片就知道。差评！差评！差评！重要事情说三遍！！', '["https://dimg04.c-ctrip.com/images/0236i12000d3119ic90B7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000d30qrm5AF24_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000d30qebnF6A5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000d316hju06F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000d30v4171095_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2024-01-30', '花园双床房', '双床房', '家庭亲子', 295, 5.69035945432406, 8, 2.19722457733622, 60, 4.110873864173311, 9, '["房间设施", "卫生状况", "整体满意度"]'::jsonb, '房间设施', '卫生状况', '整体满意度', '未知酒店', '未知地点', '匿名', '这是我住过最差的酒店（更别说是五星级酒店了），比招待所都不如，还五星。房间和卫生', '这是我住过最差的酒店（更别说是五星级酒店了），比招待所都不如，还五星。房间和卫生间冲凉房直通，冲凉换衣服都不方便，而且设施非常残旧，真的是招待所的硬件。
    冲凉房居然就是一个浴缸，排水又慢，冲个凉简直就是水漫金山，水泡到脚腕，无法排水，而且在浴缸跨来跨去影响人身安全，出来就是房间，无任何遮挡，招待所都不是如此吧？岂有此理！！
    卫生间又窄又残旧，进去又不方便，就是个招待所不如的地方。
    房间又小可能 10 平方左右，而且床又残旧，地板更残旧，反正没一样东西是好的。就是乡下的招待所都比花园酒店客房好。反正谁住谁遭殃。看看图片就知道。差评！差评！差评！重要事情说三遍！！', '2024-01-30', 1, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a4a', '预订酒店时备注了这次入住是为了过生日如果情况允许希望能安排上好一点的房间。晚上九点到店办入住时迎来了小小客流高峰，需要排队等候。办理入住手续的时候，前台小姐姐Betty 安排了一个超完美的房间，她还特意提醒我房号是精心设置了一个“好意头”的房间，还热情的给我送了几支花花。真的是太有趣了！房间安排了升级，打开房门发现房间有主题精心布置过，还有新鲜的欢迎水果，非常感谢客房姐姐的安排！房间里处处都是细节，房间桌子上摆放着酒店不同餐厅不同特色打卡点的酒店指南，图文并茂有趣又生动。连墙上挂着的装饰画都有印着二维码，好奇地拿手机一扫，显示出来的就是客房里房间装饰上蕴含的各种岭南文化元素。让我异常惊喜的是，短短的文章中透露出不同的岭南特色文化，有种让住客在入住期间都能感受到这个酒店的文化底蕴和用意。唯一一个小小的插曲大概是我们不知道今天酒店会有赠送蛋糕到房间的这个惊喜。所以早上送的时候，估计服务员看到我们挂了请勿打扰灯，让前台打了电话来确认，刚好那个时间我们还在休息，电话来的时候会有一点感觉被吵醒到了。但总体来说这次入住非常不错的呢', '["https://dimg04.c-ctrip.com/images/0231v12000fhuiq43E951_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000fhu3svwD0DE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000fhtpgqj4BDF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000fhufwt8C3A0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000fhu9t8i841F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-11', '花园大床房', '大床房', '情侣出游', 466, 6.1463292576688975, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '预订酒店时备注了这次入住是为了过生日如果情况允许希望能安排上好一点的房间。晚上九', '预订酒店时备注了这次入住是为了过生日如果情况允许希望能安排上好一点的房间。晚上九点到店办入住时迎来了小小客流高峰，需要排队等候。办理入住手续的时候，前台小姐姐Betty 安排了一个超完美的房间，她还特意提醒我房号是精心设置了一个“好意头”的房间，还热情的给我送了几支花花。真的是太有趣了！房间安排了升级，打开房门发现房间有主题精心布置过，还有新鲜的欢迎水果，非常感谢客房姐姐的安排！房间里处处都是细节，房间桌子上摆放着酒店不同餐厅不同特色打卡点的酒店指南，图文并茂有趣又生动。连墙上挂着的装饰画都有印着二维码，好奇地拿手机一扫，显示出来的就是客房里房间装饰上蕴含的各种岭南文化元素。让我异常惊喜的是，短短的文章中透露出不同的岭南特色文化，有种让住客在入住期间都能感受到这个酒店的文化底蕴和用意。唯一一个小小的插曲大概是我们不知道今天酒店会有赠送蛋糕到房间的这个惊喜。所以早上送的时候，估计服务员看到我们挂了请勿打扰灯，让前台打了电话来确认，刚好那个时间我们还在休息，电话来的时候会有一点感觉被吵醒到了。但总体来说这次入住非常不错的呢', '2024-09-11', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a4b', '风景很好，酒店有文化历史风韵。下次还会入住这里，续住了一日，非常满意。酒店周边很多老酒家，适合美食爱好者。', '["https://dimg04.c-ctrip.com/images/0235k12000ds5ynjv34C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000ds60lf740B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000ds5s3wh96AB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000ds5ni6j9D2F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-25', '花园双床房', '双床房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 4, 1.6094379124341005, 6, '["整体满意度", "周边配套", "景观/朝向"]'::jsonb, '整体满意度', '周边配套', '景观/朝向', '未知酒店', '未知地点', '匿名', '风景很好，酒店有文化历史风韵。下次还会入住这里，续住了一日，非常满意。酒店周边很', '风景很好，酒店有文化历史风韵。下次还会入住这里，续住了一日，非常满意。酒店周边很多老酒家，适合美食爱好者。', '2024-04-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a4c', '设施：大堂非常的富丽堂皇，现在是圣诞节的布置了，好浪漫。?瀑布餐厅也不错，房间的层高略矮，?以如今已是38年了，设施有点老旧，但是还是蛮干净的，床上用品很舒服，如果放在38年前绝对是顶级奢华。??
过来过生日的，酒店帮忙升级的房间，还帮忙做了布置，前台还送的了鲜花，谢谢每一位热心且用心的工作人员。
酒店的花园也是精心设计过的，但是略小，现在只有异木棉在开放。
酒店博物馆还不错，听说有免费的讲解，但是没赶上。
上上下下里里外外的每一个工作人员态度都非常好，大堂里穿粉红色裙子的小姐姐会热心的帮忙拍，而且拍照技术很赞，感谢感谢！
早餐比较一般，种类比较，但是环境很好。
送的点心很好吃！谢谢！
因为胃不好，不然高低吃顿午饭再走。
整体感觉不错，都在五星的水准，里里外外逛了个遍，没事就在房间里面写写字，很安逸。
?', '["https://dimg04.c-ctrip.com/images/0235r12000cprsuos5E53_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000cps3hjy3280_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000cps169e203B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000cprw22p8475_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000cprvbztF677_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000cps3r2cB5F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000cps3rgdF2C9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000cprxjenB7D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000cps2sb0D762_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-11', '红棉大床套房', '套房', '其他', 358, 5.883322388488279, 1, 0.6931471805599453, 5, 1.791759469228055, 9, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '设施：大堂非常的富丽堂皇，现在是圣诞节的布置了，好浪漫。?瀑布餐厅也不错，房间的', '设施：大堂非常的富丽堂皇，现在是圣诞节的布置了，好浪漫。?瀑布餐厅也不错，房间的层高略矮，?以如今已是38年了，设施有点老旧，但是还是蛮干净的，床上用品很舒服，如果放在38年前绝对是顶级奢华。??
过来过生日的，酒店帮忙升级的房间，还帮忙做了布置，前台还送的了鲜花，谢谢每一位热心且用心的工作人员。
酒店的花园也是精心设计过的，但是略小，现在只有异木棉在开放。
酒店博物馆还不错，听说有免费的讲解，但是没赶上。
上上下下里里外外的每一个工作人员态度都非常好，大堂里穿粉红色裙子的小姐姐会热心的帮忙拍，而且拍照技术很赞，感谢感谢！
早餐比较一般，种类比较，但是环境很好。
送的点心很好吃！谢谢！
因为胃不好，不然高低吃顿午饭再走。
整体感觉不错，都在五星的水准，里里外外逛了个遍，没事就在房间里面写写字，很安逸。
?', '2023-12-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c61e3c98b0941765a4d', '12555566666998888885555556666585555555555555555638885 九点不错！！', '["https://dimg04.c-ctrip.com/images/0235b12000eiqwg6m7688_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000eiqzilh8041_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000eiqt5zoE21E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-19', '花园大床房', '大床房', '情侣出游', 60, 4.110873864173311, 0, 0.0, 39, 3.688879454113936, 0.0, '[]'::jsonb, NULL, NULL, NULL, '未知酒店', '未知地点', '匿名', '1255556666699888888555555666658555555555', '12555566666998888885555556666585555555555555555638885 九点不错！！', '2024-06-19', 5, '情侣出游');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a4e', '作为全国3家白金五星级酒店，大堂富丽堂皇，后花园小桥流水，瀑布潺潺。4楼酒店博物馆不错，感受改革开放的岁月变迁，体会广州酒店业的发展历史和蓬勃生机。酒店门口地铁淘金站，去哪都很方便。稍显遗憾的是早餐种类不多，而且人多，排队时间长，体验不是很好。', '["https://dimg04.c-ctrip.com/images/0232d12000d6f3jvj4011_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000d6f55izAE56_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000d6eliyz4EBA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-11', '花园大床房', '大床房', '家庭亲子', 122, 4.812184355372417, 0, 0.0, 11, 2.4849066497880004, 9, '["交通便利性", "餐饮设施", "整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '作为全国3家白金五星级酒店，大堂富丽堂皇，后花园小桥流水，瀑布潺潺。4楼酒店博物', '作为全国3家白金五星级酒店，大堂富丽堂皇，后花园小桥流水，瀑布潺潺。4楼酒店博物馆不错，感受改革开放的岁月变迁，体会广州酒店业的发展历史和蓬勃生机。酒店门口地铁淘金站，去哪都很方便。稍显遗憾的是早餐种类不多，而且人多，排队时间长，体验不是很好。', '2024-02-11', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a4f', '本次购买的是套餐，包含自助晚餐和早餐，然后升级了一间房间为酒店景观房，十分美好，花园酒店虽然老牌但质量和服务依然上乘，房间设计精巧古典。食物也很好，很多人来吃自助，早餐最好也要早点去。附近可以去对面马路的友谊商店逛逛，是广州最早的进出口商店。也可以坐地铁或公交去天河体育西一带购物游玩，地点而言十分方便。', '["https://dimg04.c-ctrip.com/images/0230412000d9g31ae58CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-21', '花园双床房', '双床房', '家庭亲子', 152, 5.030437921392435, 0, 0.0, 22, 3.1354942159291497, 8, '["餐饮设施", "交通便利性", "整体满意度"]'::jsonb, '餐饮设施', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '本次购买的是套餐，包含自助晚餐和早餐，然后升级了一间房间为酒店景观房，十分美好，', '本次购买的是套餐，包含自助晚餐和早餐，然后升级了一间房间为酒店景观房，十分美好，花园酒店虽然老牌但质量和服务依然上乘，房间设计精巧古典。食物也很好，很多人来吃自助，早餐最好也要早点去。附近可以去对面马路的友谊商店逛逛，是广州最早的进出口商店。也可以坐地铁或公交去天河体育西一带购物游玩，地点而言十分方便。', '2024-02-21', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a50', '房间很奇葩，开放式卫生间，马桶间和淋浴室共用一扇非常难拉的拉门，可以想象*******便秘的场景，而且住到第三天被褥就会开始返潮……沟通了下前台，这种奇葩装修是老板喜欢，果然品味清奇。早餐八点左右必然排队，餐品挺难吃，我一便宜嘴巴说难吃就真真的千真万确了??，我觉得这种难吃是不以人的意志而转移的??。行政酒廊没烈酒和调酒，比较少见，全冷餐，在空调不行的情况下对老人和妇幼有点不和谐，基本上脱不了外套。酒店所有服务人员的素质很高，非常热情，仅次于海景花园了。行政酒廊的早餐点餐是冷的??', '["https://dimg04.c-ctrip.com/images/0234912000d2qxkre5497_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000d2qvavt2D2A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000d2qo6602484_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000d2r6sw2D1E7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2024-01-29', '花园双床房', '双床房', '情侣出游', 243, 5.497168225293202, 0, 0.0, 12, 2.5649493574615367, 9, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间很奇葩，开放式卫生间，马桶间和淋浴室共用一扇非常难拉的拉门，可以想象****', '房间很奇葩，开放式卫生间，马桶间和淋浴室共用一扇非常难拉的拉门，可以想象*******便秘的场景，而且住到第三天被褥就会开始返潮……沟通了下前台，这种奇葩装修是老板喜欢，果然品味清奇。早餐八点左右必然排队，餐品挺难吃，我一便宜嘴巴说难吃就真真的千真万确了??，我觉得这种难吃是不以人的意志而转移的??。行政酒廊没烈酒和调酒，比较少见，全冷餐，在空调不行的情况下对老人和妇幼有点不和谐，基本上脱不了外套。酒店所有服务人员的素质很高，非常热情，仅次于海景花园了。行政酒廊的早餐点餐是冷的??', '2024-01-29', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a51', '花园酒店一直都是很稳定，先装修的房间很好，体现岭南设计风格。', '["https://dimg04.c-ctrip.com/images/02328224x8uwpfvld3CB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-20', '花园大床房', '大床房', '商务出差', 30, 3.4339872044851463, 0, 0.0, 11, 2.4849066497880004, 6, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '花园酒店一直都是很稳定，先装修的房间很好，体现岭南设计风格。', '花园酒店一直都是很稳定，先装修的房间很好，体现岭南设计风格。', '2024-05-20', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a52', '老牌五星，广州人妇孺皆知的豪华酒店，硬件不会让人失望。服务在广州五星酒店里算比较好的，不过因为刚在上海和平饭店住过，感觉还有进一步提升空间，例如服务的主动，还有真诚。如果有机会，酒店的有关人不妨自己掏腰包，以普通客人的身份，去上海和平饭店住一晚，吃一次饭，参观一次酒店的博物馆，体验一下差距。作为一个老广州，真心希望花园酒店这个金子招牌擦得更亮。', '["https://dimg04.c-ctrip.com/images/0235t12000d2trhnt8953_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-30', '花园双床房', '双床房', '家庭亲子', 173, 5.159055299214529, 0, 0.0, 64, 4.174387269895637, 8, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '老牌五星，广州人妇孺皆知的豪华酒店，硬件不会让人失望。服务在广州五星酒店里算比较', '老牌五星，广州人妇孺皆知的豪华酒店，硬件不会让人失望。服务在广州五星酒店里算比较好的，不过因为刚在上海和平饭店住过，感觉还有进一步提升空间，例如服务的主动，还有真诚。如果有机会，酒店的有关人不妨自己掏腰包，以普通客人的身份，去上海和平饭店住一晚，吃一次饭，参观一次酒店的博物馆，体验一下差距。作为一个老广州，真心希望花园酒店这个金子招牌擦得更亮。', '2024-01-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a53', '花园酒店的大堂很有特色，很多元素，中西合璧，金光闪闪，迎面的冲击感很强。
岭南花园是酒店的特色，有四层楼高的瀑布，南国绿植，小桥流水加悠游的锦鲤，是一派太平盛世的景象。
最喜欢的部份是四楼博物馆，小姐姐洪亮的嗓音，标准的普通话讲解，把酒店发展的历史，广州酒店的历史以及花园酒店的特色娓娓道来。', '["https://dimg04.c-ctrip.com/images/0230n12000d3cl8xeCEDF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000d3cl57rF1C9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000d3cl57t7958_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000d3cl9p21263_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000d3cl4ex2B90_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-31', '花园双床房', '双床房', '家庭亲子', 146, 4.990432586778736, 0, 0.0, 13, 2.6390573296152584, 9, '["公共设施", "整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '花园酒店的大堂很有特色，很多元素，中西合璧，金光闪闪，迎面的冲击感很强。', '花园酒店的大堂很有特色，很多元素，中西合璧，金光闪闪，迎面的冲击感很强。
岭南花园是酒店的特色，有四层楼高的瀑布，南国绿植，小桥流水加悠游的锦鲤，是一派太平盛世的景象。
最喜欢的部份是四楼博物馆，小姐姐洪亮的嗓音，标准的普通话讲解，把酒店发展的历史，广州酒店的历史以及花园酒店的特色娓娓道来。', '2024-01-31', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a54', '基本满意，但是2024/1/27日在瀑布餐厅早餐的时候被一名服务人员（餐厅做鸡蛋卷的那个厨师，具体名称不清楚，就是鸡蛋摊开放菜丁的那个蛋饼）搞的心情不好，他摊好一个之后放在了台子上，我没有意识到是别人预定的，我就打算拿，刚拿起来，他就大声说“Order，understand？” ，我就放了回去，我就不明白了，你面对国内的客人，有必要说英文吗？而且还是呵斥的口吻，我很震惊，五星级老牌酒店，这种服务态度，而且还带有崇洋的潜意识，什么年代了，无语，本想投诉给餐厅经理的，行程太紧，没时间，这里吐槽一下，酒店的服务，硬件和软服务缺一不可，而且温馨的软服务才是取胜之道，总之这个人的服务影响了我对花园酒店的印象！', '["https://dimg04.c-ctrip.com/images/0232k12000d2cu55f4519_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-01-28', '花园双床房', '双床房', '家庭亲子', 303, 5.717027701406222, 2, 1.0986122886681098, 5, 1.791759469228055, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '基本满意，但是2024/1/27日在瀑布餐厅早餐的时候被一名服务人员（餐厅做鸡蛋', '基本满意，但是2024/1/27日在瀑布餐厅早餐的时候被一名服务人员（餐厅做鸡蛋卷的那个厨师，具体名称不清楚，就是鸡蛋摊开放菜丁的那个蛋饼）搞的心情不好，他摊好一个之后放在了台子上，我没有意识到是别人预定的，我就打算拿，刚拿起来，他就大声说“Order，understand？” ，我就放了回去，我就不明白了，你面对国内的客人，有必要说英文吗？而且还是呵斥的口吻，我很震惊，五星级老牌酒店，这种服务态度，而且还带有崇洋的潜意识，什么年代了，无语，本想投诉给餐厅经理的，行程太紧，没时间，这里吐槽一下，酒店的服务，硬件和软服务缺一不可，而且温馨的软服务才是取胜之道，总之这个人的服务影响了我对花园酒店的印象！', '2024-01-28', 3, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a55', '老牌白金五星底蕴还是非常深厚的 酒店本身就自带景点 餐饮配套等均在水准！
入住期间室外游泳池维修中没有体验 如有室内泳池更佳。
老酒店隔音是减分项，此次房间安排在布草间对面，保洁阿姨的开关门声聊天声都能听到，如对隔音有要求需慎选。', '["https://dimg04.c-ctrip.com/images/0232i12000d2loon5257A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000d2lqkdx21B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000d2lretx6FA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-01-29', '花园大床房', '大床房', '情侣出游', 115, 4.7535901911063645, 0, 0.0, 4, 1.6094379124341005, 8, '["公共设施", "安静程度", "餐饮设施"]'::jsonb, '公共设施', '安静程度', '餐饮设施', '未知酒店', '未知地点', '匿名', '老牌白金五星底蕴还是非常深厚的 酒店本身就自带景点 餐饮配套等均在水准！', '老牌白金五星底蕴还是非常深厚的 酒店本身就自带景点 餐饮配套等均在水准！
入住期间室外游泳池维修中没有体验 如有室内泳池更佳。
老酒店隔音是减分项，此次房间安排在布草间对面，保洁阿姨的开关门声聊天声都能听到，如对隔音有要求需慎选。', '2024-01-29', 3, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a56', '一家有情怀有历史的老牌酒店是值得入住的，特别是四楼的博物馆绝对加分，让顾客了解酒店的昨天和今天；后花园的颜值也是值得欣赏的。但是由于房间安排在电梯旁晚上总有上上下下电梯的声音，体验度不是很好；加上晚上九点多楼上还在类似发出维修的电钻和敲打声，这个暴露了管理的不精细的有违酒店顾客的酒店文化。', '["https://dimg04.c-ctrip.com/images/0233112000d25pedm5F86_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i12000d25pmxb0BED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000d25zenk5FE8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-27', '红棉大床套房', '套房', '家庭亲子', 145, 4.983606621708336, 0, 0.0, 4, 1.6094379124341005, 8, '["安静程度", "整体满意度", "公共设施"]'::jsonb, '安静程度', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '一家有情怀有历史的老牌酒店是值得入住的，特别是四楼的博物馆绝对加分，让顾客了解酒', '一家有情怀有历史的老牌酒店是值得入住的，特别是四楼的博物馆绝对加分，让顾客了解酒店的昨天和今天；后花园的颜值也是值得欣赏的。但是由于房间安排在电梯旁晚上总有上上下下电梯的声音，体验度不是很好；加上晚上九点多楼上还在类似发出维修的电钻和敲打声，这个暴露了管理的不精细的有违酒店顾客的酒店文化。', '2024-01-27', 4, '安静程度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c6ce3c98b0941765a57', '酒店大堂富丽堂皇，第一眼看到有被震惊到，涨见识了！酒店处处是艺术风景，后花园也很美，值得来。这是一家有历史，文化底蕴的酒店，所以以前的房间设施相对旧点，但总体感受很好！', '["https://dimg04.c-ctrip.com/images/0232e12000d91lfstDB4C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000d91ogui461E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000d91yjggFB1B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 84, 4.442651256490317, 0, 0.0, 2, 1.0986122886681098, 7, '["整体满意度", "公共设施", "房间设施"]'::jsonb, '整体满意度', '公共设施', '房间设施', '未知酒店', '未知地点', '匿名', '酒店大堂富丽堂皇，第一眼看到有被震惊到，涨见识了！酒店处处是艺术风景，后花园也很', '酒店大堂富丽堂皇，第一眼看到有被震惊到，涨见识了！酒店处处是艺术风景，后花园也很美，值得来。这是一家有历史，文化底蕴的酒店，所以以前的房间设施相对旧点，但总体感受很好！', '2024-02-20', 4, '整体满意度');
