INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c77e3c98b0941765a59', '酒店紧邻地铁站，出行非常方便。酒店大堂非常壮观，一进去就忍不住要拍照，服务人员热情周到，但进入房间还是有点失望的，毕竟年头长了，设施老旧现状无法避免，洗浴池地漏堵水，洗个澡要洗洗停停，非常不便，期待改进！', '["https://dimg04.c-ctrip.com/images/0231y12000d24a48x782D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000d24hlh4A9D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000d24jqvfDFC0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-27', '花园双床房', '双床房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 22, 3.1354942159291497, 8, '["房间设施", "交通便利性", "前台服务"]'::jsonb, '房间设施', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '酒店紧邻地铁站，出行非常方便。酒店大堂非常壮观，一进去就忍不住要拍照，服务人员热', '酒店紧邻地铁站，出行非常方便。酒店大堂非常壮观，一进去就忍不住要拍照，服务人员热情周到，但进入房间还是有点失望的，毕竟年头长了，设施老旧现状无法避免，洗浴池地漏堵水，洗个澡要洗洗停停，非常不便，期待改进！', '2024-01-27', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c77e3c98b0941765a5a', '酒店很大气，一入户，大厅里金碧辉煌，那面超大的金色背景墙给人一种震撼的感觉。服务人员很热情，主动提行李，主动递水，主动发小礼物，电梯口的小姐姐每次一见面都要给小朋友一大把小点心，客服部也是有求必应。后面还有瀑布大花园，很漂亮。外面一出门就是地铁5号线，非常方便，离小蛮腰也很近。整体超赞。', '["https://dimg04.c-ctrip.com/images/0231712000d7kkvnnBA2F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000d7k88qq274D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-15', '花园大床房', '大床房', '家庭亲子', 144, 4.976733742420574, 0, 0.0, 3, 1.3862943611198906, 9, '["整体满意度", "前台服务", "交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '酒店很大气，一入户，大厅里金碧辉煌，那面超大的金色背景墙给人一种震撼的感觉。服务', '酒店很大气，一入户，大厅里金碧辉煌，那面超大的金色背景墙给人一种震撼的感觉。服务人员很热情，主动提行李，主动递水，主动发小礼物，电梯口的小姐姐每次一见面都要给小朋友一大把小点心，客服部也是有求必应。后面还有瀑布大花园，很漂亮。外面一出门就是地铁5号线，非常方便，离小蛮腰也很近。整体超赞。', '2024-02-15', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c77e3c98b0941765a5b', '挺不错的，交通挺方便的', '["https://dimg04.c-ctrip.com/images/0230512000exzm2r16556_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000exzhytq0DB2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-30', '花园双床房', '双床房', '家庭亲子', 11, 2.4849066497880004, 0, 0.0, 10, 2.3978952727983707, 4, '["交通便利性", "整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '挺不错的，交通挺方便的', '挺不错的，交通挺方便的', '2024-07-30', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c77e3c98b0941765a5c', '此次广州之行第一站选择了花园酒店，非常满意。
房间设施、服务态度都是应有的水平，建筑本身也是风景。
最打动我的还是它独特的气质，而且很明显地感觉到，管理方有意营造这种热气腾腾、繁花似锦、芬芳馥郁的梦幻感。
当然也有一些问题，譬如面盆里有霉渍，深夜外面修路的声音还很嘈杂。但氛围感到位让人可以忽略。', '["https://dimg04.c-ctrip.com/images/0235312000d135y7u3442_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000d133fb69134_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230v12000d13it9kA493_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000d13e41gF495_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-24', '红棉大床套房', '套房', '家庭亲子', 148, 5.003946305945459, 0, 0.0, 7, 2.079441541679836, 8, '["整体满意度", "房间设施", "安静程度"]'::jsonb, '整体满意度', '房间设施', '安静程度', '未知酒店', '未知地点', '匿名', '此次广州之行第一站选择了花园酒店，非常满意。', '此次广州之行第一站选择了花园酒店，非常满意。
房间设施、服务态度都是应有的水平，建筑本身也是风景。
最打动我的还是它独特的气质，而且很明显地感觉到，管理方有意营造这种热气腾腾、繁花似锦、芬芳馥郁的梦幻感。
当然也有一些问题，譬如面盆里有霉渍，深夜外面修路的声音还很嘈杂。但氛围感到位让人可以忽略。', '2024-01-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c77e3c98b0941765a5d', '第二次入住了，价格有点贵但还是挺有当地特色的，服务不错。房间很大很舒服，虽然看得出已有一些些年代感了，但总体体验还是不错。每次checkin都会遇到阿联酋航空机组。唯一美中不足的是房间插座没有配备usb充电，最后问酒店借了一个充电器，也算是完美解决问题！', '["https://dimg04.c-ctrip.com/images/0230p12000d1sphzo93CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000d1spi017B34_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000d1spkr7D643_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000d1sq3020C05_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-26', '花园大床房', '大床房', '其他', 127, 4.852030263919617, 0, 0.0, 4, 1.6094379124341005, 8, '["房间设施", "整体满意度", "价格合理性"]'::jsonb, '房间设施', '整体满意度', '价格合理性', '未知酒店', '未知地点', '匿名', '第二次入住了，价格有点贵但还是挺有当地特色的，服务不错。房间很大很舒服，虽然看得', '第二次入住了，价格有点贵但还是挺有当地特色的，服务不错。房间很大很舒服，虽然看得出已有一些些年代感了，但总体体验还是不错。每次checkin都会遇到阿联酋航空机组。唯一美中不足的是房间插座没有配备usb充电，最后问酒店借了一个充电器，也算是完美解决问题！', '2024-01-26', 4, '房间设施');
