但是服务还是很受影响，没有欢迎水果，连住两晚，房间没有主动打扫。宝宝备品没有，床围没有，总之有点一言难尽', '2024-02-16', 3, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c77e3c98b0941765a60', '房间布局紧凑。进门在电梯后方，第一次遇到也是长见识了。
洗澡水压大，很舒服。早餐在30楼，鸡蛋和面食自主选择下单，第一天吃不懂，原来配菜很多量很大，第二天就知道少点了，节约粮食。
大厅果真气派，真不愧是白金五星级酒店，香氛味道很不错，4楼的博物馆和后花园瀑布一定要去参观。
以后有机会再来。', '["https://dimg04.c-ctrip.com/images/0235312000d2zovkr6AED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000d2zovkv75D2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000d2zoxg46EE3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-30', '花园双床房', '双床房', '家庭亲子', 145, 4.983606621708336, 0, 0.0, 8, 2.19722457733622, 8, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间布局紧凑。进门在电梯后方，第一次遇到也是长见识了。', '房间布局紧凑。进门在电梯后方，第一次遇到也是长见识了。
洗澡水压大，很舒服。早餐在30楼，鸡蛋和面食自主选择下单，第一天吃不懂，原来配菜很多量很大，第二天就知道少点了，节约粮食。
大厅果真气派，真不愧是白金五星级酒店，香氛味道很不错，4楼的博物馆和后花园瀑布一定要去参观。
以后有机会再来。', '2024-01-30', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c77e3c98b0941765a61', '阔别15年后再住花园酒店，没想到还这么棒。无论硬件设施还是服务质量绝对还是广州首选住宿酒店。酒店内后花园是国内众多高档酒店中难得一见的宝藏级花园。特别推荐三楼桃园馆的清蒸东星斑，非常好吃。', '["https://dimg04.c-ctrip.com/images/0231y12000d3a93yoDB2D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000d3a9hwwD9EB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-31', '花园大床房', '大床房', '商务出差', 94, 4.553876891600541, 0, 0.0, 8, 2.19722457733622, 8, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '阔别15年后再住花园酒店，没想到还这么棒。无论硬件设施还是服务质量绝对还是广州首', '阔别15年后再住花园酒店，没想到还这么棒。无论硬件设施还是服务质量绝对还是广州首选住宿酒店。酒店内后花园是国内众多高档酒店中难得一见的宝藏级花园。特别推荐三楼桃园馆的清蒸东星斑，非常好吃。', '2024-01-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a62', '在结婚28周年纪念日选择了入住花园酒店，跟着礼宾小哥参观了酒店25个打卡点，在酒店博物馆听了广州酒店历史文化发展的专属介绍。特意选择了在荔湾庭晚餐，听着故仔和粤语旧歌，聊起在江边吃过的艇子粥，胜利宾馆的虾饺，老广州喝茶时拿着单子围着干蒸烧卖车边拿一盅两件边盖印章的趣事，耳边响起黄家驹的“喜欢你”不由唱起来，感觉太好了。前台小姐姐给我们升级了粤韵房，穿着汉服和旗袍拍了好多照片。最后，没有浪漫情怀，不善表达的老公说了一句“还是很高兴的哦”为这个特别的纪念日画上了美好的句号。', '["https://dimg04.c-ctrip.com/images/0235212000cmzglnuDB08_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000cmzgvd4E73A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000cmzivuq1AE2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000cmzk1zrC46B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000cmzhmgb106B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000cmzhre7AACC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000cmzlpbx9855_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000cmzhrqi433A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000cmzkfa3B4EF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-26', '红棉大床套房', '套房', '情侣出游', 237, 5.472270673671475, 0, 0.0, 14, 2.70805020110221, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '在结婚28周年纪念日选择了入住花园酒店，跟着礼宾小哥参观了酒店25个打卡点，在酒', '在结婚28周年纪念日选择了入住花园酒店，跟着礼宾小哥参观了酒店25个打卡点，在酒店博物馆听了广州酒店历史文化发展的专属介绍。特意选择了在荔湾庭晚餐，听着故仔和粤语旧歌，聊起在江边吃过的艇子粥，胜利宾馆的虾饺，老广州喝茶时拿着单子围着干蒸烧卖车边拿一盅两件边盖印章的趣事，耳边响起黄家驹的“喜欢你”不由唱起来，感觉太好了。前台小姐姐给我们升级了粤韵房，穿着汉服和旗袍拍了好多照片。最后，没有浪漫情怀，不善表达的老公说了一句“还是很高兴的哦”为这个特别的纪念日画上了美好的句号。', '2023-11-26', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a63', '花园酒店不愧为老牌五星，卫生，服务都很不错，特别感谢前台niki服务意识和态度都很好还帮忙升级了房间，下次还会选择这里', '["https://dimg04.c-ctrip.com/images/0235912000eup7iah53E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000eupbppt3539_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000eupbaza8E73_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-21', '花园大床房', '大床房', '商务出差', 59, 4.0943445622221, 0, 0.0, 8, 2.19722457733622, 7, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '花园酒店不愧为老牌五星，卫生，服务都很不错，特别感谢前台niki服务意识和态度都', '花园酒店不愧为老牌五星，卫生，服务都很不错，特别感谢前台niki服务意识和态度都很好还帮忙升级了房间，下次还会选择这里', '2024-07-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a64', '怎么说呢，依然金碧辉煌的大堂，照旧熙熙攘攘的人流，办入住的时候说我订的房型只有5层靠边的了，外面市政施工有噪音，给我们升级到套房，看了房间后发现原来是公寓楼不是客房，没有同意，出去吃饭回来后说安排好了还是原来的房型在20楼，能感觉到小伙子想尽力做到让客人满意，还好虽然晚上外面有施工但没影响休息。就是押金要第二天9点才能给退，感觉效率太低了，给人有点店大欺客的感觉。', '["https://dimg04.c-ctrip.com/images/0236f12000d2w2qpnB054_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000d2w2jvs183F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000d2w2p51E3C8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-30', '城央绿意双床房', '双床房', '家庭亲子', 183, 5.214935757608986, 0, 0.0, 7, 2.079441541679836, 8, '["前台服务", "退房/入住效率", "安静程度"]'::jsonb, '前台服务', '退房/入住效率', '安静程度', '未知酒店', '未知地点', '匿名', '怎么说呢，依然金碧辉煌的大堂，照旧熙熙攘攘的人流，办入住的时候说我订的房型只有5', '怎么说呢，依然金碧辉煌的大堂，照旧熙熙攘攘的人流，办入住的时候说我订的房型只有5层靠边的了，外面市政施工有噪音，给我们升级到套房，看了房间后发现原来是公寓楼不是客房，没有同意，出去吃饭回来后说安排好了还是原来的房型在20楼，能感觉到小伙子想尽力做到让客人满意，还好虽然晚上外面有施工但没影响休息。就是押金要第二天9点才能给退，感觉效率太低了，给人有点店大欺客的感觉。', '2024-01-30', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a65', '广州花园酒店的大招要从进入大门后开始——自接待厅起，一众充满岭南文化韵味的陈设与装饰，真的让人感觉走进了一座现代的艺术宫殿。接待厅的中央就陈列着当年那块“白金五星级酒店”的奖牌，它两侧的墙壁上分别挂着阳江手工漆画《百美图》与《百骏图》，静与动、柔与刚，相互呼应。进入大堂，最吸睛的莫过于前台背后的《红楼梦》大理石贴金壁画，它曾被国务院认证为全国最大的酒店大堂及镶金壁画。据说这副巨画由30多位工匠，花费7个多月才完工，用2公斤重的黄金做成20万片金箔，贴成了金陵十二钗的形象与故事...金庸先生2003年时也曾来此，并为这副画题字“花园酒店/如进荣国府/身在大观园”。与《红楼梦》壁画相对的墙上，是另一幅大理石壁画《广东水乡石刻壁画》，两幅壁画中间的空间，经常会更换放置一些限时的快闪展览装置，现在放置的是，主要面向孩子们的现场互动创作区，可以让他们在玻璃上随意进行色彩作画。', '["https://dimg04.c-ctrip.com/images/0230b12000dksynf916A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000dksyuibC2E5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000dksyhj37BC0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000dksyqdu86F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000dksyqjfAD05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000dksyxm7A624_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000dksy859A0E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000dksypuvA77C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000dksyu6968FD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-03', '红棉双床套房', '套房', '家庭亲子', 388, 5.963579343618446, 0, 0.0, 10, 2.3978952727983707, 9, '["公共设施"]'::jsonb, '公共设施', NULL, NULL, '未知酒店', '未知地点', '匿名', '广州花园酒店的大招要从进入大门后开始——自接待厅起，一众充满岭南文化韵味的陈设与', '广州花园酒店的大招要从进入大门后开始——自接待厅起，一众充满岭南文化韵味的陈设与装饰，真的让人感觉走进了一座现代的艺术宫殿。接待厅的中央就陈列着当年那块“白金五星级酒店”的奖牌，它两侧的墙壁上分别挂着阳江手工漆画《百美图》与《百骏图》，静与动、柔与刚，相互呼应。进入大堂，最吸睛的莫过于前台背后的《红楼梦》大理石贴金壁画，它曾被国务院认证为全国最大的酒店大堂及镶金壁画。据说这副巨画由30多位工匠，花费7个多月才完工，用2公斤重的黄金做成20万片金箔，贴成了金陵十二钗的形象与故事...金庸先生2003年时也曾来此，并为这副画题字“花园酒店/如进荣国府/身在大观园”。与《红楼梦》壁画相对的墙上，是另一幅大理石壁画《广东水乡石刻壁画》，两幅壁画中间的空间，经常会更换放置一些限时的快闪展览装置，现在放置的是，主要面向孩子们的现场互动创作区，可以让他们在玻璃上随意进行色彩作画。', '2024-04-03', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a66', '酒店富丽堂皇还有博物馆 卫生且干净', '["https://dimg04.c-ctrip.com/images/0230n12000f3cfh4t2407_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000f3clfaa3C83_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000f3c9vvq6901_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 17, 2.8903717578961645, 0, 0.0, 4, 1.6094379124341005, 4, '["整体满意度", "卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '酒店富丽堂皇还有博物馆 卫生且干净', '酒店富丽堂皇还有博物馆 卫生且干净', '2024-08-12', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a67', '房间布置很温馨，有种回家的感觉!床特别舒服，躺在上面特别放松!床垫非常柔软!下午茶小点心味道很甜蜜。棒!各种卫生用品也很干净!后花园也很漂亮!早餐特别丰盛!确实是米其林的大厨烹饪的。有机会还会光顾!', '["https://dimg04.c-ctrip.com/images/0235o12000d3nno832A2E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000d3mueq2DD24_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000d3npnikC121_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000d3nrjsj47D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000d3nh5bl5CDB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000d3nw9apFE31_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-01', '城央绿意双床房', '双床房', '家庭亲子', 99, 4.605170185988092, 0, 0.0, 1, 0.6931471805599453, 8, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间布置很温馨，有种回家的感觉!床特别舒服，躺在上面特别放松!床垫非常柔软!下午', '房间布置很温馨，有种回家的感觉!床特别舒服，躺在上面特别放松!床垫非常柔软!下午茶小点心味道很甜蜜。棒!各种卫生用品也很干净!后花园也很漂亮!早餐特别丰盛!确实是米其林的大厨烹饪的。有机会还会光顾!', '2024-02-01', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a68', '全家人都喜欢老牌五星，这次带老人和孩子在花园酒店住了五天，非常舒心。
三个大人一个孩子，订了两间房间。由于我是金卡会员，升级到了64平粤韵房，老人的房间也一起升级到了粤韵房。
粤韵房设施良好保养得宜，补给充足干净卫生。
员工礼貌得体，处处体现五星大酒店风范。
还有真的好漂亮啊！！！大堂阔气，瀑布霸气，不敢想象38年前就有这么好的酒店了。
来之前有人跟我说花园酒店很旧了很老了不要住，我想说完全不旧，保养相当好，前台小姐姐也说旧的房间也一直在做升级改造，以后估计都会以全新面貌示人。
位置相当好！旁边利苑、点都德、八合里，吃东西太方便啦，叫外卖也好方便，吃的可太多了！！！
下面说下不太满意的。
办理入住好慢啊……刚开始一个外籍员工接待我，怎么说都不给我升级到粤韵，说只能升级到同面积新装修的房间，最后中国员工过来跟他说是可以的，外籍员工一脸懵说自己不知道。??
行政餐厅一般般哈，吃的东西好少，而且还搞过几次乌龙，一会儿说没查到行政待遇，一会儿又说有了，感觉外籍员工还是不太行。孩子起得晚，想说不在行政餐厅吃，让大人一起打包回去吃也不让，又不是吃完了再打包，不理解为什么不可以。
泳池只有露天的??。
瑕不掩瑜，总体入住还是很满意的，本来只订了3天，由于很满意又续住了两天，以后肯定也还会去住??。
对了，他们泳池后面有个儿童乐园，但是没啥人知道，没有孩子玩儿??。', '["https://dimg04.c-ctrip.com/images/0235u12000cvn7nqzDC7E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000cvnhrquE0D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000cvnhc4jB2CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236t12000cvnjolt6ABF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000cvno5cpC76C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000cvnods79B22_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000cvndglz1FA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000cvnn52qB395_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000cvnoosz5096_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-07', '花园大床房', '大床房', '家庭亲子', 596, 6.391917113392602, 0, 0.0, 17, 2.8903717578961645, 9, '["整体满意度", "房间设施", "周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套', '未知酒店', '未知地点', '匿名', '全家人都喜欢老牌五星，这次带老人和孩子在花园酒店住了五天，非常舒心。', '全家人都喜欢老牌五星，这次带老人和孩子在花园酒店住了五天，非常舒心。
