瑕不掩瑜，总体入住还是很满意的，本来只订了3天，由于很满意又续住了两天，以后肯定也还会去住??。
对了，他们泳池后面有个儿童乐园，但是没啥人知道，没有孩子玩儿??。', '2024-01-07', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a69', '花园酒店的工作人员服务很好，套房重新装修环境不错', '["https://dimg04.c-ctrip.com/images/0233w12000e6ciepuADD3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j12000e6ccokpDE90_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000e6cxnxy1540_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-26', '花园大床房', '大床房', '商务出差', 24, 3.218875824868201, 0, 0.0, 2, 1.0986122886681098, 6, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店的工作人员服务很好，套房重新装修环境不错', '花园酒店的工作人员服务很好，套房重新装修环境不错', '2024-05-26', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a6a', '环境真的是一流，中餐厅桃园馆菜品质量很高，服务员热情友好。客房卫生做的很好，房间设施齐全布局合理，不足之处是没有浴缸，酒店后花园非常值得看看走走，酒店的四楼博物馆也很值得一看，酒店服务人员态度都不错，就是前台接待人员态度一般，工作能力有些欠缺，退房后忘记退押金，居然开票资料还丢失了，经电话联系酒店后及时退还了押金并开具了发票，这点有些不可思议，入住多家广州五星级酒店还是第一次碰到。', '["https://dimg04.c-ctrip.com/images/0230i12000cn0xiy814C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000cn1169j2281_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000cn0vq0xEC3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000cn0zrbs4E9B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000cn11akm976A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000cn0yaz59AB2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000cn11cp63C9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000cn11cul3A7A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000cn11a5sAE59_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-11-26', '粤韵双床套房', '套房', '情侣出游', 192, 5.262690188904886, 1, 0.6931471805599453, 49, 3.912023005428146, 9, '["前台服务", "房间设施", "卫生状况"]'::jsonb, '前台服务', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '环境真的是一流，中餐厅桃园馆菜品质量很高，服务员热情友好。客房卫生做的很好，房间', '环境真的是一流，中餐厅桃园馆菜品质量很高，服务员热情友好。客房卫生做的很好，房间设施齐全布局合理，不足之处是没有浴缸，酒店后花园非常值得看看走走，酒店的四楼博物馆也很值得一看，酒店服务人员态度都不错，就是前台接待人员态度一般，工作能力有些欠缺，退房后忘记退押金，居然开票资料还丢失了，经电话联系酒店后及时退还了押金并开具了发票，这点有些不可思议，入住多家广州五星级酒店还是第一次碰到。', '2023-11-26', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c82e3c98b0941765a6b', '第二次入住花园饭店，大堂的“金陵十二钗”大气磅礴，很有年代感的酒店，但是保养的很好，房间舒适，床垫有点偏软，酒店的网红花园和瀑布很好逛，拍照也出片。我们还打卡了酒店的博物馆，下次来广州，应该还会选择花园！', '["https://dimg04.c-ctrip.com/images/0230t12000d6mqj4k6A1D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000d6mq6i86CA9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-12', '粤韵双床套房', '套房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 34, 3.555348061489413, 8, '["整体满意度", "公共设施", "房间设施"]'::jsonb, '整体满意度', '公共设施', '房间设施', '未知酒店', '未知地点', '匿名', '第二次入住花园饭店，大堂的“金陵十二钗”大气磅礴，很有年代感的酒店，但是保养的很', '第二次入住花园饭店，大堂的“金陵十二钗”大气磅礴，很有年代感的酒店，但是保养的很好，房间舒适，床垫有点偏软，酒店的网红花园和瀑布很好逛，拍照也出片。我们还打卡了酒店的博物馆，下次来广州，应该还会选择花园！', '2024-02-12', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a6c', '算是地标性的酒店了，就在淘金路地铁站旁边，附近知名的饭店酒楼很多，打车也很方便。但设施太老了，基础房型对老人洗浴不太友好，容易滑倒。建议带老人家的，升级房型。', '["https://dimg04.c-ctrip.com/images/0230s12000dc8uugv605B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000dc8r59eEF0E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000dc8fkxj7BE4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-03-04', '花园双床房', '双床房', '家庭亲子', 79, 4.382026634673881, 0, 0.0, 65, 4.189654742026425, 8, '["交通便利性", "周边配套", "房间设施"]'::jsonb, '交通便利性', '周边配套', '房间设施', '未知酒店', '未知地点', '匿名', '算是地标性的酒店了，就在淘金路地铁站旁边，附近知名的饭店酒楼很多，打车也很方便。', '算是地标性的酒店了，就在淘金路地铁站旁边，附近知名的饭店酒楼很多，打车也很方便。但设施太老了，基础房型对老人洗浴不太友好，容易滑倒。建议带老人家的，升级房型。', '2024-03-04', 3, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a6d', '房间太老旧，给的房间门缝漏光，不隔音。一张床的床垫还有一个坑。但是都说老牌花园酒店是粤式生活的代表还是住来这里。环境没得说，尤其是花园太美。早餐非常棒。希望抓紧改造老旧破的房间，别再让我们下次运气不好碰上这么差的房间。', '["https://dimg04.c-ctrip.com/images/0235912000d8pwea7260E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000d8pws632CA9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-02-19', '花园双床房', '双床房', '朋友出游', 109, 4.700480365792417, 0, 0.0, 6, 1.9459101490553128, 8, '["房间设施", "安静程度", "餐饮设施"]'::jsonb, '房间设施', '安静程度', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间太老旧，给的房间门缝漏光，不隔音。一张床的床垫还有一个坑。但是都说老牌花园酒', '房间太老旧，给的房间门缝漏光，不隔音。一张床的床垫还有一个坑。但是都说老牌花园酒店是粤式生活的代表还是住来这里。环境没得说，尤其是花园太美。早餐非常棒。希望抓紧改造老旧破的房间，别再让我们下次运气不好碰上这么差的房间。', '2024-02-19', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a6e', '入住愉快，但是一定要搭配套餐入住对连住不是很友好。', '["https://dimg04.c-ctrip.com/images/0230y12000e4v1q1mF350_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000e4tued96B74_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000e4u7lh361E7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-05-24', '羊羊得意主题大床房', '主题房', '家庭亲子', 25, 3.258096538021482, 0, 0.0, 75, 4.330733340286331, 4, '["性价比", "整体满意度"]'::jsonb, '性价比', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '入住愉快，但是一定要搭配套餐入住对连住不是很友好。', '入住愉快，但是一定要搭配套餐入住对连住不是很友好。', '2024-05-24', 4, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a6f', '酒店位置很好，晚上吃了晚饭可以步行去花城广场，走过可以看到小蛮腰，酒店的22楼办入住，也可以看到小蛮腰，周边吃饭很方便，离陶陶居很近，离春，夏，秋，冬商场很近，早餐品钟很丰富，广州的特色早餐都有，还有豆浆，豆浆是现磨的，味道很浓，上面还有一层豆皮，下次来广州还会入住这家酒店', '["https://dimg04.c-ctrip.com/images/0231u12000cywttyq21A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000cywti12A3F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000cywtquaD608_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-01-18', '花园双床房', '双床房', '家庭亲子', 137, 4.927253685157205, 0, 0.0, 8, 2.19722457733622, 8, '["周边配套", "餐饮设施", "整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店位置很好，晚上吃了晚饭可以步行去花城广场，走过可以看到小蛮腰，酒店的22楼办', '酒店位置很好，晚上吃了晚饭可以步行去花城广场，走过可以看到小蛮腰，酒店的22楼办入住，也可以看到小蛮腰，周边吃饭很方便，离陶陶居很近，离春，夏，秋，冬商场很近，早餐品钟很丰富，广州的特色早餐都有，还有豆浆，豆浆是现磨的，味道很浓，上面还有一层豆皮，下次来广州还会入住这家酒店', '2024-01-18', 4, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a70', '房间舒适，干净卫生，住的很舒心。过年酒店很有节日气氛，服务态度很好，帮忙拍照，拿行李，贴心用心暖心。
