交通便利，出行方便。
酒店很有历史底蕴，博物馆，木质旋转楼梯，红楼梦壁画，后花园都值得一逛。', '2024-02-15', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a71', '逢人就推荐，花园酒店的大堂太美了，一个有40年底蕴的酒店的装修媲美新酒店。感谢前台小姐姐给我升级了粤韵，秒变套房非常惊喜，哈哈。酒店内有博物馆和小花园，还有n多个餐厅，在等房间时，酒店内吃饭，再去参观博物馆溜达小花园，完美。', '["https://dimg04.c-ctrip.com/images/0234o12000czrcqvt8AA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000czr0jcxE977_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000czrh9ni8A5D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000czr8u7vD8EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000czrcae0F485_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000czrm42u2640_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-21', '花园大床房', '大床房', '独自旅行', 112, 4.727387818712341, 0, 0.0, 18, 2.9444389791664403, 9, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '逢人就推荐，花园酒店的大堂太美了，一个有40年底蕴的酒店的装修媲美新酒店。感谢前', '逢人就推荐，花园酒店的大堂太美了，一个有40年底蕴的酒店的装修媲美新酒店。感谢前台小姐姐给我升级了粤韵，秒变套房非常惊喜，哈哈。酒店内有博物馆和小花园，还有n多个餐厅，在等房间时，酒店内吃饭，再去参观博物馆溜达小花园，完美。', '2024-01-21', 5, '整体满意度');
