INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a73', '整体感觉都非常好，特别感谢前台漂亮的小姐姐给我父母升了房间，让他们感受了不一样的酒店感受。房间很大很舒服，酒店每个人的服务都是100分，早餐也很丰盛，是个完美的度假体验。', '["https://dimg04.c-ctrip.com/images/0234l12000d5rq4z54A63_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000d5rpz8m71C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000d5rp89sAE47_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-08', '花园双床房', '双床房', '家庭亲子', 85, 4.454347296253507, 0, 0.0, 14, 2.70805020110221, 8, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '整体感觉都非常好，特别感谢前台漂亮的小姐姐给我父母升了房间，让他们感受了不一样的', '整体感觉都非常好，特别感谢前台漂亮的小姐姐给我父母升了房间，让他们感受了不一样的酒店感受。房间很大很舒服，酒店每个人的服务都是100分，早餐也很丰盛，是个完美的度假体验。', '2024-02-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a74', '每次小假期都会选择本地出游，首选都是花园酒店，特别喜欢这里的游泳池，大堂的布置很有特色每次都眼前一亮，最重要的是五星级的服务和卫生真的让人放心。特别感谢迎送岗的小爱，中秋节当天很开心收到酒店月饼～???', '["https://dimg04.c-ctrip.com/images/0233a12000fobgkwrD74D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000fob3cq52989_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000foblep23348_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-21', '花园大床房', '大床房', '情侣出游', 101, 4.624972813284271, 0, 0.0, 2, 1.0986122886681098, 8, '["公共设施", "整体满意度", "卫生状况"]'::jsonb, '公共设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '每次小假期都会选择本地出游，首选都是花园酒店，特别喜欢这里的游泳池，大堂的布置很', '每次小假期都会选择本地出游，首选都是花园酒店，特别喜欢这里的游泳池，大堂的布置很有特色每次都眼前一亮，最重要的是五星级的服务和卫生真的让人放心。特别感谢迎送岗的小爱，中秋节当天很开心收到酒店月饼～???', '2024-09-21', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c8de3c98b0941765a75', '花园酒店属于店如其名，花园真的很大很有逛小公园的感觉，邓爷爷题的字～很好逛，酒店内的饭店也是米其林推荐，的确味道都很不错，就是真的很贵～500一顿完全不够～毕竟广州物廉价美的食物真的很多～不过味道的确很不错，都很好吃～就是旅游还要回来吃饭其实不大方便哈哈哈??，适合local或者行程很朵悠悠的朋友～性价比还是很不错滴
设施：好像给我升级了新装修的套房定的我看有地毯，升级的这个说是新的，是没地毯的，但说实话房间有点旧，我这间墙面和沙发，还有点脏，就大堂和花园是加分项，房间就要扣分了，不过能看到半个小蛮腰还挺大的，就扣一分意思意思吧
卫生：房间卫生一般，可能因为墙面和椅子真的显得很脏
环境：很不错，本身地理位置很好门口就是地铁站，去地标距离都不远，地铁又实惠，又方便，打车看路况地段感觉都满堵的，来回地铁乘三天20大概??
服务：外国客人挺多的，所以服务员也是各个肤色，都很不错～客气??
最后一天看到了谭咏麟哈哈哈哈～
对了每天还有小点心', '["https://dimg04.c-ctrip.com/images/0232812000d1eynhwB5E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i12000d1f56ibB5BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000d1f23b92B36_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-25', '红棉大床套房', '套房', '家庭亲子', 423, 6.049733455231958, 0, 0.0, 31, 3.4657359027997265, 8, '["周边配套", "性价比", "卫生状况"]'::jsonb, '周边配套', '性价比', '卫生状况', '未知酒店', '未知地点', '匿名', '花园酒店属于店如其名，花园真的很大很有逛小公园的感觉，邓爷爷题的字～很好逛，酒店', '花园酒店属于店如其名，花园真的很大很有逛小公园的感觉，邓爷爷题的字～很好逛，酒店内的饭店也是米其林推荐，的确味道都很不错，就是真的很贵～500一顿完全不够～毕竟广州物廉价美的食物真的很多～不过味道的确很不错，都很好吃～就是旅游还要回来吃饭其实不大方便哈哈哈??，适合local或者行程很朵悠悠的朋友～性价比还是很不错滴
设施：好像给我升级了新装修的套房定的我看有地毯，升级的这个说是新的，是没地毯的，但说实话房间有点旧，我这间墙面和沙发，还有点脏，就大堂和花园是加分项，房间就要扣分了，不过能看到半个小蛮腰还挺大的，就扣一分意思意思吧
卫生：房间卫生一般，可能因为墙面和椅子真的显得很脏
环境：很不错，本身地理位置很好门口就是地铁站，去地标距离都不远，地铁又实惠，又方便，打车看路况地段感觉都满堵的，来回地铁乘三天20大概??
服务：外国客人挺多的，所以服务员也是各个肤色，都很不错～客气??
最后一天看到了谭咏麟哈哈哈哈～
对了每天还有小点心', '2024-01-25', 4, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a76', '入住体验大大超过预期，真不愧为是中国酒店业的标杆，很有老钱风，设施非常齐全和豪华。居然还有博物馆，几个餐厅都是顶级的。服务员很热情专业训练有素，特别感谢服务员小玲。', '["https://dimg04.c-ctrip.com/images/0236g12000fbwh5858EF9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231h12000fbwc2wf3B60_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-31', '花园大床房', '大床房', '商务出差', 82, 4.418840607796598, 0, 0.0, 41, 3.737669618283368, 9, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '入住体验大大超过预期，真不愧为是中国酒店业的标杆，很有老钱风，设施非常齐全和豪华', '入住体验大大超过预期，真不愧为是中国酒店业的标杆，很有老钱风，设施非常齐全和豪华。居然还有博物馆，几个餐厅都是顶级的。服务员很热情专业训练有素，特别感谢服务员小玲。', '2024-08-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a77', '对酒店的服务人员的态度非常满意，见面问好有礼貌，帮助按电梯，房间卫生干净整洁，有胶囊咖啡机，有欢迎水果和鲜花，酒店还有后花园，小桥流水锦鲤满池，地理位置优越，对面就是广州友谊商店，地铁淘金站就在酒店正门，这两天广州气温骤降酒店马上给热空调，我们是下午的飞机经理还帮我们延迟退房到14:00，很温馨的酒店，下次来广州再入住这家！', '["https://dimg04.c-ctrip.com/images/0230812000d0zhdlwEF74_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000d0zgs51A32E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000d0zgvtl23EC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000d0zhpueD5DC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-24', '城央绿意双床房', '双床房', '情侣出游', 163, 5.099866427824199, 0, 0.0, 27, 3.332204510175204, 9, '["前台服务", "卫生状况", "交通便利性"]'::jsonb, '前台服务', '卫生状况', '交通便利性', '未知酒店', '未知地点', '匿名', '对酒店的服务人员的态度非常满意，见面问好有礼貌，帮助按电梯，房间卫生干净整洁，有', '对酒店的服务人员的态度非常满意，见面问好有礼貌，帮助按电梯，房间卫生干净整洁，有胶囊咖啡机，有欢迎水果和鲜花，酒店还有后花园，小桥流水锦鲤满池，地理位置优越，对面就是广州友谊商店，地铁淘金站就在酒店正门，这两天广州气温骤降酒店马上给热空调，我们是下午的飞机经理还帮我们延迟退房到14:00，很温馨的酒店，下次来广州再入住这家！', '2024-01-24', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a78', '服务很好，房间很舒服，一千多的房间里面的胶囊咖啡机有三种口味，可供选择，大堂也很舒服明亮，总体来说感觉很好，一共住了四个晚上，出门非常方便，好吃的有名气的餐厅都在附近一公里范围。', '["https://dimg04.c-ctrip.com/images/0230k12000d23wl4m2680_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000d23qbpb56C6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-27', '花园大床房', '大床房', '独自旅行', 89, 4.499809670330265, 0, 0.0, 22, 3.1354942159291497, 8, '["整体满意度", "房间设施", "周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套', '未知酒店', '未知地点', '匿名', '服务很好，房间很舒服，一千多的房间里面的胶囊咖啡机有三种口味，可供选择，大堂也很', '服务很好，房间很舒服，一千多的房间里面的胶囊咖啡机有三种口味，可供选择，大堂也很舒服明亮，总体来说感觉很好，一共住了四个晚上，出门非常方便，好吃的有名气的餐厅都在附近一公里范围。', '2024-01-27', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a79', '走进大堂就是一个繁花迷人眼，让人目不暇接。卫生据肉眼可见还是很干净的，客房服务员，门童等都很热情，前台Gillian服务非常热情，亲切，周到，有求必应！', '["https://dimg04.c-ctrip.com/images/0230v12000d5gapxiACED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000d5gbu84A715_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230u12000d5gcb4pFC31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000d5gax6a83F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000d5gc95r882E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000d5gbhbu6469_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000d5gcmn9B24C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000d5gcihs77BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000d5gbev736C3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-07', '花园大床房', '大床房', '独自旅行', 76, 4.343805421853684, 0, 0.0, 10, 2.3978952727983707, 7, '["前台服务", "客房服务", "卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况', '未知酒店', '未知地点', '匿名', '走进大堂就是一个繁花迷人眼，让人目不暇接。卫生据肉眼可见还是很干净的，客房服务员', '走进大堂就是一个繁花迷人眼，让人目不暇接。卫生据肉眼可见还是很干净的，客房服务员，门童等都很热情，前台Gillian服务非常热情，亲切，周到，有求必应！', '2024-02-07', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a7a', '不愧是白金五星，酒店地理位置优越，闹中取静，自带岭南风格的花园，还贴心地送了小点心', '["https://dimg04.c-ctrip.com/images/0231z224x8uhjlnud9651_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o224x8uhkjgps8E8D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231i224x8uhk42ewF4F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q224x8uhk98g888F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r224x8uhka9nl1130_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-12', '城央绿意大床房', '大床房', '独自旅行', 41, 3.737669618283368, 0, 0.0, 22, 3.1354942159291497, 8, '["整体满意度", "周边配套", "安静程度"]'::jsonb, '整体满意度', '周边配套', '安静程度', '未知酒店', '未知地点', '匿名', '不愧是白金五星，酒店地理位置优越，闹中取静，自带岭南风格的花园，还贴心地送了小点', '不愧是白金五星，酒店地理位置优越，闹中取静，自带岭南风格的花园，还贴心地送了小点心', '2024-04-12', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a7b', '大堂就很有春节气氛！房间应该经历过翻新，设施和装潢布局都很不错。被子估计是绒，轻薄又保暖。洗漱用具的盒子设计也充满巧思，可以构成一幅完整的广州市花木棉图案。', '["https://dimg04.c-ctrip.com/images/0231t12000d62b7p18A20_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000d628op81F3D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000d62c4jc3420_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-09', '花园大床房', '大床房', '独自旅行', 78, 4.3694478524670215, 0, 0.0, 46, 3.8501476017100575, 8, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '大堂就很有春节气氛！房间应该经历过翻新，设施和装潢布局都很不错。被子估计是绒，轻', '大堂就很有春节气氛！房间应该经历过翻新，设施和装潢布局都很不错。被子估计是绒，轻薄又保暖。洗漱用具的盒子设计也充满巧思，可以构成一幅完整的广州市花木棉图案。', '2024-02-09', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a7c', '酒店非常不错，是全国三个白金五星级酒店之一，入住时正好遇到中越一个商会搞活动，虽晚了一些但酒店给升级了套房而且还给了下午茶。酒店服务非常专业，感谢Rebecca小钟的热心服务和讲解，酒店近6号地铁交通便利，而且酒店有大巴直接到澳门几个固定地点，不过每天只有8:35这一班。酒店的瀑布餐厅很有特色，老人孩子非常满意，非常不错的一次体验。下次来广东还会再次入住。', '["https://dimg04.c-ctrip.com/images/0234i12000humufzq465E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000humobj20E65_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000humgr1355E9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-17', '花园双床房', '双床房', '家庭亲子', 179, 5.19295685089021, 0, 0.0, 14, 2.70805020110221, 9, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '酒店非常不错，是全国三个白金五星级酒店之一，入住时正好遇到中越一个商会搞活动，虽', '酒店非常不错，是全国三个白金五星级酒店之一，入住时正好遇到中越一个商会搞活动，虽晚了一些但酒店给升级了套房而且还给了下午茶。酒店服务非常专业，感谢Rebecca小钟的热心服务和讲解，酒店近6号地铁交通便利，而且酒店有大巴直接到澳门几个固定地点，不过每天只有8:35这一班。酒店的瀑布餐厅很有特色，老人孩子非常满意，非常不错的一次体验。下次来广东还会再次入住。', '2025-01-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a7d', '服务很好，身体不舒服李文（名字写的不知道对不对）小姐姐帮忙处理加急拿房，房间吐了清洁的工作人员特别及时有耐心的清理。定的房型12岁以下免费加了床，非常适合我们这种娃年龄小块头大的。周边有陶陶居，点都德，广州酒家，常来小聚，步行可到，非常方便。', '["https://dimg04.c-ctrip.com/images/0233o12000ic88y3n12FC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000ic88fkv7455_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000ic7qeurA1AE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-06', '红棉大床套房', '套房', '家庭亲子', 121, 4.804021044733257, 0, 0.0, 1, 0.6931471805599453, 8, '["前台服务", "客房服务", "周边配套"]'::jsonb, '前台服务', '客房服务', '周边配套', '未知酒店', '未知地点', '匿名', '服务很好，身体不舒服李文（名字写的不知道对不对）小姐姐帮忙处理加急拿房，房间吐了', '服务很好，身体不舒服李文（名字写的不知道对不对）小姐姐帮忙处理加急拿房，房间吐了清洁的工作人员特别及时有耐心的清理。定的房型12岁以下免费加了床，非常适合我们这种娃年龄小块头大的。周边有陶陶居，点都德，广州酒家，常来小聚，步行可到，非常方便。', '2025-02-06', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a7e', '和同事相约游广东，恰逢圣诞在广州花园酒店连住2晚实在是选对了。
这个酒店太让人惊艳了，他们是全国首批三家白金五星级饭店之一，而且是华南地区唯一获选的中国自主品牌酒店。
贝聿铭为花园酒店勾画了建设蓝图，***为花园酒店奠基基石，邓小平为花园酒店亲笔题写了店名！
西点做得非常正宗美味，酒店米其林提名的餐厅不止一个，瀑布餐厅很有特色，服务非常好，非常满意，必须五星好评??', '["https://dimg04.c-ctrip.com/images/0230v12000d0a91nt05F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000d0acyi6CB42_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000d0aodxk3210_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000d0ao6vsE3E8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000d0aodjg03F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000d0aodxq9FF4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000d0aodjk6D62_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000d0ao6w23884_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000d0ap7yq145B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-22', '花园双床房', '双床房', '朋友出游', 184, 5.220355825078324, 0, 0.0, 35, 3.58351893845611, 9, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '和同事相约游广东，恰逢圣诞在广州花园酒店连住2晚实在是选对了。', '和同事相约游广东，恰逢圣诞在广州花园酒店连住2晚实在是选对了。
这个酒店太让人惊艳了，他们是全国首批三家白金五星级饭店之一，而且是华南地区唯一获选的中国自主品牌酒店。
贝聿铭为花园酒店勾画了建设蓝图，***为花园酒店奠基基石，邓小平为花园酒店亲笔题写了店名！
西点做得非常正宗美味，酒店米其林提名的餐厅不止一个，瀑布餐厅很有特色，服务非常好，非常满意，必须五星好评??', '2024-01-22', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027c98e3c98b0941765a7f', '就在地铁淘金站出口，附近也很热闹，服务非常好，工作人员到处都是，房间装修也不错，除了卫生间没隔断有点不方便。新年有舞狮，有小摊，晚上还有驻场表演。', '["https://dimg04.c-ctrip.com/images/0232l12000d89zioq5C04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000d8a0q2e4144_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-17', '红棉大床套房', '套房', '家庭亲子', 73, 4.30406509320417, 0, 0.0, 4, 1.6094379124341005, 8, '["交通便利性", "周边配套", "前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '就在地铁淘金站出口，附近也很热闹，服务非常好，工作人员到处都是，房间装修也不错，', '就在地铁淘金站出口，附近也很热闹，服务非常好，工作人员到处都是，房间装修也不错，除了卫生间没隔断有点不方便。新年有舞狮，有小摊，晚上还有驻场表演。', '2024-02-17', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027caae3c98b0941765a80', '非常满意的一次住宿体验，颇具性价比。酒店很漂亮，交通方便，门口就是公交站和地铁站，服务人员态度很好，见面总是微笑打招呼，房间卫生还不错，没有异味。就是附近夜里有施工，稍微有点吵。花园很漂亮，常有打卡拍照的，二楼的早茶味道很不错。酒店旁边点都德，广州酒家离得很近。', '["https://dimg04.c-ctrip.com/images/0230x12000cw9q2dxC412_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000cwa3qxfE9F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-09', '花园双床房', '双床房', '家庭亲子', 131, 4.882801922586371, 0, 0.0, 10, 2.3978952727983707, 8, '["交通便利性", "性价比", "整体满意度"]'::jsonb, '交通便利性', '性价比', '整体满意度', '未知酒店', '未知地点', '匿名', '非常满意的一次住宿体验，颇具性价比。酒店很漂亮，交通方便，门口就是公交站和地铁站', '非常满意的一次住宿体验，颇具性价比。酒店很漂亮，交通方便，门口就是公交站和地铁站，服务人员态度很好，见面总是微笑打招呼，房间卫生还不错，没有异味。就是附近夜里有施工，稍微有点吵。花园很漂亮，常有打卡拍照的，二楼的早茶味道很不错。酒店旁边点都德，广州酒家离得很近。', '2024-01-09', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027caae3c98b0941765a81', '地理位置：酒店位于淘金地铁站出口处，前面还有数条公交线路，出行极其便利。
环境：酒店大堂金碧辉煌，前台的红楼梦壁画真是点睛之笔。
服务：从入口处的服务人员，到前台办理入住的接待人员，还有客房、餐厅的工作人员全程热情接待，笑脸相迎，让人如沐春风，可见酒店的管理水准到位，不愧为白金酒店的称谓??
