细致的服务也凸显出酒店管理的用心。', '2024-02-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027caae3c98b0941765a83', '网约车司机是个健谈的广州人，听了他对酒店的推荐，临时决定在广州多停留一晚，结果出乎意料地满意。酒店如其名，真得像个花园一样，会推荐给朋友们。升级的粤韵套房宽敞，设施很新。参观了位于4层的酒店博物馆，才知道酒店始建于1984年，还是邓小平先生题字。酒店内及周边餐厅很多，丰俭由人。交通便捷，离地铁就2-3分钟步行距离。唯一的建议是夜间关闭瀑布，减少噪声。', '["https://dimg04.c-ctrip.com/images/0236s12000cw6u2rmDCCC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000cw6mqza879F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000cw6ibq66A9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000cw6s4olDDC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000cw6rjefB8E4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000cw6s069D9E1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000cw6vn9b8480_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000cw6vmom7B92_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-09', '花园双床房', '双床房', '家庭亲子', 176, 5.176149732573829, 0, 0.0, 41, 3.737669618283368, 9, '["整体满意度", "交通便利性", "安静程度"]'::jsonb, '整体满意度', '交通便利性', '安静程度', '未知酒店', '未知地点', '匿名', '网约车司机是个健谈的广州人，听了他对酒店的推荐，临时决定在广州多停留一晚，结果出', '网约车司机是个健谈的广州人，听了他对酒店的推荐，临时决定在广州多停留一晚，结果出乎意料地满意。酒店如其名，真得像个花园一样，会推荐给朋友们。升级的粤韵套房宽敞，设施很新。参观了位于4层的酒店博物馆，才知道酒店始建于1984年，还是邓小平先生题字。酒店内及周边餐厅很多，丰俭由人。交通便捷，离地铁就2-3分钟步行距离。唯一的建议是夜间关闭瀑布，减少噪声。', '2024-01-09', 5, '整体满意度');
