INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cb5e3c98b0941765a8b', '酒店位于市中心，门口就是地铁淘金站，对面是白云宾馆。交通非常便利。
酒店有六间餐厅，吃东西很方便。酒店花园不算特别大，有两个大瀑布，庭院，假山，小桥，流水，非常惬意。酒店的电梯运行很快，很稳，不需要等很久。j订的红棉套房还包括五百块酒店餐厅消费券，可直接使用，很方便。房间装潢虽然有年代感，但使用起来没有任何问题。
床偏软了点，平时睡惯了硬床，有点不习惯了。
早餐的瀑布餐厅比较小，要排队，建议早点去
前台办入住时等了不少时间，效率稍微差点。
另酒店的博物馆值得去刷一下，有免费讲解。', '["https://dimg04.c-ctrip.com/images/023222215h3zsm4hs69F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m2224x7cyp3dc56A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023662234daq4s9yo9DFF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k2234daq4shog76C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f2234daq4spe84600_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w2215h3zsnesg3E81_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p2215h3zsnesh5ED4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f2234daq4t4tsBC48_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l2215h3zso1xs7FB0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-22', '红棉双床套房', '套房', '朋友出游', 242, 5.493061443340548, 2, 1.0986122886681098, 12, 2.5649493574615367, 9, '["交通便利性", "周边配套", "退房/入住效率"]'::jsonb, '交通便利性', '周边配套', '退房/入住效率', '未知酒店', '未知地点', '匿名', '酒店位于市中心，门口就是地铁淘金站，对面是白云宾馆。交通非常便利。', '酒店位于市中心，门口就是地铁淘金站，对面是白云宾馆。交通非常便利。
酒店有六间餐厅，吃东西很方便。酒店花园不算特别大，有两个大瀑布，庭院，假山，小桥，流水，非常惬意。酒店的电梯运行很快，很稳，不需要等很久。j订的红棉套房还包括五百块酒店餐厅消费券，可直接使用，很方便。房间装潢虽然有年代感，但使用起来没有任何问题。
床偏软了点，平时睡惯了硬床，有点不习惯了。
早餐的瀑布餐厅比较小，要排队，建议早点去
前台办入住时等了不少时间，效率稍微差点。
